[913] = {"El chillido del halcón trueno", {"Encuentra 1 halcón trueno, mátalo y llévale sus alas a Jorn Vidente del Cielo en el Campamento Taurajo."}},
[914] = {"Líderes del Colmillo", {"Lleva las gemas de Cobrahn, Anacondra, Pythas y Serpentis a Nara Ferocrín en Cima del Trueno."}},
