[930] = {"El fruto resplandeciente", {"Llévale el fruto resplandeciente a Denalan, que está en el Lago Al'Ameth."}},
[931] = {"Fronda fulgurante", {"Llévale una fronda fulgurante a Denalan. Normalmente está en el Lago Al'Amethm, pero a veces viaja hasta el Cobertizo Primigenio."}},
