[952] = {"El Páramo de los Ancianos", {"Entrégale el mensaje de Fandral a Onus en el Páramo de los Ancianos en Costa Oscura, al sur de Auberdine."}},
[953] = {"La caída de Ameth'Aran", {"Estudia las tablillas que hablan de Ameth'Aran y de su caída y reúnete con la centinela Tysha Filoluna en Costa Oscura."}},
[954] = {"Bashal'Aran", {"Encuentra la fuente de la extraña aura azul en las Ruinas de Bashal'Aran."}},
[955] = {"Bashal'Aran", {"Consigue 8 pendientes de grell y llévaselos a Asterion a Bashal'Aran."}},
[956] = {"Bashal'Aran", {"Consigue el sello de piedra lunar antiguo y llévaselo a Asterion a Bashal'Aran."}},
[957] = {"Bashal'Aran", {"Destruye el sello de piedra lunar antiguo en la antigua llama de Ameth'Aran y vuelve a reunirte con Asterion en Bashal'Aran."}},
