[973] = {"La Torre de Althalaxx", {"Llévale el Libro de Ilkrud Magthrull a Delgren el Purificador en la Atalaya de Maestra."}},
[974] = {"Busca la fuente", {"Krakle, en el Cráter de Un'Goro, quiere que encuentres la zona más caliente de la Cresta del Penacho en Llamas.","","Siempre que des con un punto caliente, pulsa con el botón derecho sobre el termómetro para comprobar la temperatura. Sigue buscando hasta que encuentres el punto más caliente."}},
