[976] = {"Suministros a Auberdine", {"Habla con Delgren el Purificador en la Atalaya de Maestra después ayudar a Feero a cruzar el Bosque de Vallefresno y dejarlo a buen recaudo."}},
[977] = {"Yeti... ¿ya hemos llegado?", {"Reúne 2 cuernos prístinos de yeti para Umi Risitas en Vista Eterna."}},
