[981] = {"La Torre de Althalaxx", {"Habla con Delgren el Purificador en la Atalaya de Maestra."}},
[982] = {"Profundo océano, mar inmenso", {"Recupera el arcón del Amanecer de Plata y la caja fuerte del Halo de Bruma para Gorbold Mano de Acero de Auberdine. Ambos objetos deberían estar en los cascos de los navíos naufragados al norte de la aldea."}},
