[1039] = {"El puerto de Los Baldíos", {"Ve a Trinquete y habla con el maestro de muelles Vertipeluca."}},
[1040] = {"Pasaje a Bahía del Botín", {"Coge un barco a Bahía del Botín y habla con el caravanero Ruzzgot."}},
[1041] = {"La ruta de la caravana", {"Habla con el secretario Daltry en Villa Oscura."}},
[1042] = {"La familia Carevin", {"Habla con Jonathan Carevin en Villa Oscura."}},
[1043] = {"La Guadaña de Elune", {"Busca signos de la Guadaña de Elune y regresa a Villa Oscura, con Jonathan Carevin."}},
