[1051] = {"La venganza de Vorrel", {"Lleva la alianza de Vorrel Sengutz a Monika Sengutz de Molino Tarren."}},
[1052] = {"El sendero Escarlata", {"Lleva la carta de mención honorífica del hermano Anton a Raleigh el Devoto, en Costasur."}},
[1053] = {"En el nombre de la Luz", {"Mata a la alta inquisidora Melenablanca, al Comandante Escarlata Mograine, a Herod, el Campeón Escarlata y al maestro de canes Loksey. A continuación, preséntate ante Raleigh el Devoto, en Costasur."}},
[1054] = {"Matanza selectiva", {"Llévale la calavera de Dal Zarpasangrante a Raene Correlobo en Astranaar."}},
[1055] = {"La limpieza de Raene", {"Vuelve junto a Shael'dryn en la Poza de la Luna."}},
[1056] = {"Viaje a Cima del Espolón", {"Ve junto al vigilante Albagorm en la Cima del Espolón."}},
[1057] = {"La reconquista de La Vega Carbonizada", {"El vigilante Albagorm en la Cima del Espolón quiere que mates a 7 arpías Furia Sangrienta, a 7 emboscadoras Furia Sangrienta, a 7 destripadoras Furia Sangrienta y a 7 malaplumas Furia Sangrienta."}},
