[1059] = {"La reconquista de La Vega Carbonizada", {"Ve a ver al Díscolo Falfindel en la frontera entre Las Mil Agujas y Feralas."}},
[1060] = {"Una carta para Jin'Zil", {"Entrégale la carta de Darsok a Jin'Zil en su cueva de Malaka'jin, en Espolón."}},
[1061] = {"Los espíritus del Espolón", {"Habla con Seereth Petrajada en la frontera entre Sierra Espolón y Los Baldíos."}},
[1062] = {"Los invasores goblin", {"Mata a 15 leñadores de Ventura y Cía. y vuelve a ver a Seereth Petrajada, en la frontera entre Espolón y Los Baldíos."}},
[1063] = {"La bruja anciana", {"Habla con Magatha en Cima del Trueno."}},
[1064] = {"La ayuda de los Renegados", {"Habla con la boticaria Zamah en las Pozas de las Visiones de Cima del Trueno."}},
[1065] = {"Viaja a Molino Tarren", {"Entrégale la nota de Zamah al boticario Lydon, que está en Molino Tarren."}},
[1066] = {"Sangre inocente", {"Lleva 5 viales de sangre inocente al boticario Lydon de Molino Tarren."}},
[1067] = {"Regresa a Cima del Trueno", {"Lleva la toxina de Lydon a la boticaria Zamah de Cima del Trueno."}},
[1068] = {"Las sierras XT:4 y XT:9", {"Destruye las sierras XT:4 y XT:9, a continuación vuelve a ver a Seereth Petrajada, en la frontera entre Sierra Espolón y Los Baldíos."}},
[1069] = {"Huevos de arañas Musgondo", {"Llévale 15 huevos de Musgondo a Mebok Mizzyrix en Trinquete"}},
[1070] = {"Estar de guardia en Espolón", {"Encuentra a Kaela Lanzasombra contemplando la vista del valle a la entrada del Risco Cortaviento, en Sierra Espolón."}},
