[1074] = {"Ineptitud + Productos químicos = Diversión", {"Lleva el nitromirgliceronio de vuelta a Gaxim Silvóxido en Espolón."}},
[1075] = {"Un pergamino de Mauren", {"Encuentra a Collin Mauren en Ventormenta."}},
[1076] = {"Demonios en los Páramos de Poniente", {"Lleva restos de demonio de polvo a Collin Mauren en Ventormenta."}},
[1077] = {"Entrega especial para Gaxim", {"Lleva el Pergamino de mensajes de vuelta a Gaxim Silvóxido en Espolón."}},
