[3568] = {"La filtración de la corrupción", {"Llena los 4 viales vacíos en las pozas de las mareas que se encuentran a lo largo de la costa de las Ruinas de Eldarath en Azshara y después ve a ver al químico Cuely."}},
[3569] = {"La filtración de la corrupción", {"Dale el elixir de Cuely a Thersa Son del Viento, que está en Entrañas."}},
