[3601] = {"¡Kim'jael, claro!", {"Busca en el Campamento base thalassiano la brújula de Kim'jael, la mira, el pollo relleno y el cachivache y llévaselo todo a Azshara."}},
[3602] = {"Azsharita", {"Recupera 20 azsharitas cristalizadas del sur de Azshara. Puede que encuentres canes manáfagos dispuestos a ayudarte a rastrear la ubicación de los depósitos hábilmente escondidos.","","Vuelve con Loramus cuando hayas completado la tarea."}},
[3621] = {"La formación de Aterravil", {"Llévale el envío a Galvan el Antiguo en la Vega de Tuercespina."}},
[3625] = {"Armas Fel en Azsharita encantada", {"Espera que Galvan acabe de forjar las armas."}},
[3626] = {"Regresa a Las Tierras Devastadas", {"Vuelve junto al héroe caído de la Horda en el Cruce Lanzarrota, en el Pantano de las Penas."}},
[3627] = {"Juntar pedazos del amuleto", {"Mata a Grol el Destructor, a Lady Sevine y al archimago Allistarj. De sus cadáveres coge el amuleto de Grol, el amuleto de Sevine y el amuleto de Allistarj.","","Acuérdate de USAR tus armas viles de azsharita encantada para debilitar a la tríade. Es la única forma de matarlos, pero úsalas con moderación..."}},
[3628] = {"Eres Rakh'likh, demonio", {"Destruye a Razelikh el Rapiñador y llévale el cuerno de Rapiñador cortado al héroe caído de la Horda. También tendrás que devolver el Resguardo del Rapiñador para que el héroe caído pueda destruirlo y así impedir que caiga en las manos equivocadas."}},
[3629] = {"Ingeniería goblin", {"Si quieres saber más sobre ingeniería goblin, llévale el Manual de disciplinas de ingeniería a Nixx Muellepiñón de Gadgetzan."}},
[3630] = {"Ingeniería gnómica", {"Si quieres saber más sobre ingeniería gnómica, lleva el Manual de disciplinas de ingeniería al maestro manitas Sobrechispa en Forjaz."}},
