[3762] = {"Ayuda al archidruida Tótem de Runa", {"Habla con el archidruida Hamuul Tótem de Runa en Cima del Trueno."}},
[3763] = {"Ayuda al archidruida Corzocelada", {"Habla con el archidruida Fandral Corzocelada en Darnassus."}},
