[3765] = {"Lejana corrupción", {"Ve a ver a Gershala Susurro Nocturno en Auberdine."}},
[3781] = {"Investigar la mañagrana", {"Lleva el vale para semillas del archidruida a Mathrengyl Garroso al Enclave Cenarion de Darnassus."}},
[3782] = {"Investigar la mañagrana", {"Llévale este vale para semillas a Bashana Tótem de Runa en Cima del Trueno."}},
[3783] = {"Yeti... ¿ya hemos llegado?", {"Reúne 10 pelajes de yeti gruesos para Umi Risitas en Vista Eterna."}},
[3784] = {"Ayuda al archidruida Tótem de Runa", {"Habla con el archidruida Hamuul Tótem de Runa en Cima del Trueno."}},
[3785] = {"Investigar la mañagrana", {"Utiliza una faltriquera de siempreverde con 1 paquete de semillas de Tharlendris y 2 muestras de tierra de Un'Goro para intentar cultivar mañagrana.","","Lleva 10 plantas de mañagrana a Mathrengyl Garroso a Darnassus."}},
