[3801] = {"El legado de los Hierro Negro", {"Habla con Franclorn Forjador en la Tumba de Forjador, en la Montaña Roca Negra, si te interesa obtener una llave de la ciudad."}},
[3802] = {"El legado de los Hierro Negro", {"Mata a Finoso Virunegro y recupera el gran martillo, Ferrovil. Lleva a Ferrovil al Santuario de Thaurissan y coloca el martillo en la estatua de Franclorn Forjador."}},
