[3821] = {"Roca Machacamiedo", {"Adéntrate en Las Estepas Ardientes y averigua qué le ha ocurrido a Sha'ni Colmillo Orgulloso."}},
[3822] = {"Krom'Grul", {"Recupera el aro de la nariz de Sha'ni de Krom'Grul y llévasela a Thal'trak en Kargath. Busca por las diferentes cuevas y minas de la Roca Machacamiedo."}},
[3823] = {"El exterminio de los Pirontraña", {"Mata a 15 magos ogros Pirontraña, 7 ogros Pirontraña y 7 ogros toscos Pirontraña."}},
[3824] = {"Gor'tesh, el Señor de los toscos", {"Recoge la cabeza cortada de Gor'tesh."}},
[3825] = {"Una cabeza ogro empalada = FIESTA", {"Coge la cabeza cortada de Gor'tesh y colócala en lo alto de la Roca Machacamiedo. Busca un montículo de tierra blanda para clavar la pica."}},
[3841] = {"Un huérfano que busca un hogar", {"Ve a Las Mil Agujas y habla con Quentin."}},
[3842] = {"Una corta incubación", {"Lleva 2 elixires de entereza a Quentin a Las Mil Agujas."}},
[3843] = {"Un nuevo miembro en la familia", {"Lleva tu huevo de duende dardo frágil a las Tierras del Interior y habla con Agnar Domabestias, pero date prisa: si tardas más de 1 hora en encontrarlo, la cría que hay en el huevo morirá."}},
[3844] = {"Un secreto bien guardado", {"Busca alrededor del estanque alguna pista sobre a quién perteneció la balsa destrozada."}},
[3845] = {"Un secreto bien guardado", {"Examina los objetos de la talega y devuélveselos a su propietario."}},
[3861] = {"¡CLOQUEA!", {"Consigue comida para pollos especial y vuelve junto a tu nuevo amigo pollo. Cuando lo encuentres, anímalo con el comando /animar antes de darle la comida para pollos especial."}},
[3881] = {"Salvar a la expedición", {"Lleva un cajón de comestibles y el equipo de investigación a Williden Marshal en el Cráter de Un'Goro."}},
[3882] = {"Choca esos huesos", {"Lleva 8 huesos de dinosaurio a Chispik Minamal en el Cráter de Un'Goro."}},
[3883] = {"Ecología alienígena", {"Utiliza el vial de raspadura para recoger una Muestra de pared de colmena de uno de los criaderos Gorishi del Cráter de Un'Goro. Busca las cámaras con los huevos de larva colgantes.","","Lleva la Muestra de pared de colmena a Hol'anyee Marshal en el Cráter de Un'Goro."}},
[3884] = {"Diario de Williden", {"Devuelve el diario a Williden Marshal en algún lugar del Cráter de Un'Goro."}},
[3901] = {"Sacudir esqueletos", {"Mata a 8 esqueletos armadóseos."}},
[3902] = {"Hurgar en Camposanto", {"Busca 6 piezas de mercancías extraviadas por Camposanto y los alrededores y llévaselas al Guardia de la Muerte Saltain."}},
[3903] = {"Milly Osworth", {"Habla con Milly Osworth."}},
[3904] = {"La cosecha de Milly", {"Lleva 8 cajas de cosecha a Milly Osworth a la Abadía de Villanorte."}},
[3905] = {"Informe de la vendimia", {"Lleva el Informe de la vendimia al hermano Neals a la Abadía de Villanorte."}},
[3906] = {"La discordia de las llamas", {"Ve a la cantera de la Montaña Roca Negra y ejecuta al Maestro Supremo Pyron. Vuelve junto a Corazón Atronador cuando hayas completado este encargo."}},
[3907] = {"La discordia del fuego", {"Adéntrate en las Profundidades de Roca Negra y localiza a Lord Incendius. Mátalo y llévale toda la información que encuentres a Corazón Atronador."}},
[3908] = {"Un secreto bien guardado", {"Lleva la Espada de Linken a Donova Cubilnevado en Cuna del Invierno."}},
[3909] = {"El Elixir de Videre", {"Busca a Gregan Tirabirras en el norte de Feralas. Con él, aprende cómo puedes obtener el Elixir de Videre. Cuando lo sepas, vuelve con Donova Cubilnevado en Cuna del Invierno."}},
[3912] = {"Encuentro en la tumba", {"Ve al cementerio a las afueras de Gadgetzan y utiliza el Elixir de Videre. Sigue las demás instrucciones de Donova para encontrar a Gaeriyan."}},
[3913] = {"Una situación mortal", {"Resucita y busca la lápida de la que te habló Gaeriyan."}},
[3914] = {"La Espada de Linken", {"Entrega la Espada superior a Linken en el Cráter de Un'Goro."}},
[3921] = {"Wenikee Tuercasmil", {"Llévale el churumbele roto y maltrecho a Wenikee Tuercasmil. Habla con Brak para teletransportarte directamente hasta ella."}},
[3922] = {"Engranajes", {"Reúne 10 engranajes de los cubos que encuentres por la zona de El Fangal."}},
[3923] = {"Rilli Gapegajoso", {"Llévale el churumbele roto y maltrecho a Rilli Gapegajoso en Orgrimmar."}},
[3924] = {"El manual del churumbele", {"Llévale el manual del churumbele a Rilli Gapegajoso en Orgrimmar."}},
[3941] = {"La ayuda de una gnoma", {"Encuentra a J.D. Collie en la cueva del Refugio de Marshal."}},
[3942] = {"Recuerdos de Linken", {"Encuentra a Eridan Vientoazul en el sur de Frondavil."}},
[3961] = {"La aventura de Linken", {"Lleva el Tótem plateado de Aquamentas a Linken, en el Refugio de Marshal."}},
[3962] = {"Ir solo es peligroso", {"Viaja a Cresta del Penacho en Llamas, al sur del Refugio de Marshal.","","Busca a Correfuego y utiliza el Tótem para eliminar su aura protectora. Cuando le hayas derrotado, coge la Llama Dorada de la cueva."}},
[3981] = {"Comandante Gor'shak", {"Encuentra al comandante Gor'shak en las Profundidades de Roca Negra.","","Recuerdas que en el dibujo burdo había rejas sobre el rostro del orco. Quizás deberías buscar una cárcel o algo similar."}},
[3982] = {"¿Qué pasa?", {"Defiende a Gor'shak."}},
[4001] = {"¿Qué pasa?", {"Habla con Kharan Martillo Poderoso y recaba información sobre el secuestro de la princesa Moira Barbabronce. Llévale esa información a Thrall en Orgrimmar.","","Recuerdas que Gor'shak mencionó que Kharan estaba preso en una celda cercana."}},
[4002] = {"Los Reinos del Este", {"Si aceptas la misión, habla con Thrall."}},
[4003] = {"El rescate real", {"Mata al emperador Dagran Thaurissan para liberar a la princesa Moira Barbabronce del hechizo."}},
[4004] = {"¿Princesa salvada?", {"Vuelve junto a Thrall en el Fuerte Grommash en Orgrimmar."}},
[4005] = {"Aquamentas", {"Lleva el Libro de Aquor, las zarpas plateadas y el corazón de Troncoferro a Tanaris.","","Utiliza el Libro de Aquor para invocar Aquamentas.","","Cuando tengas el tótem completo llévaselo a J.D. Collie en el Refugio de Marshal."}},
[4021] = {"¡Contraataca!", {"Mata centauros Kolkar hasta que aparezca Krom'zar, después asesínalo y coge una pieza del estandarte de Krom'zar."}},
[4022] = {"Un sabor a llamarada", {"Enséñale a Cyrus Therepentio la escama de Vuelo Negro que recibiste de Kalaran Espada del Viento."}},
[4023] = {"Un sabor a llamarada", {"Demuéstrale a Cyrus Therepentio lo que vales.","","Te da la impresión de que Cyrus ya sabe que no eres digno."}},
[4024] = {"Un sabor a llamarada", {"Viaja hasta las Profundidades de Roca Negra y mata a Bael'Gar.","","Solo sabes que el gigante vive en las Profundidades de Roca Negra. Acuérdate de usar la escama alterada de Vuelo Negro sobre los restos de Bael'Gar para capturar la esencia ígnea.","","Llévale la esencia ígnea encerrada a Cyrus Therepentio."}},
[4041] = {"El Elixir de Videre", nil},
[4061] = {"La revuelta de las máquinas", {"Adéntrate en Las Estepas Ardientes y recupera 10 fragmentos elementales fracturados para Hierofante Theodora Mulvadania.","","Recuerdas que Theodora mencionó que los gólems y elementales de esa región eran la fuente de estos fragmentos."}},
[4062] = {"La revuelta de las máquinas", {"Lleva el ejemplar de fragmento elemental a Lotwil Veriatus.","","Recuerdas que Theodora dijo que Lotwil se encontraba en un campamento hacia el este."}},
[4063] = {"La revuelta de las máquinas", {"Encuentra al Señor Gólem Argelmach y mátalo. Llévale su cabeza a Lotwil. Asimismo tendrás que reunir 10 núcleos de elemental intactos de los gólems Furiatracadores y de los ensamblajes belisario que protegen a Argelmach. Lo sabes porque eres <un adivino/una adivina>."}},
[4081] = {"MATAR INMEDIATAMENTE: enanos Hierro Negro", {"Adéntrate en las Profundidades de Roca Negra ¡y destruye a esos viles agresores!","","El señor de la guerra Dientegore quiere que mates a 15 celadores Yunque Colérico, 10 alcaides Yunque Colérico y 5 lacayos Yunque Colérico. Vuelve junto a él cuando hayas acabado la tarea."}},
[4082] = {"MATAR INMEDIATAMENTE: oficiales Hierro Negro de alto rango", {"Adéntrate en las Profundidades de Roca Negra ¡y destruye a esos viles agresores!","","El señor de la guerra Dientegore quiere que mates a 10 médicos Yunque Colérico, 10 soldados Yunque Colérico y 10 oficiales Yunque Colérico. Vuelve junto a él cuando hayas acabado la tarea."}},
