[4120] = {"La fuerza de la corrupción", {"Talo Pezuñahendida, del Campamento Mojache de Feralas, quiere que mates a 12 pardos Zarpira y 12 devastadores Zarpayel de Frondavil."}},
[4121] = {"¡Estás en un aprieto!", {"Escolta al prisionero, Grark Lorkrub, a través de Las Estepas Ardientes y la Montaña Roca Negra hasta La Garganta de Fuego.","","Recuerdas que Lexlort mencionó que tendría a algunos de sus hombres esperándote al otro lado para llevarse a Grark detenido.","","También tendrás que entregarle a Lexlort los grilletes de torio."}},
[4122] = {"Grark Lorkrub", {"Ve a Las Estepas Ardientes y encuentra a Grark Lorkrub. Recuerdas que Lexlort mencionó que lo habían visto por última vez en una colosal fortaleza Roca Negra.","","Cuando encuentres a Grark Lorkrub, usa los grilletes de torio para atarlo y condúcelo de vuelta por la Montaña Roca Negra hasta La Garganta de Fuego. Lexlort tendrá a algunos de sus hombres esperándote al otro lado para llevarse a Grark detenido."}},
[4123] = {"El corazón de la montaña", {"Llévale el corazón de la montaña a Maxwort Suprandor en Las Estepas Ardientes."}},
[4124] = {"El mensajero desaparecido", {"Ve al Bastión Plumaluna y habla con Ginro Mechogar."}},
[4125] = {"El mensajero desaparecido", {"Localiza el bote del mensajero por la costa de Feralas."}},
[4126] = {"Hurley Negrálito", {"Llévale la receta de Cebatruenos perdida a Ragnar Cebatruenos en Kharanos."}},
[4127] = {"Los restos del bote", {"Vuelve al Bastión Plumaluna y enseña a Ginro Mechogar el cuchillo perdido que encontraste."}},
[4128] = {"Ragnar Cebatruenos", {"Habla con Ragnar Cebatruenos."}},
[4129] = {"La revelación del cuchillo", {"Lleva el cuchillo perdido a Quintis Jonguja al Bastión Plumaluna."}},
[4130] = {"Lectura psicométrica", {"Ve al Bastión Plumaluna y habla con Ginro Mechogar."}},
[4131] = {"Los gnolls Zarpaleña", {"Busca el rastro del mensajero o sus pertenencias en los campamentos de los gnoll Zarpaleña del sur de Feralas."}},
[4132] = {"Operación: muerte a Forjainquina", {"Viaja hasta las Profundidades de Roca Negra ¡y mata al general Forjainquina! Vuelve junto al señor de la guerra Dientegore cuando hayas acabado la tarea."}},
[4133] = {"Vivian Lagrave", {"Habla con la taumaturgo oscuro Vivian Lagrave en Kargath."}},
[4134] = {"La receta de Cebatruenos perdida", {"Llévale la receta de Cebatruenos perdida a Vivian Lagrave en Kargath."}},
[4135] = {"Las Galerías Retorcidas", {"Ahora que has descubierto el rastro de Raschal, adéntrate en Las Galerías Retorcidas y encuéntrale... o encuentra lo que quede de él. Según la nota, debes dirigirte al sur de los campamentos de los Zarpaleña."}},
[4136] = {"Ribbly Llavenrosca", {"Llévale la cabeza de Ribbly a Yuka Llavenrosca en Las Estepas Ardientes."}},
[4141] = {"Muigin y Larion", {"Recoge 15 pétalos de sangre y ve a ver a Muigin."}},
[4142] = {"Visita a Gregan", {"Llévale un Sangrepétalo a Gregan Tirabirras de Feralas."}},
[4143] = {"Bruma del mal", {"Reúne 5 muestras de calima Atal'ai y después ve a ver de nuevo a Muigin al Cráter de Un'Goro."}},
[4144] = {"Brotes Sangrepétalo", nil},
[4145] = {"Larion y Muigin", {"Caza 5 azotadores Sangrepétalo, 5 trilladores Sangrepétalo, 5 desolladores Sangrepétalo y 5 tramperos Sangrepétalo para Larion en el Refugio de Marshal."}},
[4146] = {"Combustible de irradior", {"Entrega el Controlador descargado y 5 muestras de calima Atal'ai a Larion, en el Refugio de Marshal."}},
[4147] = {"El taller de Marvon", {"Viaja hasta el taller de Marvon Buscarroblones en Trinquete."}},
