[4808] = {"Felnok Acerovera", {"Entrégale la carta de Tinkee a Felnok Acerovera en Vista Eterna, en Cuna del Invierno."}},
[4809] = {"Cuernos de Orvallo", {"Reúne 8 cuernos de quimera del Orvallo."}},
[4810] = {"Regresa junto a Tinkee", {"Llévale el paquete de Felnok a Tinkee Vaporio en el Peñasco Llamarada en Las Estepas Ardientes."}},
[4811] = {"El cristal rojo", {"Viaja al este de Auberdine y busca un gran cristal rojo en la zona montañosa que hay al este de Costa Oscura. Vuelve a Auberdine e informa de lo que has encontrado a la centinela Glynda Nal'Shea."}},
[4812] = {"Agua en cascada", {"Llena el tubo de agua vacío en la Poza de la Luna de Auberdine y luego examina el cristal rojo a lo largo de la pared montañosa oriental de Costa Oscura."}},
[4813] = {"Los trozos del interior", {"Vuelve a Auberdine e informa de lo que has averiguado a la centinela Glynda Nal'Shea."}},
[4821] = {"Un huevo extraño", {"Devuélvele el huevo extraño a Hagar Pezuña del Rayo, que está en el Poblado Viento Libre."}},
[4822] = {"¡Quiero un heladooooo!", {"Consigue helado de fresa para tu pupilo. Parece que el favorito del muchacho es el helado de Tigule y Foror."}},
[4841] = {"Apaciguar al centauro", {"Mata a 12 exploradores Galak, 10 retadores Galak y 6 cazavientos Galak, y después ve a ver de nuevo al vigiarrisco Cuerno Largo al Poblado Viento Libre."}},
[4842] = {"Fuentes extrañas", {"Sigue las indicaciones de Donova Cubilnevado y vuelve a informarle."}},
[4861] = {"Lechúcico salvaje iracundo", {"Localiza el campamento arrasado y los suministros de Jaron Tallapiedras en la parte sur de Cuna del Invierno."}},
[4862] = {"Bestia amaestrada", {"Viaja a la Cumbre de Roca Negra y reúne 15 huevos de araña de la cumbre para Kibler.","","Yo diría que se pueden encontrar estos huevos cerca de arañas."}},
[4863] = {"Lechúcico salvaje iracundo", {"Encuentra el carro destrozado de Jaron Tallapiedras."}},
[4864] = {"Lechúcico salvaje iracundo", {"Recoge de la nieve los Suministros de Jaron y encuentra al lechúcico salvaje que robó el amuleto del que te habló Jaron.","","Lleva los Suministros de Jaron y el Amuleto de plumas azules a Jaron Tallapiedras en el refugio de Cuna del Invierno."}},
[4865] = {"Venganza", {"Cuéntale lo que has descubierto a Motega Crin de Fuego en el Campamento del Tramo Blanco, en Las Mil Agujas."}},
[4866] = {"La leche de la madre", {"En el corazón de la Cumbre de Roca Negra encontrarás a la madre Telabrasada. Provócala para que te envenene. Lo más seguro es que tendrás que matarla también. Vuelve junto a John Andrajoso cuando estés envenenado para que pueda extraer el veneno de ti."}},
[4867] = {"Urok Aullasino", {"Lee el pergamino de Warosh. Llévale el mojo de Warosh a Warosh."}},
[4881] = {"Complot de asesinato", {"Avisa a Kanati Nube Gris, en el Campamento del Tramo Blanco, acerca de la conspiración para acabar con su vida."}},
[4882] = {"Guardar un secreto", {"Lleva el Collar de plumas azules a Trull Fallarruina en el Puesto del Veneno."}},
[4883] = {"Guardar un secreto", {"Lleva el Collar de plumas azules a Nara Ferocrín."}},
[4901] = {"Guardianes del altar", {"Protege a Ranshalla mientras intenta reactivar el Altar de Elune. Informa sobre tus descubrimientos a Erelas Cieloámbar de Aldea Rut'theran."}},
[4902] = {"Lechúcico salvaje de Elune", {"Habla con el archidruida Fandral Corzocelada en Darnassus."}},
[4903] = {"La orden del Señor de la Guerra", {"Mata al alto señor Omokk, al maestro de guerra Voone y al señor supremo Vermiothalak. Recupera importantes documentos Roca Negra. Vuelve junto al señor de la guerra Dientegore en Kargath cuando hayas cumplido la misión."}},
[4904] = {"Al fin libre", {"Saca a Lakota Son del Viento de Cumbre de la Nube Negra y después habla con Thalia Ocultaámbar, que está en el Poblado Viento Libre."}},
[4906] = {"Más corrupción", {"Eridan Vientoazul de Frondavil quiere que mates a 8 clamainfernos Fuego de Jade, 8 traidores Fuego de Jade, 8 timadores Fuego de Jade y a Xavaric. Vuelve con Eridan cuando lo hayas hecho."}},
[4907] = {"Tinkee Vaporio", {"Habla con Tinkee Vaporio en el Peñasco Llamarada, en las Estepas Ardientes."}},
[4921] = {"Perdida en la batalla", {"Encuentra a la esposa de Mankrik y llévala a El Cruce."}},
[4941] = {"La sabiduría de Eitrigg", {"Habla con Eitrigg en Orgrimmar. Cuando hayas tratado unos asuntos con Eitrigg, busca el consejo de Thrall.","","Recuerdas haber visto a Eitrigg en la Cámara de Thrall."}},
[4961] = {"La purificación del orbe de Orahil", {"Mata al demonio del orbe y luego habla con Tabetha."}},
[4962] = {"Fragmento de can manáfago", {"Coge el rubí de Felhas y úsalo en uno de los canes manáfagos de Desolace. Cuando lo consigas, llévale el rubí de Felhas y el espíritu del can manáfago encarcelado a Menara Nadiz en Los Baldíos."}},
[4963] = {"Fragmento de infernal", {"Coge la esmeralda de Infus y úsala en uno de los infernales de Desolace. Cuando lo consigas, llévale la esmeralda de Infus y el espíritu del infernal encarcelado a Menara Nadiz en Los Baldíos."}},
[4964] = {"El orbe completo de Dar'Orahil", {"Espera a Menara Nadiz para completar el orbe de Dar'Orahil y vuelve entonces a hablar con ella."}},
[4965] = {"El conocimiento del orbe de Orahil", {"Habla con Menara Nadiz en Los Baldíos."}},
[4966] = {"Defensa de Kanati Nube Gris", {"Defiende a Kanati Nube Gris contra el ataque de los centauros."}},
[4967] = {"El conocimiento del orbe de Orahil", {"Habla con Menara Nadiz en Los Baldíos."}},
[4968] = {"El conocimiento del orbe de Orahil", {"Habla con Menara Nadiz en Los Baldíos."}},
[4969] = {"El conocimiento del orbe de Orahil", {"Habla con Menara Nadiz en Los Baldíos."}},
[4970] = {"Provisiones de sable de hielo", {"Recoge 5 carnes de Dentoesquirla y 5 carnes de Orvallo para Rivern Ventogélido de Cuna del Invierno."}},
[4971] = {"Una cuestión de tiempo", {"Utiliza el desplazador temporal junto a uno de los silos de Andorhal y saca a la luz los parásitos temporales.","","Mata a 10 parásitos temporales y devuélvele el desplazador temporal a Cromi en la posada de Andorhal, en las Tierras de la Peste del Oeste."}},
[4972] = {"Contar el tiempo", {"Localiza 5 relojes de Andorhal, los encontrarás en cajas fuertes entre las ruinas de la ciudad. Cuando los tengas regresa con Cromi, en la posada de Andorhal, en las Tierras de la Peste del Oeste."}},
[4973] = {"Contar el tiempo", {"Localiza 5 relojes de Andorhal entre las ruinas de la ciudad y llévaselos a Cromi, en la posada de Andorhal, en las Tierras de la Peste del Oeste."}},
[4974] = {"¡Por la Horda!", {"Ve a Cumbre de Roca Negra para matar al Jefe de Guerra Rend Puño Negro. Lleva su cabeza a Orgrimmar."}},
[4975] = {"El orbe completo de Noh'Orahil", {"Espera a Menara Nadiz para completar el orbe de Noh'Orahil y vuelve entonces a hablar con ella."}},
[4976] = {"Devolver el orbe purificado", {"Llévale el orbe infernal limpio a Menara Nadiz en Los Baldíos."}},
[4981] = {"La espía Bijou", {"Viaja hasta la Cumbre de Roca Negra y averigua qué le ha ocurrido a Bijou."}},
[4982] = {"Las pertenencias de Bijou", {"Encuentra las pertenencias de Bijou y devuélveselas. Recuerdas que ella mencionó haberlas ocultado en la planta baja de la ciudad."}},
[4983] = {"El informe de reconocimiento de Bijou", {"Llévale el informe de reconocimiento de Bijou al maestro mayor Lexlort en Kargath."}},
[4984] = {"La naturaleza también sufre", {"Destruye 8 lobos malsanos y regresa con Mulgris Río Hondo en El Tormento, en las Tierras de la Peste del Oeste."}},
[4985] = {"La naturaleza también sufre", {"Destruye 8 pardos malsanos y regresa con Mulgris Río Hondo en El Tormento, en las Tierras de la Peste del Oeste."}},
[4986] = {"Rama de roble con inscripciones", {"Según la magia con la que está encantada La rama de roble con inscripciones, el siguiente paso del druida tauren debía ser su entrega al Círculo Cenarion en Darnassus. Pide ayuda a uno de los druidas que encontrarás allí."}},
[4987] = {"Rama de roble con inscripciones", {"Según la magia con la que está encantada de La rama de roble con inscripciones, el siguiente paso del druida tauren debía ser su entrega al Círculo Cenarion de Cima del Trueno. Pide ayuda a uno de los druidas que encontrarás allí."}},
[5001] = {"Las pertenencias de Bijou", {"Encuentra las pertenencias de Bijou y devuélveselas. ¡Suerte!"}},
[5002] = {"Un mensaje para Maxwell", {"Viaja a Las Estepas Ardientes y dale la información sobre Bijou al mariscal Maxwell."}},
[5021] = {"Más vale tarde que nunca", {"Entre lamentos, la mujer fantasmal recordaba tener que entregar un paquete. Según ella estaba junto a su caballo. No puedes entender dónde está el caballo o dónde había que entregar el paquete."}},
[5022] = {"Más vale tarde que nunca", {"Consulta con los agentes reales de Ventormenta para averiguar el paradero de una tal Emma Piedra Mácula. Suele haber un oficial del censo en el Ayuntamiento."}},
[5023] = {"Más vale tarde que nunca", {"Consulta con los supervisores reales de Entrañas para averiguar el paradero de Jeremiah Piedra Mácula. Suele haber un oficial del censo junto a la oficina de registro de hermandades y tabardos."}},
[5041] = {"Suministros para El Cruce", {"Reúne 5 cajones de suministros de El Cruce en el interior de la cueva de los Crines de Acero."}},
[5042] = {"La fuerza de Agamaggan", nil},
[5043] = {"La agilidad de Agamaggan", nil},
[5044] = {"La sabiduría de Agamaggan", nil},
[5045] = {"Fortaleza de espíritu", nil},
[5046] = {"Ocultafilo", nil},
[5047] = {"¡Finkle Einhorn, a tu servicio!", {"Habla con Malyfous Martilloscuro en Vista Eterna."}},
[5048] = {"El buen carácter de Emma", {"Encuentra a la Vieja Emma en Ventormenta y descubre si realmente es Emma Piedra Mácula. Si lo es, quizás quiera el paquete que Janice Piedra Mácula hizo para ella."}},
[5049] = {"La depre de Jeremiah", {"Encuentra a Jeremiah Payson en Entrañas y averigua si en realidad es Jeremiah Piedra Mácula. Si es así, quizás quiera el paquete que Janice Piedra Mácula preparó para él."}},
[5050] = {"Talismán de buena suerte", {"Devuelve a Janice Piedra Mácula en las Tierras de la Peste del Oeste su Medio talismán de buena suerte."}},
[5051] = {"Dos mitades hacen una", {"Localiza la otra mitad del talismán de la suerte en algún lugar del Campo de Piedramácula, en las Tierras de la Peste del Oeste, y recomponlo.","","Dale el talismán de la suerte a Janice Piedra Mácula en la Granja de Piedra Mácula, en las Tierras de la Peste del Oeste."}},
[5052] = {"Esquirlas de sangre de Agamaggan", {"Llévale una esquirla de sangre a Quebrantadientes en el Campamento Taurajo en Los Baldíos.","","Reúne más esquirlas de sangre si quieres que te bendiga con el poder de Agamaggan."}},
[5054] = {"Ursius de los Dentoesquirla", {"Ventisca Pezuña Umbría de Vista Eterna, en Cuna del Invierno, quiere que mates a Ursius."}},
[5055] = {"Brumerán de los Orvallo", {"Ventisca Pezuña Umbría de Vista Eterna, en Cuna del Invierno, quiere que mates a Brumerán."}},
[5056] = {"Shi-Rotam", {"Ventisca Pezuña Umbría de Vista Eterna, en Cuna del Invierno, quiere que acabes con Shi-Rotam."}},
[5057] = {"Esfuerzos del pasado", {"Lleva la Señal de Ventisca Pezuña Umbría a Melor Pezuña Pétrea de Cima del Trueno."}},
[5058] = {"El diario de la señora Dalson", nil},
[5059] = {"Encierro", nil},
[5060] = {"Encierro", nil},
[5061] = {"Forma acuática", {"Vuelve a Darnassus y enséñale el colgante del león marino a Mathrengyl Garroso."}},
[5062] = {"El fuego Sagrado", {"Recoge 10 pitas incendiarias y después pide consejo a Magatha Tótem Siniestro en el Alto de los Ancestros de Cima del Trueno."}},
[5063] = {"Almete del Sabio Escarlata", {"Para crear el Almete del Sabio Escarlata deberás llevarle los siguientes objetos a Malyfous Martilloscuro: 1 pellejo de la Bestia prístino; 5 costuras desgarradas de abominación; 8 cristales Arcanos; 5 hilos escarlata encantados.","","También tendrás que pagar 50 piezas de oro para la elaboración del almete."}},
[5064] = {"Espiando a los Tótem Siniestro", {"Localiza y reúne las 3 notas secretas que hay en Cumbre de la Nube Negra."}},
[5065] = {"Las tablillas perdidas Mosh'aru", {"Llévale la tercera y cuarta tablillas Mosh'aru al prospector Ferrobota, que está en Tanaris."}},
[5066] = {"Un llamamiento a las armas: las Tierras de la Peste", {"Busca al comandante Ashlam Puñovalor. Su campamento base se encuentra en Campamento del Orvallo, al norte de las Montañas de Alterac."}},
[5067] = {"Leotardos de Arcana", {"Para crear los leotardos arcana deberás llevarle los siguientes objetos a Malyfous Martilloscuro: 1 pellejo de la Bestia prístino; 5 costuras desgarradas de abominación; 5 barras de arcanita; 5 líquidos de embalsamar de Murmuhielo.","","También tendrás que pagar 50 piezas de oro para la elaboración del almete."}},
[5068] = {"Coraza Sed de Sangre", {"Para crear la coraza Sed de Sangre deberás llevarle los siguientes objetos a Malyfous Martilloscuro: 1 pellejo de la Bestia prístino; 10 costuras desgarradas de abominación; 5 barras de arcanita; 5 pieles de Sombra.","","También tendrás que pagar 50 piezas de oro para la elaboración del almete."}},
[5081] = {"La misión de Maxwell", {"Viaja a la Cumbre de Roca Negra y acaba con el maestro de guerra Voone, el alto señor Omokk y el señor supremo Vermiothalak."}},
[5082] = {"La amenaza de los Nevada", {"Donova Cubilnevado de Cuna del Invierno quiere que mates 8 abrecaminos Nevada, 8 vigías del cubil Nevada y 8 totémicos Nevada."}},
[5083] = {"Aguardiente Nevada", {"Lleva el frasco vacío de aguardiente a Donova Cubilnevado de Cuna del Invierno."}},
[5084] = {"Sucumbir a la corrupción", {"Busca una pista en el campamento fúrbolg Muertobosque en el norte de Frondavil."}},
[5085] = {"Baba misteriosa", {"Informa sobre tus descubrimientos a Donova Cubilnevado."}},
[5086] = {"Horrores tóxicos", {"Recoge 3 gotitas de horror tóxico para Donova Cubilnevado de Cuna del Invierno."}},
[5087] = {"Corredores Nevada", {"Encuentra a los corredores Nevada y detenlos antes de que entreguen su cargamento en Poblado Nevada."}},
[5088] = {"Arikara", {"Mata a Arikara. Llévale sus restos y el polvo de incendiaria a Motega Pirocabello al Campamento del Tramo Blanco como prueba de tus actos."}},
[5089] = {"Orden del general Drakkisath", {"Llévale la orden del general Drakkisath al mariscal Maxwell en Las Estepas Ardientes."}},
[5090] = {"Un llamamiento a las armas: las Tierras de la Peste", {"Busca al comandante Ashlam Puñovalor. Su campamento base se encuentra en Campamento del Orvallo, al norte de las Montañas de Alterac."}},
[5091] = {"Un llamamiento a las armas: las Tierras de la Peste", {"Busca al comandante Ashlam Puñovalor. Su campamento base se encuentra en Campamento del Orvallo, al norte de las Montañas de Alterac."}},
[5092] = {"Despejar el camino", {"Mata 10 despellejadores esqueléticos y 10 necrófagos esclavizantes en la Colina de las Penas.","","Vuelve con el comandante Ashlam Puñovalor en el Campamento del Orvallo, en las Tierras de la Peste del Oeste."}},
[5093] = {"Un llamamiento a las armas: las Tierras de la Peste", {"Busca al sumo ejecutor Derrington; su campamento base está en El Baluarte, al este de Claros de Tirisfal y Entrañas."}},
[5094] = {"Un llamamiento a las armas: las Tierras de la Peste", {"Busca al sumo ejecutor Derrington; su campamento base está en El Baluarte, al este de Claros de Tirisfal y Entrañas."}},
[5095] = {"Un llamamiento a las armas: las Tierras de la Peste", {"Busca al sumo ejecutor Derrington; su campamento base está en El Baluarte, al este de Claros de Tirisfal y Entrañas."}},
[5096] = {"Distracción Escarlata", {"Adéntrate en el campamento base de la Cruzada Escarlata entre el Campo de Piedramácula y el Llanto de Dalson y destruye su tienda de mando.","","Coloca el estandarte de la Plaga en el campamento y vuelve con el sumo ejecutor Derrington en El Baluarte en las Tierras de la Peste del Oeste."}},
[5097] = {"Todas las atalayas", {"Con la antorcha de aviso, marca las atalayas de Andorhal. Tendrás que estar en la entrada de la atalaya para poder marcarla.","","Cuando estén marcadas las cuatro atalayas devuelve la antorcha de aviso al comandante Ashlam Puñovalor del Campamento del Orvallo, en las Tierras de la Peste del Oeste."}},
[5098] = {"Todas las atalayas", {"Con la antorcha de aviso, marca las atalayas de Andorhal. Tendrás que estar en la entrada de la atalaya para poder marcarla.","","Cuando estén marcadas las cuatro atalayas, devuelve la antorcha de aviso al sumo ejecutor Derrington en El Baluarte, en las Tierras de la Peste del Oeste."}},
[5102] = {"Muerte al general Drakkisath", {"Viaja hasta la Cumbre de Roca Negra y mata al general Drakkisath."}},
[5103] = {"Muerte abrasadora", {"Alguien en este mundo debe de saber qué hacer con estos guanteletes. ¡Suerte!"}},
[5121] = {"Gran Jefe Nevada", {"Donova Cubilnevado de Cuna del Invierno quiere que derrotes al Gran Jefe Nevada."}},
[5122] = {"El medallón de Fe", nil},
[5123] = {"La pieza final", {"Lleva el diario mal escrito a Donova Cubilnevado de Cuna del Invierno."}},
[5124] = {"Guanteletes de placas ígneas", {"Lleva a Malyfous Martilloscuro 6 barras de torio encantado, 2 esencias de fuego y 4 rubíes estrellados. También tendrás que entregarle tus guanteletes de placas sin templar."}},
[5125] = {"La estimación de Aurius", nil},
[5126] = {"La historia de Lorax", {"Habla con Lorax. Escucha todo lo que tiene que decirte."}},
[5127] = {"La forja demoníaca", {"Viaja a la Cumbre de Roca Negra y encuentra a Goraluk Yunquegrieta. Mátale y utiliza el Pica manchada de sangre sobre su cadáver. Cuando hayas absorbido su alma, la pica estará manchada de alma.","","También debes encontrar la coraza cubierta de runas sin forjar.","","Lleva la pica manchada de alma y la coraza cubierta de runas sin forjar a Lorax en Cuna del Invierno."}},
[5128] = {"Las palabras del Gran Jefe", {"Lleva el registro escrito de forma rudimentaria a Kelek Guardacielo en el sur de Frondavil."}},
[5141] = {"Peletería dragontina", {"Consigue 2 corazas de escórpido resistentes, 2 guantes de escórpido resistentes, y 10 dragontinas desgastadas para Peter Galen, en Azshara.","","Si completas esta misión tendrás acceso al arte de la peletería dragontina.","","Si lo haces, también dejarás de tener acceso a la peletería elemental y tribal. Tienes que asegurarte de querer seguir este camino antes de completarla."}},
[5142] = {"La pequeña Pamela", {"Encuentra a Pamela Rutagrana en Villa Darrow."}},
[5143] = {"Peletería tribal", {"Lleva 1 jubón de cuero salvaje y 1 casco de cuero salvaje a Caryssia Cazaluna a Feralas.","","Si completas esta misión, tendrás acceso a las artes de Peletería tribal.","","Si lo haces, no podrás aprender peletería dragontina ni peletería elemental; asegúrate de que este es el camino que deseas seguir antes de completar la misión."}},
[5144] = {"Peletería elemental", {"Lleva 2 corazones de fuego, 2 globos de agua, 2 núcleos de tierra y 2 alientos de viento a Sarah Peletero a La Garganta de Fuego.","","Al completar esta tarea aprenderás peletería elemental.","","Si te dedicas a este arte, no podrás aprender peletería dragontina ni peletería tribal; piénsatelo bien antes de decidirte."}},
[5145] = {"Peletería dragontina", {"Consigue 2 corazas de escórpido resistentes, 2 guantes de escórpido resistentes, y 10 dragontinas desgastadas para Thorkaf Ojo de Dragón, en las Tierras Inhóspitas.","","Si completas esta misión tendrás acceso al arte de la peletería dragontina.","","Si lo haces, también dejarás de tener acceso a la peletería elemental y tribal. Tienes que asegurarte de querer seguir este camino antes de completarla."}},
[5146] = {"Peletería elemental", {"Llévale 2 corazones de fuego, 2 globos de agua, 2 núcleos de tierra y 2 alientos de viento a Brumm Pezuña Invernal en las Tierras Altas de Arathi.","","Cuando completes esta misión tendrás acceso a las artes de peletería elemental.","","Si completas esta misión, no podrás aprender peletería dragontina ni peletería tribal; asegúrate de que este es el camino que deseas seguir antes de tomarlo."}},
[5147] = {"Se busca: Arnak Tótem Siniestro", {"Mata a Arnak Tótem Siniestro y llévale una prueba de tu hazaña al vigiarrisco Cuerno Largo, que está en el Poblado Viento Libre."}},
[5148] = {"Peletería tribal", {"Lleva un jubón de cuero salvaje y un casco de cuero salvaje a Se'Jib en la Vega de Tuercespina.","","Completar esta misión te proporcionará acceso a las artes de la peletería tribal.","","Completar esta misión evitará que aprendas peletería dragontina y peletería elemental. Asegúrate que este es el camino que quieres seguir antes de hacerlo."}},
[5149] = {"La muñeca de Pamela", {"Encuentra la muñeca de Pamela."}},
[5150] = {"¡Dadanga tiene hambre!", nil},
[5151] = {"Hipercondensador", {"Acaba con la bestia y trae de regreso el hipercondensador y la llave de la jaula de pantera a Wizlo Rodabrillante."}},
[5152] = {"Tía Marlene", {"Habla con Marlene. Está al sur de las Ruinas de Andorhal."}},
[5153] = {"Una extraña historiadora", {"Lleva la alianza de Joseph a Cromi."}},
[5154] = {"Las Crónicas de Villa Darrow", {"Lleva el libro Crónicas de Villa Darrow a Cromi a Andorhal."}},
[5155] = {"Las fuerzas de Jaedenar", {"Entra en Jaedenar y mata a 4 canes Jaedenar, 4 guardianes Jaedenar, 6 adeptos Jaedenar y 6 cultores Jaedenar antes de volver con Greta Pezuñamusgo a Frondavil."}},
[5156] = {"Investigación acerca de la corrupción", {"Busca y destruye a 2 bestias entrópicas y 2 horrores entrópicos a la vez que exploras la Cañada Gran Cicatriz. Cuando hayas comprobado si los cráteres del lugar aún contienen agua vil corrupta, vuelve con Taronn Plumarroja a Frondavil."}},
[5157] = {"Una muestra de agua corrupta", {"Lleva la cantimplora vacía a la Poza de la Luna que hay en el centro de Jaedenar y llénala antes de volver con Greta Pezuñamusgo a Frondavil."}},
[5158] = {"Buscando ayuda espiritual", {"Lleva el agua de la Poza de la Luna corrupta a Islen Vidente del Agua a Los Baldíos."}},
[5159] = {"El agua purificada vuelve a Frondavil", {"Lleva el agua de la Poza de la Luna purificada a Greta Pezuñamusgo en Frondavil."}},
[5160] = {"El Protectorado de la matrona", {"Viaja hasta la Cuna del Invierno y encuentra a Haleh. Dale la escama de Awbee."}},
[5161] = {"La cólera del Vuelo Azul", {"Habla con Haleh si quieres continuar."}},
[5162] = {"La cólera del Vuelo Azul", {"Habla con Jeziba en las Tierras de la Peste. Vive en Andorhal."}},
[5163] = {"Yeti... ¿ya hemos llegado?", {"Coge el yeti mecánico de Umi y asusta con él a sus amigos:","","Legacki en Vista Eterna (Cuna del Invierno)","","Roxio en Gadgetzan (Tanaris)","","Quixxil en el Refugio de Marshal (Cráter de Un'Goro)","","Cuando hayas terminado, devuelve el yeti mecánico a Umi."}},
[5164] = {"Catálogo del Díscolo", {"Lee el Catálogo del Díscolo."}},
[5165] = {"Sofocar las llamas de protección", {"Utiliza el agua de la Poza de la Luna purificada para apagar las llamas de los cuatro Blandones de Protección de la Guarida Sombría de Frondavil y vuelve con Greta Pezuñamusgo al Santuario Esmeralda."}},
[5166] = {"Coraza del Vuelo Cromático", {"Para forjar la coraza del Vuelo Cromático deberás llevarle a Jeziba el 'Escultor\" los siguientes objetos:","","1 caparazón cromático.","","10 escamas cromáticas luminosas.","","10 sangres de héroes.","","10 costuras desgarradas de abominación."}},
[5167] = {"Quijotes del desafiante cromático", {"Para forjar los quijotes del desafiante cromático deberás llevarle a Jeziba el 'Escultor\" los siguientes objetos:","","1 caparazón cromático.","","10 escamas cromáticas luminosas.","","10 sangres de héroes.","","5 pieles de Sombra."}},
[5168] = {"Los héroes de Villa Darrow", {"Lleva el Tratado de Davil y el Escudo de Rutagrana a Carlin Rutagrana."}},
[5181] = {"Los villanos de Villa Darrow", {"Lleva el cráneo de Horgus y la espada destrozada de Marduk a Carlin Rutagrana a la Capilla de la Esperanza de la Luz."}},
[5201] = {"Intrusión Nevada", {"Rivern Ventogélido quiere que mates 5 chamanes Nevada y 5 ursas Nevada."}},
[5202] = {"Una extraña llave roja", {"Recorre Jaedenar y descubre para qué se utiliza la llave roja de sangre."}},
[5203] = {"El rescate en Jaedenar", {"Escolta a Arko'narin hasta el lugar en el que están Forjaluz y su equipo y protégela en la huida de la Guarida Sombría. Después, busca a Jessir Arcolunar en Frondavil para contarle lo que les ha ocurrido a sus amigos."}},
[5204] = {"La reprensión de la Luz", {"Vuelve a Jaedenar y mata al súcubo Rakaiah antes de encontrar los Restos de Trey Forjaluz."}},
[5206] = {"Los merodeadores de Villa Darrow", {"Lleva 5 calaveras resonadoras y el cristal místico a Carlin Rutagrana a las Tierras de la Peste del Este."}},
[5210] = {"Carlin, el hermano de Joseph", {"Lleva las Crónicas ampliadas de Villa Darrow a Carlin Rutagrana a las Tierras de la Peste del Este."}},
[5211] = {"Los defensores de Villa Darrow", {"Libera a 15 espíritus de Villa Darrow y vuelve con Carlin Rutagrana."}},
[5212] = {"La carne no miente", {"Recoge 10 muestras de carne apestada de Stratholme y vuelve con Betina Bigglezink. Sospechas que podrías obtener una muestra de cualquier criatura de Stratholme."}},
[5213] = {"El agente activo", {"Viaja a Stratholme y busca los zigurats. Encuentra información sobre la Plaga y llévasela a Betina Bigglezink."}},
[5214] = {"El gran Fras Siabi", {"Encuentra la Tienda de humo de Fras Siabi en Stratholme y recupera una caja del tabaco de calidad de Siabi. Cuando lo hayas hecho, vuelve con Smokey LaRue."}},
[5215] = {"Las calderas de la Plaga", {"Habla con la suma sacerdotisa MacDonnell en el Alto del Orvallo, en las Tierras de la Peste del Oeste."}},
[5216] = {"Objetivo: Campo de Piedramácula", {"Ve al Campo de Piedramácula en las Tierras de la Peste del Oeste para localizar y derrotar a su señor de la caldera. Seguramente tendrá una llave para acceder a la caldera. Debes llevar contigo la Botella vacía del Campo de Piedramácula para obtener una muestra de los venenos utilizados en el interior de la caldera."}},
[5217] = {"Regresa al Campamento del Orvallo", {"Lleva la Botella rellena del Campo de Piedramácula a la suma sacerdotisa MacDonnell en el Campamento del Orvallo, en las Tierras de la Peste del Oeste."}},
[5218] = {"La caldera del Campo de Piedramácula", nil},
[5219] = {"Objetivo: Llanto de Dalson", {"Ve al Llanto de Dalson en las Tierras de la Peste del Oeste para localizar y derrotar a su señor de la caldera. Utiliza su llave para acceder a la caldera. Debes llevar contigo la botella vacía del Llanto de Dalson para obtener una muestra de los venenos utilizados en el interior de la caldera."}},
[5220] = {"Regresa al Campamento del Orvallo", {"Lleva la botella del Llanto de Dalson llena a la suma sacerdotisa MacDonnell en el Campamento del Orvallo, en las Tierras de la Peste del Oeste."}},
[5221] = {"La caldera del Llanto de Dalson", nil},
