[5421] = {"Pescado en un balde", {"Jinar'Zillen quiere que recojas 5 mariscos de las trampas que hay cerca de la Aldea Cazasombras."}},
[5441] = {"Peones vagos", {"Utiliza la Cachiporra del supervisor con los peones vagos que estén durmiendo. Despierta a 5 peones y devuélvele la cachiporra al supervisor Thazz'ril en el Valle de los Retos."}},
[5461] = {"El humano, Ras Murmuhielo", {"Viaja a las Tierras Altas de Arathi, a las Ruinas de Stromgarde. En Stromgarde busca un Libro de los Recuerdos. Si lo encuentras llévaselo al magistrado Marduke."}},
[5462] = {"El moribundo, Ras Murmuhielo", {"Viaja a Esperanza de la Luz en las Tierras de la Peste del Este y busca a Leonid Barthalomew el Venerado. Enséñale el Libro de los Recuerdos y cuéntale todo lo que has descubierto."}},
[5463] = {"El Obsequio de Menethil", {"Viaja a Stratholme y encuentra el Obsequio de Menethil. Coloca el Libro de los Recuerdos en suelo no consagrado."}},
[5464] = {"El Obsequio de Menethil", {"Lleva el Libro de Memorias del Alma a Leonid Barthalomew a las Tierras de la Peste del Este."}},
[5465] = {"El Libro de Memorias del Alma", {"Vuelve con el magistrado Marduke a Castel Darrow. Muéstrale el Libro de Memorias del Alma."}},
[5466] = {"El exánime, Ras Murmuhielo", {"Busca a Ras Murmuhielo en Scholomance. Cuando lo hayas encontrado utiliza el Libro de Memorias del Alma sobre su rostro no-muerto. Si consiguieras convertirlo en mortal, derrótale y recupera la Cabeza humana de Ras Murmuhielo. Lleva la cabeza al magistrado Marduke."}},
[5481] = {"La tarea de Gordo", {"Recoge 3 hierbas luminiscentes y entrégaselas al boticario auxiliar Holland en el cementerio de Rémol."}},
[5482] = {"Apocalíseas", {"Recoge 10 apocalíseas y entrégaselas al boticario auxiliar Holland."}},
[5501] = {"Recolección de kodos", {"Lleva 10 huesos de kodo del Cementerio de Kodos a Bibbly F'utzhebilla a la Cabaña de Kormek."}},
[5502] = {"Alcaide de la Horda", {"Compra un expositor para espadas de gomaespuma a Blax Botemisil en La Calle Mayor de Orgrimmar. Después, habla con la supervisora de huérfanos Llantobatalla en La Calle Mayor para llevar a tu pupilo de vuelta al orfanato de Orgrimmar."}},
[5503] = {"Comisión de El Alba Argenta", nil},
[5504] = {"Mantos del Alba", {"Lleva 10 muestras de valor de El Alba Argenta al intendente Hasana en El Baluarte, en las Tierras de la Peste del Oeste."}},
[5505] = {"La llave de Scholomance", nil},
[5507] = {"Mantos del Alba", {"Lleva 10 muestras de valor de El Alba Argenta al intendente Chispillo en el Campamento del Orvallo, en las Tierras de la Peste del Oeste."}},
[5508] = {"Piedras de la Plaga del corruptor", nil},
[5509] = {"Piedras de la Plaga del invasor", nil},
[5510] = {"Piedras de la Plaga del esbirro", nil},
[5511] = {"La llave de Scholomance", nil},
[5513] = {"Mantos del Alba", {"Lleva 10 muestras de valor de El Alba Argenta al intendente Cerrobrecha a la Capilla de la Esperanza de la Luz de las Tierras de la Peste del Este."}},
[5514] = {"Molde rima con... ¿oro?", {"Lleva los trozos esqueléticos imbuidos y 15 piezas de oro a Krinkle Buenacero en Gadgetzan."}},
[5515] = {"Bolsa de los horrores de Krastinov", {"Localiza a Jandice Barov en Scholomance y destrúyela. En su cadáver encontrarás la Bolsa de los horrores de Krastinov. Devuélvele la bolsa a Eva Sarkhoff."}},
[5517] = {"Manto del Alba cromático", {"Lleva 25 muestras de valor de El Alba Argenta al intendente Cerrobrecha a la Capilla de la Esperanza de la Luz de las Tierras de la Peste del Este."}},
[5518] = {"El disfraz de ogro Gordok", {"Lleva 4 madejas de paño rúnico, 8 cueros bastos, 2 hilos rúnicos y tanino de ogro a Knot Llavededo. Actualmente está encadenado en el interior del ala Gordok de La Masacre."}},
[5519] = {"El disfraz de ogro Gordok", nil},
[5521] = {"Manto del Alba cromático", {"Lleva 25 muestras de valor de El Alba Argenta al intendente Chispillo en el Campamento del Orvallo, en las Tierras de la Peste del Oeste."}},
[5522] = {"Leonid Barthalomew", {"Lleva los huevos congelados a Leonid Barthalomew a las Tierras de la Peste del Este."}},
[5524] = {"Manto del Alba cromático", {"Lleva 25 muestras de valor de El Alba Argenta al intendente Hasana en El Baluarte, en las Tierras de la Peste del Oeste."}},
[5525] = {"¡Libera a Knot!", nil},
[5526] = {"Fragmentos de gangrevid", {"Encuentra gangrevid en La Masacre y coge un fragmento. Es probable que solo puedas conseguirlo si derrotas a Alzzin el Formaferal. Usa el relicario de Pureza para guardar el fragmento y llévaselo a Rabine Saturna a Amparo de la Noche, en Claro de la Luna."}},
[5527] = {"Un relicario de Pureza", {"Ve a Silithus a buscar un relicario de Pureza en las ruinas de la Aldea del Viento del Sur. Llévaselo a Rabine Saturna a Amparo de la Noche, en Claro de la Luna."}},
[5528] = {"La cata de los Gordok", nil},
[5529] = {"Crías de dragón apestadas", {"Mata a 20 crías de dragón apestadas y ve a ver a Betina Bigglezink a la Capilla de la Esperanza de la Luz."}},
[5531] = {"Betina Bigglezink", {"Lleva los huevos congelados a Betina Bigglezink."}},
[5533] = {"Scholomance", {"Habla con el alquimista Arbington en el Alto del Orvallo, en las Tierras de la Peste del Oeste."}},
[5534] = {"El equipamiento \"perdido\" de Kim'jael", {"Encuentra una runa que los nagas guardan en las Ruinas de Eldarath y llévasela a Kim'jael en Azshara."}},
[5535] = {"Agitación espiritual", {"Mata a 6 aparecidas Altonato y 6 exanimatos Altonato antes de volver junto a Loh'atu en Azshara."}},
[5536] = {"Una tierra llena de odio", {"Mata 6 sátiros Haldarr, 2 tramposos Haldarr, 2 jurapenas Haldarr y vuelve junto a Loh'atu en la frontera de Vallefresno."}},
[5537] = {"Trozos esqueléticos", {"Lleva 15 trozos esqueléticos al alquimista Arbington, en el Alto del Orvallo, en las Tierras de la Peste del Oeste."}},
[5538] = {"Molde rima con... ¿oro?", {"Lleva los trozos esqueléticos imbuidos y 15 piezas de oro a Krinkle Buenacero en Gadgetzan."}},
[5541] = {"Municiones para Estruendo", {"Lleva la munición de Estruendo a Hegnar Estruendo a Dun Morogh."}},
[5542] = {"Perros demoníacos", {"Mata 20 cachorros de can de peste, 5 canes de peste y 5 canes de peste demenciados. Cuando hayas terminado tu tarea regresa con Tirion Vadín."}},
[5543] = {"Cielos sangrientos", {"Mata 30 murcipestes y vuelve con Tirion Vadín."}},
[5544] = {"Gusanos carroñeros", {"Busca las larvas y devoradores carroñeros de la zona. Mátalos y recoge su carne. Regresa con Tirion Vadín cuando tengas 15 trozos de carne de gusano carroñero."}},
[5545] = {"El cumplimiento del plazo", {"Lleva 8 fardos de madera a Raelen al Aserradero de la Vega del Este."}},
[5561] = {"El rodeo kodo", {"Lleva 3 kodos domados y el kombobulador kodo a Smeed Mezclatornillos, al Campamento de los Mezclatornillos."}},
[5581] = {"Los portales de la Legión", {"Destruye 6 Portales en el Aquelarre Mannoroc y vuelve al Campamento del Espíritu Errante a hablar con Felgur Doscortes."}},
[5582] = {"Escama de dragón sana", {"Lleva la escama de dragón sana a Betina Bigglezink a la Capilla de la Esperanza de la Luz, en las Tierras de la Peste del Este."}},
