[5901] = {"Una Peste en la Cruzada", {"Utiliza el tarro de termitas vacío en los montones de termitas de las Tierras de la Peste del Este. Cuando hayas reunido 100 termitas de las Tierras de la Peste, vuelve con Mickey Levine, que está en El Baluarte, en Claros de Tirisfal."}},
[5902] = {"Una Peste en la Cruzada", {"Encuentra un lugar adecuado en el centro del Aserradero Crestanorte, en las Tierras de la Peste del Oeste, para colocar la barrica de termitas de las Tierras de la Peste."}},
[5903] = {"Una Peste en la Cruzada", {"Utiliza el tarro de termitas vacío en los montones de termitas de las Tierras de la Peste del Este. Cuando hayas reunido 100 termitas de las Tierras de la Peste, vuelve con Nathaniel Dumah al Campamento del Orvallo en las Tierras de la Peste del Oeste."}},
