[5921] = {"Claro de la Luna", {"Utiliza el hechizo \"Teletransporte: Claro de la Luna\" para viajar a Claro de la Luna. Cuando llegues, ve al poblado Amparo de la Noche y habla con Dendrita Rafagaestelar."}},
[5922] = {"Claro de la Luna", {"Utiliza el hechizo \"Teletransporte: Claro de la Luna\" para viajar a Claro de la Luna. Cuando llegues, ve al poblado Amparo de la Noche y habla con Dendrita Rafagaestelar."}},
