[5929] = {"Espíritu del gran oso", {"Busca al espíritu del gran oso al noroeste de Claro de la Luna y aprende lo que tenga que enseñarte sobre la naturaleza del oso. Después ve a hablar con Dendrita Rafagaestelar a Amparo de la Noche, en Claro de la Luna."}},
[5930] = {"Espíritu del gran oso", {"Busca al espíritu del gran oso al noroeste de Claro de la Luna y aprende lo que tenga que enseñarte sobre la naturaleza del oso. Después ve a hablar con Dendrita Rafagaestelar a Amparo de la Noche, en Claro de la Luna."}},
[5931] = {"El regreso a Darnassus", {"Vuelve a Darnassus para hablar con Mathrengyl Garroso en el Enclave Cenarion."}},
[5932] = {"Vuelve a Cima del Trueno", {"Vuelve a Cima del Trueno para hablar con Turak Tótem de Runa en Alto de los Ancestros."}},
[5941] = {"Regresa junto a Cromi", {"Lleva el montón de reliquias a Cromi a Andorhal."}},
[5942] = {"Tesoros ocultos", {"Lleva la llave de Joseph al cofre de Joseph."}},
[5943] = {"La caravana Gizelton", {"Escolta la caravana Gizelton a través del Aquelarre Mannoroc. Habla con Smeed en el Campamento de los Mezclatornillos para recibir tu recompensa."}},
[5944] = {"En sueños", {"Escolta a Taelan Vadín fuera de la Vega del Amparo."}},
[5961] = {"Campeón de la Reina alma en pena", {"Habla con Nathanos Clamañublo en las Tierras de la Peste del Este. Se dice que ahora vive en la Hacienda de Marris."}},
[5981] = {"Gigantes arrasadores", {"Rivern Ventogélido quiere que mates 4 gigantes Machacahielo y 4 valedores Machacahielo."}},
[6001] = {"Cuerpo y corazón", {"Utiliza el polvo de luna Cenarion en la piedra de lechúcico lunar de Auberdine para invocar a Garraluna. Luego tendrás que enfrentarte a Garraluna y ganar la fuerza física y de corazón que posee.","","Cuando hayas acabado, vuelve a Darnassus y habla con Mathrengyl Garroso."}},
[6002] = {"Cuerpo y corazón", {"Aplica el polvo de luna Cenarion a la piedra de lechúcico lunar que se encuentra entre Mulgore y Los Baldíos para provocar a Garraluna. Hecho esto, has de enfrentarte a Garraluna para obtener la fuerza física y de corazón que posee.","","Habla con Turak Tótem de Runa en Cima del Trueno cuando hayas acabado."}},
[6004] = {"Negocios inconclusos", {"Mata a 2 médicos Escarlata, 2 cazadores Escarlata, 2 magos Escarlata y 2 caballeros Escarlata antes de regresar con Kirsta Sombraprofunda en las Tierras de la Peste del Oeste."}},
[6021] = {"Zaeldarr el Marginado", {"Lleva la cabeza de Zaeldarr al custodio Alen a la Capilla de la Esperanza de la Luz."}},
[6022] = {"Matar con un propósito", {"Viaja al Cruce de Corin al este y mata a los miembros de la Plaga que habitan allí. Recoge 7 piezas de putrefacción viva en 10 minutos. Utiliza el mortero y el majadero para convertir la putrefacción viva en putrefacción coagulada."}},
[6023] = {"Negocios inconclusos", {"Mata al montero Radley y al hidalgo Durgen antes de regresar con Kirsta Sombraprofunda en las Tierras de la Peste del Oeste."}},
[6024] = {"La súplica de Hameya", {"Mata al infiltrador Hameya. Usa su llave en el túmulo detrás de La Subgranja."}},
[6025] = {"Negocios inconclusos", {"Entra en la Vega del Amparo y busca un punto elevado desde el que puedas ver la ciudad y calcular las fuerzas de la Cruzada Escarlata. Cuando lo hayas hecho regresa con Kirsta Sombraprofunda en las Tierras de la Peste del Oeste."}},
[6026] = {"Eso pide mucho", {"Smokey LaRue quiere que consigas 2 barras de torio, 1 vara dorada, 8 bombas de gran carga y 8 disparadores inestables.","","Tendrás que encontrar a un herrero y a un ingeniero para conseguir esos objetos."}},
[6027] = {"El Libro de los Ancestros", {"Consigue el Libro de los Ancestros y llévaselo a Azore Aldamort a la torre de Ethel Rethor."}},
[6028] = {"El informe Vista Eterna", {"Entrega el informe de Vista Eterna a la oficial Argenta Purocorazón en el Campamento del Orvallo, en las Tierras de la Peste del Oeste."}},
[6029] = {"El informe Vista Eterna", {"Entrega el informe de Vista Eterna al oficial Argenta Garush en El Baluarte, en las Tierras de la Peste del Oeste."}},
[6030] = {"El duque Nicolas Zverenhoff", {"Entrega el libro, \"Estudios sobre la Comunicación con los Espíritus\", al duque Nicolas Zverenhoff en la Capilla de la Esperanza de la Luz, en las Tierras de la Peste del Este."}},
[6031] = {"Paño rúnico", {"Llévale 30 paños rúnicos a Meilosh, que está en el Bastión Fauces de Madera."}},
[6032] = {"Tela sagrada", {"Llévale 2 retales de tela lunar a Meilosh, que está en el Bastión Fauces de Madera."}},
[6041] = {"Cuando Smokey canta, me pongo violento", {"Viaja al Bosque de la Peste, al noroeste de la Esperanza de la Luz. Destruye 8 estructuras de la Plaga utilizando el compuesto especial de Smokey en la marca de detonación que hay en el interior de cada edificio. Smokey ha hecho marcar los zigurats y los degolladeros.","","Cuando plantes la bomba, sal del edificio y disfruta del espectáculo.","","Por cierto, el compuesto especial de Smokey es... bastante inestable."}},
[6042] = {"Los pequeños problemas de la no-vida", {"Mata a 20 murcipestes tóxicos y 10 murcipestes monstruosos. Vuelve con Nathanos Clamañublo cuando hayas acabado."}},
[6061] = {"Domesticar la bestia", {"Usa la fusta de doma para domar un zancudo de llanura adulto. Practica un poco y devuélvele la fusta a Yaw Crinafilada en el Poblado Pezuña de Sangre."}},
[6062] = {"Domesticar la bestia", {"Usa la fusta de doma para domar un jabalí jaspeado temible. Practica un poco y devuélvele la fusta a Thotar en Cerrotajo."}},
[6063] = {"Domesticar la bestia", {"Utiliza la fusta de doma para domar a un rondador Tejemadera. Practica tus habilidades y después devuélvele la fusta de doma a Dazalar, que está en Dolanaar."}},
[6064] = {"Domesticar la bestia", {"Usa la fusta de doma para domar a un jabalí del risco grande. Practica un poco y devuélvele la fusta a Grif Corazón Salvaje en Kharanos."}},
