[6085] = {"Domesticar la bestia", {"Usa la fusta de doma para domar un oso zarpahelada. Practica un poco y devuélvele la fusta a Grif Corazón Salvaje en Kharanos."}},
[6086] = {"Domesticar la bestia", {"Habla con Belia Tronagranito en Forjaz."}},
[6087] = {"Domesticar la bestia", {"Usa la fusta de doma para domar un acechador de pradera. Practica un poco y devuélvele la fusta a Yaw Crinafilada en el Poblado Pezuña de Sangre."}},
[6088] = {"Domesticar la bestia", {"Usa la fusta de doma para domar un aguilón. Practica un poco y devuélvele la fusta a Yaw Crinafilada en el Poblado Pezuña de Sangre."}},
[6089] = {"Domesticar la bestia", {"Habla con Holt Tronacuerno en el Alto de los Cazadores, en Cima del Trueno."}},
[6101] = {"Domesticar la bestia", {"Utiliza la fusta de doma para domar a un acechador sable de la noche. Practica tus habilidades y después devuélvele la fusta de doma a Dazalar, que está en Dolanaar."}},
[6102] = {"Domesticar la bestia", {"Utiliza la fusta de doma para domar a un estridador estrígido. Practica tus habilidades y después devuélvele la fusta de doma a Dazalar, que está en Dolanaar."}},
[6103] = {"Domesticar la bestia", {"Habla con Jocaste en el Enclave Cenarion de Darnassus."}},
[6121] = {"Nuevas lecciones", {"Viaja a Claro de la Luna, al poblado Amparo de la Noche, y habla con Dendrita Rafagaestelar."}},
[6122] = {"La fuente del envenenamiento", {"Recoge agua de Salto de Fonroca a la entrada de la cueva.","","Entrégale la muestra llena de Salto de Fonroca a Alanndarian Arrullanoche; en Auberdine, en Costa Oscura."}},
[6123] = {"Reunir los ingredientes del remedio", {"Lleva 5 raíces de tierra y 12 hongos lunares a Alanndarian Arrullanoche a Auberdine, para que pueda preparar un bálsamo curativo."}},
[6124] = {"Curar la dolencia", {"Utiliza el bálsamo curativo para animales en los 10 ciervos enfermos que hay en Costa Oscura; el bálsamo debería curarlos. Se han avistado ciervos enfermos desde el sur del Río Fonroca hasta el norte de Auberdine y por toda la zona que lleva hasta el sur de Costa Oscura, donde empieza Vallefresno."}},
[6125] = {"Poder contra el veneno", {"Vuelve a Darnassus para hablar con Mathrengyl Garroso en el Enclave Cenarion."}},
[6126] = {"Nuevas lecciones", {"Viaja a Claro de la Luna, al poblado Amparo de la Noche, y habla con Dendrita Rafagaestelar."}},
[6127] = {"La fuente del envenenamiento", {"Usa el muestrario de Cima Calígine vacío para recoger una muestra de agua de uno de los estanques de la cima.","","Luego llévale el muestrario de Cima Calígine lleno a Tonga Tótem de Runa a El Cruce, en Los Baldíos."}},
[6128] = {"Reunir los ingredientes del remedio", {"Llévale 5 raíces de tierra y 5 cuernos de kodo a Tonga Tótem de Runa en El Cruce para que pueda confeccionar un bálsamo curativo."}},
[6129] = {"Curar la dolencia", {"Usa el bálsamo animal curativo sobre las 10 gacelas enfermas que se encuentran en la parte norte de Los Baldíos; así se curarán. Hemos recibido informes según los cuales se han avistado gacelas enfermas por la carretera que va de este a oeste en El Cruce."}},
[6130] = {"Poder contra el veneno", {"Vuelve a Cima del Trueno para hablar con Turak Tótem de Runa en Alto de los Ancestros."}},
[6132] = {"¡Sácame de aquí!", {"Escolta a Melizza Zumbala."}},
[6133] = {"La orden del Señor forestal", {"Viaja a la frontera norte de las Tierras de la Peste del Este y recupera el Registro de Quel'Thalas. Se encuentra en algún lugar del Refugio Quel'Lithien.","","También tienes que matar a 8 forestales, 8 zancaminos y 8 leñadores."}},
[6134] = {"La caza de ectoplasmas", {"Reúne 8 ectoplasmas."}},
[6135] = {"Alaocaso, cómo te odio...", {"Encuentra a Alaocaso y mátalo. Recoge un parche de pelaje de Alaocaso de su cadáver y llévaselo a Nathanos Clamañublo.","","Se dice que Alaocaso vaga por el campo, al norte de la Hacienda de Marris."}},
[6136] = {"El corpulento", {"Encuentra a Borelgore en las planicies del norte de las Tierras de la Peste del Este y destrúyelo. Vuelve junto a Nathanos Clamañublo cuando hayas cumplido la misión."}},
[6141] = {"Hermano Anton", {"Habla con el hermano Anton en Desolace."}},
[6142] = {"Almejas", {"Encuentra 10 piezas de carne de almeja blanda y llévaselas a Mai'Lahii a la Aldea Cazasombras."}},
[6143] = {"Otros pescados para freír", {"Mata a 7 mirmidones Filozante, 7 nagas Filozante y 5 hechiceras Filozante y luego ve a Cazasombras, en Desolace, a hablar con Drulzegar."}},
[6144] = {"La llamada del teniente", {"Viaja a Entrañas y habla con Bragor Puñosangre."}},
[6145] = {"El mensajero carmesí", {"Vuelve a las Tierras de la Peste del Este y encuentra al mensajero carmesí. Mata al mensajero y recupera la Orden del Gran Cruzado.","","Lleva el documento a Nathanos Clamañublo y espera sus instrucciones."}},
[6146] = {"La estratagema de Nathanos", {"Viaja a Mano de Tyr, al sureste de la Hacienda de Marris. Una vez allí, da un mordisco a la manzana podrida. Entrega la Orden del Gran Cruzado al señor cruzado Valdemar con la protección de la forma de la Cruzada Escarlata."}},
[6147] = {"Regresa junto a Nathanos", {"Vuelve con Nathanos Clamañublo con la nueva información."}},
[6148] = {"El Oráculo Escarlata, Demetria", {"La Cruzada Escarlata se está moviendo. En algún lugar, a lo largo del camino que va de Mano de Tyr a Stratholme, encontrarás al Oráculo, Demetria, con su escolta. Da caza a Demetria y mátala. Vuelve junto a Nathanos Clamañublo si tienes éxito."}},
[6161] = {"La búsqueda del tesoro de Masatormento", {"Encuentra la llave de plata de Masatormento. Encuentra la llave de oro de Masatormento. Encuentra y abre el cofre de Masatormento."}},
[6162] = {"La última batalla de un marido", {"Mata al señor supremo Ror y lleva su garra a Dreka'Sur al Puesto del Veneno de Frondavil."}},
[6163] = {"Ramstein", {"Viaja a Stratholme y mata a Ramstein el Empachador. Coge su cabeza y llévasela como souvenir a Nathanos."}},
[6164] = {"Libro de entradas de Augustus", {"Consigue el libro de entradas de Augustus en la posada del Valle del Terror."}},
[6181] = {"Mensajero a toda prisa", {"Lleva la Nota de Lewis a Thor, el maestro de grifos."}},
[6182] = {"El primero y el último", {"Habla con Mathias Shaw en el Casco Antiguo, en Ventormenta. Vive en los Cuarteles."}},
[6183] = {"Honra a los muertos", {"Vuelve a hablar con Mathias Shaw si quieres aceptar esta misión."}},
[6184] = {"Flint Sombramás", {"Vete al Campamento del Orvallo en las Tierras de la Peste del Oeste y reúnete con tu contacto, Flint Sombramás."}},
[6185] = {"Las pestes del este", {"Explora las Tierras de la Peste del Este en busca de pistas sobre el \"Clamañublo\" y los agentes perdidos del IV:7. Si encuentras alguna insignia del IV:7 llévasela a Flint Sombramás en el Campamento del Orvallo."}},
[6186] = {"El regreso de Clamañublo", {"Regresa a Ventormenta e informa al rey Varian Wrynn sobre el destino de Nathanos Marris."}},
[6187] = {"Restaurar el orden", {"Reúne un ejército y viaja a las Tierras de la Peste del Este. Lanza un asalto contra Nathanos Clamañublo y cualquier miembro de la Horda que pueda intentar protegerle.","","Tienes que permanecer alerta, <nombre>. Los de la Horda defenderán al Señor forestal con su vida."}},
[6261] = {"Dungar Tragolargo", {"Lleva el cajón de Osric a Dungar Tragolargo, el maestro de grifos."}},
[6281] = {"Prosigue hasta Ventormenta", {"Cómprale al maestro de grifos Thor un vuelo en grifo y lleva la Nota de Lewis a Osric Strang, en la tienda Inmunidad Limitada, en el Casco Antiguo de Ventormenta."}},
[6282] = {"La amenaza de las arpías", {"Maggran Vinculador Terrestre, en el Refugio Roca del Sol, quiere que mates 7 arpías Furia Sangrienta, 7 emboscadoras Furia Sangrienta, 7 destripadoras Furia Sangrienta y 7 malaplumas Furia Sangrienta."}},
[6283] = {"El linaje Furia Sangrienta", {"Maggran, en el Refugio Roca del Sol, quiere que mates a la desgarradora Furia Sangrienta y le lleves sus restos como prueba de tu hazaña."}},
[6284] = {"Aracnofobia", {"Mata a Besseleth y lleva el colmillo de Besseleth a Maggran en el Refugio Roca del Sol."}},
[6285] = {"Regresa junto a Lewis", {"Compra un vuelo en grifo hasta la Colina del Centinela al maestro de grifos Dungar Tragolargo y lleva el cajón de Osric a Lewis de la Colina del Centinela."}},
[6301] = {"El ciclo del renacimiento", {"Tammra Campo de Viento, en el Refugio Roca del Sol, quiere que le consigas 10 semillas de Gaia."}},
[6321] = {"Suministros para El Sepulcro", {"Lleva el pedido de Podrig a Karos Razok."}},
[6322] = {"Michael Garrett", {"Lleva el cajón de Gordok a Michael Garrett."}},
[6323] = {"Vuela a Entrañas", {"Pídele un viaje en murciélago a Entrañas a la cuidadora de murciélagos Anette. Después, lleva el pedido de Morris a Gordon Wendham en Entrañas."}},
[6324] = {"Vuelve con Podrig", {"Compra un viaje en murciélago a El Sepulcro al maestro de murciélagos Michael Garrett. Después lleva el cajón de Gordok al Guardia de la Muerte Podrig en El Sepulcro."}},
[6341] = {"A Darnassus", {"Habla con Fidelio para comprar un vuelo a Darnassus. Después, lleva el libro de recetas de Dolanaar a la hermana Aquinne en Darnassus."}},
[6342] = {"Vuela a Auberdine", {"Consigue un hipogrifo del maestro de hipogrifos Vesprystus, viaja a Auberdine y lleva la colección de Nessa a Laird."}},
[6343] = {"Regresa junto con Nyoma", {"Habla con Leora para alquilar un hipogrifo y regresar a Dolanaar. Cuando llegues, entrégale la nota de la hermana Aquinne a Nyoma."}},
[6344] = {"Nessa Cantosombrío", {"Habla con Nessa Cantosombrío."}},
[6361] = {"Un fardo de pellejos", {"Llévale el fardo de pellejos al maestro de jinetes del viento Tak en el Poblado Pezuña de Sangre."}},
[6362] = {"Un viaje a Cima del Trueno", {"Cómprale un trayecto en jinete del viento hasta Cima del Trueno al maestro de jinetes del viento Tak y llévale entonces el fardo de pellejos a Ahanu en Cima del Trueno."}},
[6363] = {"Tal, maestro de jinetes del viento", {"Lleva los artículos de cuero de Ahanu a Tal en Cima del Trueno."}},
[6364] = {"Volver junto a Jahan", {"Cómprale un jinete del viento para El Cruce al maestro de jinetes del viento Tal y llévale entonces los artículos de piel de Ahanu a Jahan Alalcón."}},
[6365] = {"Entrega de carne a Orgrimmar", {"Llévale la carne de Grimtak a Burok en Cerrotajo."}},
[6381] = {"Nueva vida", {"Planta 10 semillas de Gaia en los Túmulos y lleva las semillas de Gaia encantadas restantes a Tammra en el Refugio Roca del Sol."}},
[6382] = {"La Caza de Vallefresno", {"Habla con Senani Corazón Atronador en Puesto del Hachazo, en Vallefresno."}},
[6383] = {"La Caza de Vallefresno", nil},
[6384] = {"Un viaje a Orgrimmar", {"Cómprale un jinete del viento al maestro de jinetes del viento Burok y llévale entonces la carne de Grimtak a Gryshka en Orgrimmar."}},
[6385] = {"Doras, maestro de jinetes del viento", {"Llévale la carta de Gryshka a Doras en Orgrimmar."}},
[6386] = {"El regreso a El Cruce", {"Cómprale un jinete del viento para El Cruce al maestro de jinetes del viento Doras y llévale entonces la carta de Gryshka a Zargh en El Cruce."}},
[6387] = {"Estudiantes de honor", {"Lleva la lista de Gremlock a Brolan Barbaviento a Kharanos."}},
[6388] = {"Gryth Thurden", {"Lleva los picos honorarios a Gryth Thurden a Forjaz."}},
[6389] = {"Una Peste en la Cruzada", {"Libera las termitas de las Tierras de la Peste en el Aserradero Crestanorte y luego vuelve con la barrica de termitas de las Tierras de la Peste a Nathaniel Dumah en el Campamento del Orvallo en las Tierras de la Peste del Oeste."}},
[6390] = {"Una Peste en la Cruzada", {"Libera las termitas de las Tierras de la Peste en el Aserradero Crestanorte y luego vuelve con la barrica de termitas de las Tierras de la Peste a Mickey Levine en El Baluarte en los Claros de Tirisfal."}},
[6391] = {"Vuela a Forjaz", {"Contrata un vuelo en grifo a Forjaz con el maestro de grifos Brolan Barbaviento y lleva la lista de Gremlock a Golnir Dedorroca, en Forjaz."}},
[6392] = {"Regresa junto a Gremlock", {"Contrata un vuelo en grifo a Kharanos con el maestro de grifos Gryth Thurden para llevar los picos honorarios a Gremlock Pilsnor en Kharanos."}},
[6393] = {"Guerra elemental", {"Lleva 10 incendritas a Tsunaman en el Refugio Roca del Sol."}},
[6394] = {"Pico de Thazz'ril", {"Lleva el pico de Thazz'ril al supervisor Thazz'ril."}},
[6395] = {"El último deseo de Marla", {"Lleva los restos de Samuel Fipps a la tumba de Marla y luego vuelve con la novicia Elreth."}},
[6401] = {"Kaya está viva", {"Da las buenas noticias a Tammra Campo de Viento en el Refugio Roca del Sol."}},
[6402] = {"Tienes una cita en Ventormenta", {"Viaja hasta la Ciudad de Ventormenta y aventúrate tras las puertas de la ciudad. Habla con el escudero Rowe para que haga saber al mariscal Windsor sobre tu llegada."}},
[6403] = {"La gran farsa", {"Sigue a Reginald Windsor por Ventormenta. ¡Protégele del peligro!"}},
[6421] = {"Barranco del Alud", {"Explora las profundidades de la cueva del Barranco del Alud y lleva 10 cristales de resonita al Refugio Roca del Sol para que Mor'rogal las estudie."}},
[6441] = {"Los cuernos de sátiro", {"Reúne 16 cuernos de sátiro para Pixie en el Puesto del Hachazo."}},
[6442] = {"Nagas en la Ensenada de Zoram", {"Llévale 20 cabezas de Colafuria a Marukai en La Ensenada de Zoram."}},
[6461] = {"Chupasangres", {"Xen'zilla, en Malaka'Jin, necesita que mates a 10 trepadores Musgondo y a 7 escupevenenos Musgondo."}},
[6462] = {"El talismán trol", {"Llévale 8 talismanes trols a Mitsuwa en la Avanzada Grito Infernal."}},
[6481] = {"El despertar del terráneo", {"Abre el barril de resonita con el cristal de resonita encantado y, a continuación, mata a Goggeroc. Vuelve a ver a Mor'rogal para contarle lo ocurrido y entregarle el cristal de resonita encantado."}},
[6482] = {"Liberar a Ruul", {"Escolta a Ruul y después habla con Yama Pezuña Nevada en el Puesto del Hachazo."}},
[6501] = {"El Ojo del Dragón", {"Debes buscar por todo el mundo y encontrar un ser capaz de restaurar el poder del fragmento del Ojo del Dragón. La única información que tienes sobre dicho ser es que existe."}},
[6502] = {"Amuleto Pirodraco", {"Tienes que recuperar la sangre de dragón Negro Campeón, la tiene el general Drakkisath. Puedes encontrar a Drakkisath en su sala del trono, tras las Salas de la Ascensión, en la Cumbre de Roca Negra."}},
[6503] = {"Avanzada de Vallefresno", {"Mata a 9 avanzadas de Vallefresno."}},
[6504] = {"Las páginas perdidas", {"Encuentra las 12 páginas que faltan del manual de instrucciones de trituradora y vuelve a componer con ellas los 3 primeros capítulos. Devuélvele las páginas a Gurda Cicafuria cerca del Puesto del Hachazo."}},
[6521] = {"Una alianza impía", {"Lleva la cabeza del embajador Malcin a Bragor Puñosangre, que está en Entrañas."}},
[6522] = {"Una alianza impía", {"Lleva el pergamino pequeño a Bragor Puñosangre que está en el Barrio Real en Entrañas."}},
[6523] = {"Protege a Kaya", {"Escolta a Kaya Pezuña Plana hasta el Campamento Aparaje y ve a ver a Makaba Pezuña Plana cerca del límite sureste de Espolón."}},
[6541] = {"Preséntate ante Kadrak", {"Preséntate ante Kadrak en la torre de vigilancia en Los Baldíos del Norte."}},
[6542] = {"Preséntate ante Kadrak", {"Preséntate ante Kadrak en la torre de vigilancia en Los Baldíos del Norte."}},
[6543] = {"Los informes Grito de Guerra", {"Abre el fardo de informes. Lleva los informes Grito de Guerra al explorador Grito de Guerra, al corredor Grito de Guerra y al escolta Grito de Guerra. Preséntate ante Kadrak en la torre de vigilancia norte en los Baldíos con la información que te hayan dado."}},
[6544] = {"El asalto de Torek", {"Escolta a Torek en su ataque sobre la Avanzada Ala de Plata contra Duriel Fuegolunar e informa después a Ertog Colmillorrabioso en el Puesto del Hachazo."}},
[6545] = {"Novedades de corredor Grito de Guerra", nil},
[6546] = {"Novedades de escolta Grito de Guerra", nil},
[6547] = {"Novedades de explorador Grito de Guerra", nil},
[6548] = {"Venga mi aldea", {"Mata a 8 rufianes Tótem Siniestro y a 6 mercenarios Tótem Siniestro. A continuación, ve a ver a Makaba Pezuña Plana cerca del límite sureste de Espolón."}},
[6561] = {"La vileza de Brazanegra", {"Llévale la cabeza del señor crepuscular Kelris a Bashana Tótem de Runa en Cima del Trueno."}},
[6562] = {"Problemas en las profundidades", {"Habla con Je'neu Sancrea en Vallefresno."}},
[6563] = {"La esencia de Aku'Mai", {"Llévale 20 zafiros de Aku'Mai a Je'neu Sancrea en Vallefresno."}},
[6564] = {"Lealtad a los dioses antiguos", {"Llévale la nota mojada a Je'neu Sancrea en Vallefresno."}},
[6565] = {"Lealtad a los dioses antiguos", {"Mata a Lorgus Jett."}},
[6566] = {"Lo que trae el viento", {"Escucha a Thrall."}},
[6567] = {"El Campeón de la Horda", {"Busca a Rokaro en la Aldea Cazasombras, en Desolace."}},
[6568] = {"Profesora del engaño", {"Entrega la carta de Rokaro a Myranda la Fada en las Tierras de la Peste del Oeste."}},
[6569] = {"Ilusiones oculares", {"Viaja a la Cumbre de Roca Negra y recoge 20 ojos de dragauro negro. Cuando hayas terminado tu tarea regresa con Myranda la Fada."}},
[6570] = {"Brasaliza", {"Viaja a la Ciénaga de Fuego del Marjal Revolcafango y busca El Cubil de Brasaliza. Cuando estés dentro ponte el Amuleto de Subversión Dracónica y habla con Brasaliza."}},
[6571] = {"Suministros Grito de Guerra", {"Reúne los suministros Grito de Guerra: las espadas dentadas Grito de Guerra, cuerda, aceite Grito de Guerra y el envío de hachas de los Grito de Guerra para Locke Okarr en el Puesto del Hachazo."}},
[6581] = {"Espadas dentadas Grito de Guerra", nil},
[6582] = {"La prueba de los cráneos, Arúspice", {"Debes encontrar a Arúspice, el Campeón draco del Vuelo Azul y matarlo. Separa su cráneo de su cuerpo y llévaselo a Brasaliza.","","Sabes que puedes encontrar a Arúspice en Cuna del Invierno."}},
[6583] = {"La prueba de los cráneos, Somnus", {"Destruye al Campeón del Vuelo Verde, Somnus. Lleva su cráneo a Brasaliza."}},
[6584] = {"La prueba de los cráneos, Chronalis", {"Chronalis, hijo de Nozdormu, custodia las Cavernas del Tiempo en el Desierto de Tanaris. Destrúyelo y lleva su cráneo a Brasaliza."}},
[6585] = {"La prueba de los cráneos, Axtroz", {"Viaja a Grim Batol y encuentra a Axtroz, el Campeón del Vuelo Rojo. Destrúyelo y hazte con su cráneo. Llévaselo a Brasaliza."}},
[6601] = {"El ascenso", {"Diría que se acabaron las charadas. Ya sabes que el amuleto de Subversión Dracónica que Myranda la Fada creó para ti no funcionará en el interior de la Cumbre de Roca Negra. Quizás deberías buscar a Rokaro y explicarle el apuro en el que te encuentras. Enséñale el amuleto Pirodraco apagado. Con un poco de suerte, él sabrá que hay que hacer ahora."}},
[6602] = {"La sangre de dragón Negro Campeón", {"Viaja a la Cumbre de Roca Negra y mata al general Drakkisath. Recoge su sangre y llévasela a Rokaro."}},
[6603] = {"Problemas en Cuna del Invierno", {"Encuentra a Donova Cubilnevado cerca de las fuentes termales de Cuna del Invierno."}},
[6604] = {"Lechúcico salvaje iracundo", {"Habla con Jaron Tallapiedras en Aldea Estrella Fugaz."}},
[6605] = {"Algo extraño", {"Habla con Winna Riessgo en Frondavil."}},
[6606] = {"Un poco de suerte", {"Habla con la médica bruja Mau'ari en Vista Eterna."}},
[6607] = {"Nat Pagle, pescador extremo", {"Nat Pagle quiere que pesques los siguientes peces:","","Mahi mahi juncobruma de la Playa Juncobruma del Pantano de las Penas.","","1 artillero Sar'theris de la Playa de Sar'theris de Desolace.","","1 Ahi de Feralas del Río Verdantis de Feralas.","","Latipinia azul de La Costa Salvaje de Vega de Tuercespina.","","Cuando los tengas todos, vuelve a buscar a Nat Pagle."}},
[6608] = {"¡Qué bueno eres!", {"Parece que Lumak piensa que ya no puede enseñarte nada más sobre la pesca. Ve a buscar a su amigo, Nat Pagle, un humano pescador que vive en una isla al sur de Theramore"}},
[6609] = {"¡Me has dejado seco!", {"Ve a Kalimdor, a la ciudad costera de Theramore. Busca una isla hacia el sur. ¡Nat Pagle te espera!"}},
[6610] = {"Sorpresa de almejate", {"Dirge Hojágil quiere que le consigas lo siguiente:","","10 huevos gigantes. Pueden ser huevos de los rocs que deambulan por Tanaris o de cualquier otro pájaro de grandes dimensiones.","","10 piezas de carne de almeja sabrosa. ¡Esta la podrás obtener de las almejas, por supuesto!","","20 piezas de queso cheddar curado bueno. ¡Podrás encontrarlo en cualquier quesería!","","Consigue todo lo que Dirge necesita y llévaselo."}},
[6611] = {"Ve a Gadgetzan", {"Ve a Gadgetzan, en el Desierto de Tanaris, y habla con Dirge Hojágil sobre tus habilidades culinarias."}},
[6612] = {"Conozco a un tío...", {"Ve a Gadgetzan, en el Desierto de Tanaris, y habla con Dirge Hojágil sobre tus habilidades culinarias."}},
[6621] = {"El rey de los Maderiza", {"Coloca el estandarte de Senani en el montículo del tótem de los Maderiza. No permitas que los fúrbolgs destruyan el estandarte. Derrota al jefe Murgut y lleva el tótem de Murgut a Senani en el Refugio Brisa de Plata."}},
[6622] = {"La selección", {"Salva a pacientes asignando vendas identificativas para atender sus heridas por orden de gravedad. Debes salvar a 15 pacientes antes de que 6 mueran a consecuencia de sus heridas.","","¡Ten presente el orden de prioridad! Los soldados gravemente heridos mueren antes que los soldados con graves heridas. Los soldados malheridos son los que más tardan en morir y solo hay que salvarlos DESPUÉS de identificar y atender a los soldados gravemente heridos y a los soldados con graves heridas."}},
[6623] = {"Dispensario de la Horda", {"Ve a Sentencia, en las Tierras Altas de Arathi, y habla con el doctor Gregory Victor sobre tu incorporación al Dispensario de la Horda."}},
[6624] = {"Orden de gravedad", {"Salva a pacientes asignando vendas identificativas para atender sus heridas por orden de gravedad. Debes salvar a 15 pacientes antes de que 6 mueran a consecuencia de sus heridas.","","¡Ten presente el orden de prioridad! Los soldados con heridas graves mueren antes que los soldados con heridas de gravedad media. Los soldados heridos leves son los que más tardan en morir y solo hay que salvarlos DESPUÉS de identificar y atender a los soldados con heridas graves y medias."}},
