[6626] = {"Un anfitrión del mal", {"Mata a 8 guardias de batalla de Rajacieno y 8 tejespinas Rajacieno y 8 cultores Caramuerte y ve a ver a Myriam Lunacanta cerca de la entrada a Zahúrda Rajacieno."}},
[6627] = {"Prueba de conocimiento", {"Responde la pregunta de Braug Espíritu Tenue con acierto y después habla con él de nuevo. Se quedará en Sierra Espolón hasta que estés <listo/lista>."}},
[6628] = {"Prueba de conocimiento", {"Responde la pregunta de Parqual Fintallas con acierto y después habla con él de nuevo. Se quedará en Entrañas hasta que estés <listo/lista>."}},
