[7081] = {"Los cementerios del Valle de Alterac", {"Asalta un cementerio y vuelve con el sargento Durgen Pico Tormenta en las Montañas de Alterac."}},
[7082] = {"Los cementerios de Alterac", {"Asalta un cementerio y vuelve con el cabo Teeka Gruñido Sangriento en las Montañas de Alterac."}},
[7101] = {"Las torres y los búnkeres", {"Captura una torre enemiga y vuelve con el cabo Teeka Gruñido Sangriento en las Montañas de Alterac."}},
