[7123] = {"Habla con nuestro intendente", {"Habla con el intendente de Lobo Gélido."}},
[7124] = {"Capturar una mina", {"Captura una mina y vuelve con el cabo Teeka Gruñido Sangriento en las Montañas de Alterac."}},
[7141] = {"La batalla de Alterac", {"Adéntrate en el Valle de Alterac, derrota al general Drek'thar de la Horda y vuelve junto a la prospectora Tallapiedra en las Montañas de Alterac."}},
[7142] = {"La batalla por Alterac", {"Adéntrate en el Valle de Alterac y derrota al general enano Vanndar Pico Tormenta. Vuelve entonces junto a Voggah Agarre Letal en las Montañas de Alterac."}},
[7161] = {"Terreno de Pruebas", {"Viaja hasta la Caverna Zarpa Salvaje ubicada al sureste del campamento base en el Valle de Alterac y encuentra el estandarte Lobo Gélido. Devuélvele el estandarte al maestro de guerra Laggrond."}},
[7162] = {"Terreno de Pruebas", {"Viaja hasta la cueva Ala Gélida ubicada al suroeste de Dun Baldar en el Valle de Alterac y recupera el estandarte Pico Tormenta. Devuélveselo al teniente Haggerdin en las Montañas de Alterac."}},
