[7201] = {"El último elemento", {"Viaja a las Profundidades de Roca Negra y recupera 10 esencias de los elementos. Tu primer impulso es buscar los gólems y a los creadores de gólems. Recuerdas que Vivian Lagrave también murmuró entre dientes algo sobre los elementales."}},
[7202] = {"Korrak el Sanguinario", {"Según cuenta la leyenda, el jefe de los poderosos trols Hacha Invernal parece dispuesto a sembrar el caos entre los habitantes del Valle de Alterac.","","Si Korrak se digna aparecer, destrúyelo y vuelve con el teniente Haggerdin en las Montañas de Alterac."}},
