[7441] = {"Pusillín y el ancestro Azj'Tordin", {"Viaja a La Masacre y encuentra al diablillo Pusillín. Convence a Pusillín de que te dé el libro de Conjuros de Azj'Tordin, por cualquier medio.","","Si consigues hacerte con el libro de Conjuros, vuelve al Pabellón de Lariss de Feralas y busca a Azj'Tordin."}},
[7461] = {"Locura interior", {"Debes destruir a los guardianes que rodean las 5 torres que controlan la Prisión de Immol'thar. Una vez desactivadas las torres, el campo de fuerza que rodea a Immol'thar se disipará.","","Entra en la Prisión de Immol'thar y erradica al demonio que hace guardia en su interior. Por último, haz frente al príncipe Tortheldrin en El Athenaeum.","","Si consigues completar esta misión, ve al patio a buscar a la ancestro Shen'dralar."}},
[7462] = {"El tesoro de los Shen'dralar", {"Vuelve a El Athenaeum y encuentra el tesoro de los Shen'dralar. ¡Reclama tu recompensa!"}},
[7463] = {"El refresco arcano", {"Viaja al Barrio Alabeo de La Masacre y mata al elemental de agua, Hidromilecio. Lleva la esencia de Hidromilecio al Tradicionalista Lydros que está en El Athenaeum."}},
[7481] = {"Leyendas élficas", {"Busca a Kariel Winthalus en La Masacre. Vuelve al Campamento Mojache e informa al Sabio Korolusk de cualquier cosa que encuentres."}},
[7482] = {"Leyendas élficas", {"Busca a Kariel Winthalus en La Masacre. Vuelve al Bastión Plumaluna a informar al erudita Runaespina de lo que hayas encontrado."}},
[7483] = {"El tratado sobre rapidez", {"Lleva 1 tratado sobre rapidez, 1 diamante negro prístino, 2 fragmentos luminosos grandes y 2 sangres de héroes al Tradicionalista Lydros a La Masacre para conseguir un arcanum de rapidez."}},
[7484] = {"El tratado sobre enfoque", {"Lleva 1 tratado sobre enfoque, 1 diamante negro prístino, 4 fragmentos luminosos grandes y 2 pieles de Sombra al Tradicionalista Lydros a La Masacre para conseguir un arcanum de enfoque."}},
[7485] = {"El tratado sobre protección", {"Lleva 1 tratado sobre protección, 1 diamante negro prístino, 2 fragmentos luminosos grandes y 1 costura desgarrada de abominación al Tradicionalista Lydros a La Masacre para conseguir un arcanum de protección."}},
[7486] = {"Una recompensa de héroe", {"Recoge tu recompensa en el arca de Hydraxis."}},
[7488] = {"La membrana de Lethtendris", {"Lleva la Membrana de Lethtendris a Latronicus Lanzaluna al Bastión Plumaluna de Feralas."}},
[7489] = {"La membrana de Lethtendris", {"Lleva la Membrana de Lethtendris a Talo Pezuñahendida al Campamento Mojache de Feralas."}},
[7490] = {"Victoria para la Horda", {"Lleva la cabeza de Onyxia a Garrosh a Orgrimmar."}},
[7491] = {"Para que todos lo vean", {"Busca al señor supremo Runthak en el Valle de la Fuerza."}},
[7492] = {"Campamento Mojache", {"Ve al Campamento Mojache de Feralas y habla con Talo Pezuñahendida."}},
[7493] = {"El viaje acaba de empezar", nil},
[7494] = {"Bastión Plumaluna", {"Habla con Latronicus Lanzaluna. Lo encontrarás en el Bastión Plumaluna de Feralas."}},
[7495] = {"Victoria para la Alianza", {"Lleva la cabeza de Onyxia al rey Varian Wrynn en Ventormenta."}},
[7496] = {"Celebrar los buenos momentos", {"Busca al mayor Mattingly en el Valle de los Héroes."}},
[7497] = {"El viaje acaba de empezar", nil},
[7498] = {"Garona: Un Estudio sobre el Sigilo y la Traición", {"Devuelve el libro a sus legítimos dueños."}},
[7499] = {"Códice de Defensa", {"Devuelve el libro a sus legítimos dueños."}},
[7500] = {"El libro de cocina del Arcanista", {"Devuelve el libro a sus legítimos dueños."}},
[7501] = {"La Luz y cómo alterarla", {"Devuelve el libro a sus legítimos dueños."}},
[7502] = {"Sombras acechadoras", {"Devuelve el libro a sus legítimos dueños."}},
[7503] = {"La mejor raza de cazadores", {"Devuelve el libro a sus legítimos dueños."}},
[7504] = {"Sagrada Bologna: lo que la Luz nunca te dirá", {"Devuelve el libro a sus legítimos dueños."}},
[7505] = {"El choque de Escarcha y tú", {"Devuelve el libro a sus legítimos dueños."}},
[7506] = {"El Sueño Esmeralda", {"Devuelve el libro a sus legítimos dueños."}},
[7507] = {"Compendio de Foror", {"Devuelve el compendio de matar dragones de Foror a El Athenaeum."}},
[7508] = {"Forjar Quel'Serrar", {"Entrega la hoja élfica roma Tradicionalista Lydros."}},
[7509] = {"Forjar Quel'Serrar", {"Debes conseguir que Onyxia escupa fuego sobre la hoja antigua sin templar. Una vez hecho, recógela, su hoja estará candente. Pero ten cuidado: una hoja candente no permanecerá así para siempre, no tienes tiempo que perder.","","Antes de volver a mí, tienes que terminar lo empezado, debes matar a la bestia e introducir la hoja candente en su cadáver.","","Hazlo y Quel'Serrar será tuya."}},
[7541] = {"Un servicio para la Horda", nil},
[7562] = {"Mor'zul Sangredoble", {"Habla con Mor'zul Sangredoble en el Altar de la Tempestad en Las Estepas Ardientes."}},
[7563] = {"La ira de sangre", {"Llévale 30 botellas de sangre de bestia embravecida a Mor'zul Sangredoble en Las Estepas Ardientes."}},
[7564] = {"Ojovago", {"Llévale el estuche de sangre a Gorzeeki Ojovago al Altar de la Tempestad, en Las Estepas Ardientes."}},
[7581] = {"Las selladuras de la prisión", {"Viaja a La Masacre en Feralas y consigue 15 muestras de sangre de sátiro del sátiro Mala Hierba que habita en el Barrio Alabeo. Cuando hayas acabado, ve a ver a Daio a la Escara Impía."}},
[7582] = {"El revestimiento de la prisión", {"Viaja a la Garganta Negro Rumor en Cuna del Invierno y recoge 5 Lágrimas de los Hederine de los demonios Hederine que ocupan la garganta. Cuando hayas cumplido tu tarea, ve a ver a Daio a la Escara Impía."}},
[7583] = {"Supresión", {"Aventúrate en la Escara Impía y localiza a un comandante Guardia apocalíptico.","","Utiliza la prisión de cristal resplandeciente para atrapar al comandante Guardia apocalíptico. Prepárate para una sucesión de ataques pues el demonio intentará escapar.","","Si tienes éxito, llévale el Guardia apocalíptico encarcelado a Daio, en la Escara Impía."}},
[7601] = {"La orden de Niby", {"Habla con Diblis en Frondavil."}},
[7602] = {"Esencia de energía vil pura", {"Diblis de Frondavil te ha pedido que le lleves 3 esencias viles impecables que provengan de 3 lugares distintos.","","Los sátiros Legashi de Azshara tienen la esencia vil impecable de su región. Los Legionarios Jaedenar de Jaedenar tienen la esencia vil impecable de su región. Los guardias viles de Las Tierras Devastadas tienen la esencia vil impecable de su región.","","Reúne las esencias viles impecables y vuelve con Diblis a Frondavil."}},
[7603] = {"El núcleo infernal de Kroshius", {"Busca los restos de Kroshius en la Cañada Gran Cicatriz de Frondavil. Cuando localices sus restos, utiliza el fuego vil cerca de ellos y espera el regreso de Kroshius. Cuando el infernal se haya despertado, acaba con él y extrae de su cuerpo el núcleo infernal de Kroshius.","","Lleva el núcleo infernal de Kroshius a Niby el Todopoderoso a Frondavil."}},
[7604] = {"Un contrato vinculante", {"Entrégale el contrato de La Hermandad del Torio a Lokhtos Tratoscuro si quieres recibir los planes de Sulfuron."}},
[7621] = {"Un aviso", nil},
[7622] = {"Equilibrio de Luz y Sombras", {"Salva a 50 campesinos antes de que 15 sean asesinados. Habla con Eris Feleste si tienes éxito.","","Puedes ver el Poste de la muerte para ver cuántos campesinos han sido asesinados."}},
[7623] = {"Lord Pesadilla", {"Cómprale pociones enigmáticas a Gorzeeki Ojovago en el Altar de la Tempestad en Las Estepas Ardientes.","","Usa las pociones para viajar por Jaedenar en Frondavil y habla con Lord Pesadilla en el interior de la Guarida Sombría."}},
[7624] = {"Ulathek el Traidor", {"Enfréntate a Ulathek y llévale el corazón del traidor a Lord Pesadilla en Jaedenar."}},
[7625] = {"Polvo estelar xorothiano", {"Cómprale polvo estelar xorothiano a Ur'dan en el interior de la Guarida Sombría en Jaedenar, en Frondavil. Llévaselo a Gorzeeki Ojovago en Las Estepas Ardientes."}},
[7626] = {"La Campana de Dethmoora", {"Llévale 2 elixires de poder de las sombras a Gorzeeki Ojovago en Las Estepas Ardientes."}},
[7627] = {"Rueda de la Marcha Negra", {"Llévale 6 fragmentos luminosos grandes y 25 minerales de hierro negro a Gorzeeki Ojosalvajes en Las Estepas Ardientes."}},
[7628] = {"La Vela del Apocalipsis", {"Lleva 3 dragontinas negras a Gorzeeki Ojovago a Las Estepas Ardientes."}},
[7629] = {"Entrega de diablillo", {"Llévale el diablillo en un tarro al laboratorio de alquimia de Scholomance. Después de crear el papiro llévale el tarro a Gorzeeki Ojovago."}},
[7630] = {"La arcanita", {"Lleva una barra de arcanita a Gorzeeki Ojosalvajes a Las Estepas Ardientes."}},
[7631] = {"Corcel nefasto xorothiano", {"Lee las instrucciones de Mor'zul. Invoca a un corcel nefasto xorothiano, derrótalo y después vincula su espíritu al tuyo."}},
[7632] = {"La hoja antigua", {"Encuentra al dueño de la hoja petrificada vieja. Buena suerte, <nombre>; este es un mundo enorme..."}},
[7633] = {"Una presentación", nil},
[7634] = {"Carcaj antiguo cosido con tendón", {"Hastat el anciano te ha pedido que le lleves 1 tendón de dragón Azul maduro. Si lo encuentras, llévaselo a Hastat a Frondavil."}},
[7635] = {"La cuerda adecuada", {"Estoma el Anciano te ha pedido que le lleves 1 tendón de dragón Negro maduro. Si lo encontraras, llévaselo a Estoma a Frondavil."}},
[7636] = {"El báculo de los Ancestros", {"Debes encontrar y destruir a estos 4 corruptores demoníacos:","","Simone la Seductora.","","Klinfran el Enloquecido.","","Solenor el Destripador.","","Artorius el Fatídico.","","Destruye a estas criaturas, vuelve a Frondavil y entrega sus cabezas a Vartrus el Ancestro.","","Busca pistas de su paradero en la corteza petrificada.","","DEBES completar esta misión tú <solo/sola>."}},
[7637] = {"Énfasis en el sacrificio", {"Viaja a Forjaz y consigue el incensario de exorcismos del sumo sacerdote Rohan. Tendrás que hacer una donación de 150 monedas de oro para conseguirlo."}},
[7638] = {"Lord Grisillo Quiebrasombras", {"Habla con Lord Grisillo Quiebrasombras en el Distrito de la Catedral de Ventormenta."}},
[7639] = {"Mostrarse juicioso", {"Devuelve el incensario de exorcismos a Lord Grisillo Quiebrasombras en el Distrito de la Catedral de Ventormenta."}},
[7640] = {"Exorcismo en Valle del Terror", {"Utiliza el incensario de exorcismos para expulsar los espíritus que atormentan el Valle del Terror. Cuando hayas matado 25 espíritus del Valle del Terror, vuelve a ver a Lord Grisillo Quiebrasombras en el Distrito de la Catedral de Ventormenta."}},
[7641] = {"El trabajo de Grimand Elmore", {"Habla con Grimand Elmore en el Distrito de los Enanos, en Ventormenta."}},
[7642] = {"Recopilación de artículos", {"Lleva 40 paños rúnicos, 6 barras de arcanita, 10 lágrimas de Arthas, 5 viales de agua sagrada de Stratholme y 150 monedas de oro a Grimand Elmore en el Distrito de los Enanos de Ventormenta."}},
[7643] = {"El antiguo espíritu equino", {"Consigue comida para caballos para alimentar a un espíritu equino. Por lo visto, Merideth Carlson, en Costasur, tiene esa comida.","","Ve a la mazmorra de La Masacre, en Feralas y mata a Tendris Alabeo. Al hacerlo, liberarás al antiguo espíritu equino. Dale la comida para caballos y lo aplacarás. Por último, dale la gualdrapa de arcanita para que la bendiga."}},
[7644] = {"La gualdrapa de arcanita bendita", {"Devuelve la gualdrapa de arcanita bendita a Lord Grisillo Quiebrasombras en el Distrito de la Catedral de Ventormenta."}},
[7645] = {"Alimento para caballos enriquecido con maná", {"Consigue 20 galletas enriquecidas con maná, ingrediente principal del alimento especial para caballos, y llévaselas a Merideth Carlson a las Laderas de Trabalomas, en Costasur. Solo El Alba Argenta fabrica esas galletas.","","También tienes que darle 50 piezas de oro para aplacar su orgullo herido."}},
[7646] = {"El cristal de adivinación", {"Lleva un diamante de Azeroth y un diamante negro prístino a Lord Grisillo Quiebrasombras en el Distrito de la Catedral de Ventormenta."}},
[7647] = {"Juzgar y redimir", {"Utiliza el cristal de adivinación en el centro del sótano de El Gran Osario en Scholomance. Al hacerlo, aparecerán los espíritus que tienes que juzgar. Si derrotas a esos espíritus, aparecerá el Caballero de la Muerte Atracoscuro. Acaba con él y reclama el alma perdida del destrero caído.","","Entrega el alma redimida del destrero y la gualdrapa encantada bendecida al destrero caído de Atracoscuro."}},
[7648] = {"Un trabajo bien hecho", {"Lleva la gualdrapa de arcanita a Lord Grisillo Quiebrasombras en el Distrito de la Catedral de Ventormenta para que la inspeccione."}},
[7649] = {"Las mallas de placas en torio encantado: volumen I", {"Devuelve el libro a sus legítimos dueños."}},
[7650] = {"Las mallas de placas en torio encantado: volumen II", {"Devuelve el libro a sus legítimos dueños."}},
[7651] = {"Las mallas de placas en torio encantado: volumen III", {"Devuelve el libro a sus legítimos dueños."}},
