[7815] = {"¡Quijafortes, colega!", {"Katoom el Pescador, del Poblado Sañadiente en las Tierras del Interior, quiere que mates 10 quijafortes marinos. Ve a verlo cuando hayas terminado."}},
[7816] = {"¡Gammerita, colega!", {"Katoom el Pescador, del Poblado Sañadiente en las Tierras del Interior, quiere que mates a Gammerita y que le saques el cebo del estómago.","","Dijo que Gammerita está en la costa con las otras tortugas."}},
