[7828] = {"Acechar a los acechadores", {"El montero Markhor, del Poblado Sañadiente en las Tierras del Interior, quiere que mates 5 acechadores melenargenta y 5 aulladores melenargenta. Vuelve a verlo cuando hayas terminado.","","Dijo que los lobos se ocultan entre la maleza en las Tierras del Interior."}},
[7829] = {"Cazar a los salvajes", {"El montero Markhor, del Poblado Sañadiente en las Tierras del Interior, quiere que mates 10 lechubestias salvajes. Vuelve a verlo cuando hayas terminado.","","Dijo que viven por todas las Tierras del Interior."}},
[7830] = {"Vengar a los Caídos", {"El montero Markhor, del Poblado Sañadiente en las Tierras del Interior, quiere que mates a un Señor del Cielo y le lleves la péndola.","","Dijo que son una raza poco común que se extiende por toda la región."}},
