[7839] = {"Los vándalos de Vilrama", {"El herrero Esco de Poblado Sañadiente, en las Tierras del Interior, quiere que encuentres y le lleves sus herramientas perdidas.","","Dijo que las herramientas pueden estar en uno de los templos Vilrama en la zona noreste de las Tierras del Interior. Mira también en Roca Oculta."}},
[7840] = {"Lard perdió su almuerzo", {"Lard, del Poblado Sañadiente en las Tierras del Interior, quiere que vayas a buscar su almuerzo. Llévaselo cuando lo encuentres.","","Dijo que se lo dejó en la isla del norte. Ten cuidado con los trols Vilrama."}},
[7841] = {"Un mensaje para los Martillo Salvaje", {"Otho Moji'ko del Poblado Sañadiente, en las Tierras del Interior, quiere que mates a 8 exploradores Vallealto, 5 avanzadas Vallealto, 5 forestales Vallealto y 2 tiradores Vallealto. Vuelve a verlo cuando hayas terminado.","","Los elfos nobles Vallealto están en la Avanzada Quel'Danil, en la zona noroeste de las Tierras del Interior."}},
[7842] = {"Un nuevo mensaje para los Martillo Salvaje", {"Otho Moji'ko del Poblado Sañadiente, en las Tierras del Interior, quiere que le lleves 1 pluma elegante larga de los grifos de las Tierras del Interior. Vuelve a verlo cuando hayas terminado.","","Los grifos habitan en todas las Tierras del Interior."}},
[7843] = {"Un mensaje final para los Martillo Salvaje", {"Otho Moji'ko del Poblado Sañadiente, en las Tierras del Interior, quiere que vayas a Pico Nidal, al oeste de la región, y coloques el mensaje final junto al pozo del centro del pueblo. Vuelve a verlo cuando hayas terminado.","","Ten cuidado con los belicosos enanos Martillo Salvaje y los miembros indisciplinados de la Alianza."}},
[7844] = {"Unos primos caníbales", {"La mística Yayo'jin del Poblado Sañadiente, en las Tierras del Interior, quiere que mates a 6 arrancacabelleras y a 2 veritas Vilrama. Vuelve a verla cuando hayas terminado.","","Dijo que estos trols suelen estar cerca de los templos de Shaol'watha y Agol'watha, en la zona noreste de las Tierras del Interior."}},
[7845] = {"El secuestro del anciano Colmillopartido", {"Primigenia Colmillopartido, del Poblado Sañadiente en las Tierras del Interior, quieres que rescates a su compañero, el anciano Colmillopartido, que está en Jintha'alor.","","Está prisionero en la cima de Jintha'alor, la capital Vilrama al sur de las Tierras del Interior."}},
[7846] = {"¡Recupera la llave!", {"El anciano Colmillopartido de Jintha'alor quiere que mates a Hitah'ya la Guardiana para quitarle la llave de los grilletes. Vuelve a verlo cuando hayas conseguido la llave."}},
[7847] = {"Regresa junto a Primigenia Colmillopartido", {"El anciano Colmillopartido de Jintha'alor quiere que informes de su rescate a Primigenia Colmillopartido en el Poblado Sañadiente."}},
[7848] = {"Armonización con el Núcleo", {"Acércate al portal de entrada del Núcleo de Magma en las Profundidades de Roca Negra y recoge un trozo del Núcleo. Llévaselo a Lothos Levantagrietas a la Montaña Roca Negra."}},
[7849] = {"Una separación angustiosa", {"El montero Markhor de Poblado Sañadiente, en las Tierras del Interior, quiere que le lleves los restos de su hermano gemelo. Llévale la calavera y los huesos de Malkhor.","","Dijo que los Vilrama habían arrojado los restos de su hermano a los mocos y los lobos. También dijo que hay una fosa llena de mocos en Jintha'alor, además de una guarida de lobos, ambas cerca de la parte alta del templo."}},
[7850] = {"Vasijas oscuras", {"Primigenia Colmillopartido, del Poblado Sañadiente en las Tierras del Interior, quiere que recojas 5 vasijas de sangre corrupta en Jintha'alor. Vuelve a verla cuando hayas terminado la tarea."}},
[7861] = {"Se busca: sacerdotisa vil Hexx y sus esbirros", {"Te han ordenado que mates a la sacerdotisa vil Hexx y a 5 guardias Aman'zasi Vilrama. Ve a ver a Primigenia Colmillopartido al Poblado Sañadiente en las Tierras del Interior cuando hayas terminado.","","Los encontrarás en la cima de Jintha'alor, en las Tierras del Interior."}},
[7862] = {"Oferta de empleo: capitán de la guardia de Poblado Sañadiente", {"Debes aniquilar a 5 rabiosos Vilrama, a 3 cazadores de las Sombras Vilrama, a 3 bebesangres Vilrama y a 2 comealmas Vilrama.","","Cuando hayas terminado, ve a ver a Primigenia Colmillopartido al Poblado Sañadiente, en las Tierras del Interior."}},
