[8311] = {"Golosinas de Halloween para Jesper", {"Habla con los taberneros de Ventormenta, Forjaz y Darnassus, así como con Talvash del Kissel en Forjaz. Realiza los trucos que te pidan a cambio de los tratos que ofrecen.","","Vuelve a ver a Jesper frente a Ventormenta con un mazapán de Darnassus, una gominola de Gnomeregan, un almendrado de Ventormenta y una menta de Forjaz."}},
[8312] = {"Golosinas de Halloween para Pupas", {"Habla con los taberneros de Orgrimmar, Entrañas y Cima del Trueno y con Kali Remik en el Valle de los Espíritus de Orgrimmar. Realiza los trucos que te pidan a cambio de los tratos que ofrecen.","","Vuelve a ver a Pupas en las Ruinas de Lordaeron con un mazapán de Cima del Trueno, una gominola de Lanza Negra, un almendrado de Orgrimmar y una menta de Entrañas."}},
[8313] = {"Compartir el conocimiento", {"Lleva la página de receta rota a Calandrath en la taberna del Fuerte Cenarion."}},
[8314] = {"Desentrañar el misterio", {"Entrégale el prisma de cristal con inscripciones a la geóloga Trotuina en el Fuerte Cenarion de Silithus."}},
[8315] = {"La llamada", {"La Geóloga Trotuina del Fuerte Cenarion de Silithus quiere que consigas el mecanismo de desbloqueo de los cristales del emisario qiraji.","","Tienes que llevar los glifos a Huesos de Grakkarond, al sur del Fuerte Cenarion, y dibujarlos en la arena. Si aparece el emisario qiraji, mátalo y coge el mecanismo de desbloqueo de los cristales. Si lo consigues, ve a ver a la geóloga Trotuina.","","¡Lleva un ejército contigo, <nombre>!"}},
