[8409] = {"Los barriles dañados", {"Ve a ver de nuevo a la clamasombras Yanka, que está en el Festival del Hombre de Mimbre en los Claros de Tirisfal."}},
[8410] = {"Maestría elemental", {"Recoge una muestra de aire, fuego, tierra y agua para Bath'rah el Vigía del viento."}},
[8411] = {"Dominar los elementos", {"Lleva los elementos tierra, aire, fuego y agua a Bath'rah el Vigía del viento."}},
[8412] = {"Tótem de espíritu", {"Lleva lo necesario para el tótem del espíritu a Bath'rah el Vigía del viento."}},
[8413] = {"Vudú", {"Lleva las plumas vudú a Bath'rah el Vigía del viento."}},
[8414] = {"Expulsión de los demonios", {"Recoge 20 piedras de la Plaga del esbirro y entrégaselas al sumo sacerdote Thel'danis en las Tierras de la Peste del Oeste."}},
[8415] = {"Campamento del Orvallo", {"Habla con el comandante Ashlam Puñovalor en el Campamento del Orvallo."}},
[8416] = {"Piedras de la Plaga inertes", {"Lleva la piedra de la Plaga inerte al comandante Ashlam Puñovalor en el Alto del Orvallo."}},
[8417] = {"Un espíritu afligido", {"Habla con el héroe caído de la Horda en la entrada de Las Tierras Devastadas."}},
[8418] = {"La forja de la piedra de poderío", {"Obtén plumas vudú ámbar, azules y verdes de los trols del Templo Sumergido."}},
[8419] = {"Pedido de un diablillo", {"Lleva un retal de tela vil a Diblis a Frondavil."}},
[8420] = {"Caliente y picante", {"Lleva un retal de tela vil a Diblis a Frondavil."}},
[8421] = {"La mercancía equivocada", {"Lleva 10 maderas putrefactas y 4 esencias de veneno a Diblis a Frondavil."}},
[8422] = {"Plumas de trol", {"Reúne un total de 6 plumas vudú en el Templo Sumergido."}},
[8423] = {"Parentesco guerrero", {"Mata a 7 jabinfernos de Las Tierras Devastadas y vuelve junto al héroe caído de la Horda."}},
[8424] = {"La guerra contra los Sombra Jurada", {"Acaba con los Sombra Jurada en Las Tierras Devastadas y regresa junto al héroe caído de la Horda."}},
[8425] = {"Plumas Vudú", {"Llévale las plumas vudú de los trols del Templo Sumergido al héroe caído de la Horda."}},
[8426] = {"La batalla por Garganta Grito de Guerra", {"Entrega 3 marcas de honor de la Garganta Grito de Guerra a un Belisario de la Horda fuera de los campos de batalla."}},
