[8446] = {"Inundación de Pesadilla", {"Encuentra a alguien que pueda descifrar el significado del objeto envuelto en pesadillas.","","Quizás un druida de gran poder pueda ayudarte."}},
[8447] = {"Leyendas veraces", {"Espera a que el Guardián Remulos del Claro de la Luna purifique el objeto envuelto en pesadillas."}},
[8460] = {"Aliado Fauces de Madera", {"Grazle quiere que demuestres tu valía matando a 6 guerreros Muertobosque, 6 abrecaminos Muertobosque y 6 jardineros Muertobosque. Cuando lo hayas hecho, vuelve con él al sur de Frondavil, cerca del Santuario Esmeralda."}},
[8461] = {"Los Muertobosque del Norte", {"Nafien quiere que mates a 6 vigías del cubil Muertobosque, 6 vengadores Muertobosque y 6 chamanes Muertobosque. Luego, vuelve a buscarlo al norte de Frondavil, cerca de la entrada del Bastión Fauces de Madera."}},
[8462] = {"Habla con Nafien", {"Viaja hacia el norte por el camino principal de Frondavil y habla con el fúrbolg Nafien. Está haciendo guardia en la entrada del Bastión Fauces de Madera."}},
[8464] = {"Actividad de los Nevada", {"Salfa quiere que mates 8 chamanes Nevada, 8 vigías del cubil Nevada y 8 ursas Nevada. Salfa está a las puertas del Bastión Fauces de Madera en Cuna del Invierno."}},
[8465] = {"Habla con Salfa", {"Viaja por el Bastión Fauces de Madera y sal a Cuna del Invierno. Habla con Salfa, que está haciendo guardia en la entrada del Bastión Fauces de Madera."}},
[8466] = {"Plumas para Grazle", nil},
[8467] = {"Plumas para Nafien", nil},
[8469] = {"Cuentas para Salfa", nil},
[8470] = {"El tótem de ritual Muertobosque", {"Lleva el tótem de ritual Muertobosque al interior del Bastión Fauces de Madera. A ver si alguno de los fúrbolgs que hay en él sabe dar uso al objeto. Los Fauces de Madera no hablarán contigo si no tienes un nivel de reputación neutral o superior con ellos."}},
[8471] = {"Tótem de ritual Nevada", {"Lleva el tótem de ritual Nevada al Bastión Fauces de Madera y averigua si alguno de los fúrbolgs sabe de su utilidad. Los Fauces de Madera no hablarán contigo si tu reputación con ellos no es como mínimo de neutral."}},
[8481] = {"La raíz de todos los males", {"Clava la antorcha para invocar demonios en la entrada de la cueva de Grolnar en el Poblado Nevada de los fúrbolgs. Derrota al demonio y consigue la esencia de Xandivious para Monóculo de Gorn en el Bastión Fauces de Madera."}},
[8484] = {"Negociar la paz", {"Llévale la ofrenda de paz de los Fauces de Madera al rey Magni Barbabronce de Forjaz."}},
[8485] = {"Negociar la paz", {"Llévale la ofrenda de paz de los Fauces de Madera a Shok Narnes a Orgrimmar."}},
[8492] = {"¡La Alianza necesita lingotes de cobre!", {"Llévale 20 lingotes de cobre al sargento Petrocejas en La Sala Militar de Forjaz."}},
[8493] = {"¡La Alianza necesita más lingotes de cobre!", {"Llévale 20 lingotes de cobre al sargento Petrocejas en la base aérea de Dun Morogh."}},
[8494] = {"¡La Alianza necesita barras de hierro!", {"Llévale 20 barras de hierro al cabo Carnes en La Sala Militar de Forjaz."}},
[8495] = {"¡La Alianza necesita más barras de hierro!", {"Llévale 20 barras de hierro al cabo Carnes en la base aérea de Dun Morogh."}},
[8496] = {"Vendas para el campo de batalla", {"Lleva 30 vendas de paño rúnico gruesas, 30 vendas de seda gruesas y 30 vendas de tejido mágico gruesas a Clamavientos Cuerno Digno en el Fuerte Cenarion, en Silithus. También debes llevar el Informe de tareas logísticas X para poder completar la misión."}},
[8497] = {"Material de supervivencia en el desierto", nil},
[8498] = {"Órdenes de batalla Crepusculares", {"Consigue las órdenes de batalla Crepusculares y llévaselas al comandante Mar'alith en el Fuerte Cenarion, en Silithus. También debes llevar el Informe de tareas tácticas X para poder completar la misión."}},
[8499] = {"¡La Alianza necesita barras de torio!", {"Llévale 20 barras de torio a Dama Trenzado en La Sala Militar de Forjaz."}},
[8500] = {"¡La Alianza necesita más barras de torio!", {"Llévale 20 barras de torio a Dama Trenzado en la base aérea de Dun Morogh."}},
[8501] = {"Objetivo: los aguijoneros Colmen'Ashi", {"Mata 30 aguijoneros Colmen'Ashi y preséntate ante el comandante Mar'alith en el Fuerte Cenarion, en Silithus. También debes llevar el Informe de tareas de combate XII para poder completar la misión."}},
[8502] = {"Objetivo: los trabajadores Colmen'Ashi", {"Mata 30 trabajadores Colmen'Ashi y preséntate ante el comandante Mar'alith en el Fuerte Cenarion, en Silithus. También debes llevar el Informe de tareas de combate III para poder completar la misión."}},
[8503] = {"¡La Alianza necesita algas estranguladoras!", {"Llévale 20 algas estranguladoras al soldado Draxlegauge en La Sala Militar de Forjaz."}},
[8504] = {"¡La Alianza necesita más algas estranguladoras!", {"Llévale 20 algas estranguladoras al soldado Draxlegauge en la base aérea de Dun Morogh."}},
[8505] = {"¡La Alianza necesita lotos cárdenos!", {"Llévale 20 lotos cárdenos al maestro Arrullanoche en La Sala Militar de Forjaz."}},
[8506] = {"¡La Alianza necesita más lotos cárdenos!", {"Llévale 20 lotos cárdenos al maestro Arrullanoche en la base aérea de Dun Morogh."}},
[8507] = {"Servicio de campo", {"Preséntate en el puesto de la Brigada de Forjaz cerca de Colmen'Zora. Prepara tu documentación de instrucción de campo sin firmar y consigue la documentación de instrucción de campo firmada del capitán Yunquenegro. A continuación, reúnete con Clamavientos Kaldon en el Fuerte Cenarion, en Silithus.","","Nota: curar o lanzar hechizos benéficos a un miembro de la Brigada de Forjaz, te marcará como JcJ."}},
