[8519] = {"Un peón en el ajedrez de la vida", {"Aprende todo lo que puedas del pasado y habla con Anacronos en las Cavernas del Tiempo de Tanaris."}},
[8520] = {"¡La Alianza necesita vendas de seda!", {"Llévale 20 vendas de seda a la Enfermera Pedregosa en La Sala Militar de Forjaz."}},
[8521] = {"¡La Alianza necesita más vendas de seda!", {"Llévale 20 vendas de seda a la Enfermera Pedregosa en la base aérea de Dun Morogh."}},
