[8523] = {"¡La Alianza necesita más vendas de paño rúnico!", {"Llévale 20 vendas de paño rúnico al vigilante Sombra Lunar en la base aérea de Dun Morogh."}},
[8524] = {"¡La Alianza necesita atún blanco arco iris!", {"Llévale 20 atunes blancos arco iris al Gastrónomo Salao en La Sala Militar de Forjaz."}},
[8525] = {"¡La Alianza necesita más atún blanco arco iris!", {"Llévale 20 atunes blancos arco iris al Gastrónomo Salao en la base aérea de Dun Morogh."}},
[8526] = {"¡La Alianza necesita raptor asado!", {"Llévale 20 raptores asados a Sarah Silbotriste en La Sala Militar de Forjaz."}},
[8527] = {"¡La Alianza necesita más raptor asado!", {"Llévale 20 raptores asados a Sarah Silbotriste en la base aérea de Dun Morogh."}},
[8528] = {"¡La Alianza necesita serviolas moteadas!", {"Llévale 20 serviolas moteadas a la Cazadora Río Veloz en La Sala Militar de Forjaz."}},
[8529] = {"¡La Alianza necesita más serviolas moteadas!", {"Llévale 20 serviolas moteadas a la Cazadora Río Veloz en la base aérea de Dun Morogh."}},
[8532] = {"¡La Horda necesita lingotes de cobre!", {"Llévale 20 lingotes de cobre al Minero Cromwell en el Valle de los Espíritus de Orgrimmar."}},
[8533] = {"¡La Horda necesita más lingotes de cobre!", {"Llévale 20 lingotes de cobre al Minero Cromwell en Durotar."}},
[8534] = {"Informe de exploración de Colmen'Zora", {"Contacta con el explorador Cenarion Azenel en Colmen'Zora y entrega el informe de exploración de Colmen'Zora a Clamavientos Cuerno Digno en el Fuerte Cenarion. También debes llevar el Informe de tareas tácticas VI para poder completar la misión."}},
[8535] = {"Templario vetusto", {"Invoca y mata a un Templario vetusto y preséntate ante Bor Ferocrín en el Fuerte Cenarion. También debes llevar el Informe de tareas tácticas IV para poder completar la misión."}},
[8536] = {"Templario de tierra", {"Invoca y mata a un Templario de tierra y preséntate ante Bor Ferocrín en el Fuerte Cenarion. También debes llevar el Informe de tareas tácticas III para poder completar la misión."}},
[8537] = {"Templario Carmesí", {"Invoca y mata a un templario Carmesí y preséntate ante Bor Ferocrín en el Fuerte Cenarion. También debes llevar el Informe de tareas tácticas II para poder completar la misión."}},
[8538] = {"Los cuatro Duques", {"Invoca y mata al duque de las Brasas, al duque de las Profundidades, al duque de los Céfiros y al duque de las Esquirlas y preséntate ante el comandante Mar'alith en el Fuerte Cenarion. También debes llevar el Informe de tareas tácticas V para poder completar la misión."}},
[8539] = {"Objetivo: las hermanas de la colmena de Colmen'Zora", {"Mata 30 hermanas de la colmena de Colmen'Zora y preséntate ante el comandante Mar'alith en el Fuerte Cenarion, en Silithus. También debes llevar el Informe de tareas de combate V para poder completar la misión."}},
[8540] = {"Botas para la guardia", {"Lleva 3 botas de mitril ornamentado a Vish Kozus, Capitán de la guardia del Fuerte Cenarion en Silithus. También debes llevar el Informe de tareas logísticas II para poder completar la misión."}},
[8541] = {"Piedra de pulir para la guardia", {"Lleva 10 piedras de pulir densas, 10 piedras de pulir sólidas y 10 piedras de pulir pesadas a Vish Kozus, Capitán de la guardia del Fuerte Cenarion en Silithus. También debes llevar el Informe de tareas logísticas III para poder completar la misión."}},
[8542] = {"¡La Horda necesita lingotes de estaño!", {"Llévale 20 lingotes de estaño al bruto Maug en el Valle de los Espíritus de Orgrimmar."}},
[8543] = {"¡La Horda necesita más lingotes de estaño!", {"Llévale 20 lingotes de estaño al bruto Maug en Durotar."}},
[8544] = {"Las bufas de conquistador", {"Llévale las ataduras de mando qiraji, 2 ídolos de la noche, 5 escarabajos de piedra y 5 escarabajos de terracota a Andorgos en Ahn'Qiraj. También debes alcanzar la reputación neutral ante el Linaje de Nozdormu para completar esta misión."}},
[8545] = {"¡La Horda necesita barras de mitril!", {"Llévale 20 barras de mitril al sargento jefe T'kelah en el Valle de los Espíritus de Orgrimmar."}},
[8546] = {"¡La Horda necesita más barras de mitril!", nil},
[8548] = {"Equipamiento de Voluntario", {"Lleva 5 distintivos de combate Cenarion, 3 distintivos de logística Cenarion y 7 distintivos de táctica Cenarion a Vargus en el Fuerte Cenarion, en Silithus. También debes conseguir un nivel de reputación amistoso con el Círculo Cenarion para poder completar esta misión."}},
[8549] = {"¡La Horda necesita flores de paz!", {"Llévale 20 flores de paz al herborista Pluma Digna en el Valle de los Espíritus de Orgrimmar."}},
[8550] = {"¡La Horda necesita más flores de paz!", nil},
[8551] = {"El cofre del Capitán", {"Lleva el cofre de Smotts a Hecklebury Smotts en la Bahía del Botín."}},
[8552] = {"La banda con monograma", {"Devuelve la banda con monograma a su propietario."}},
[8553] = {"El alfanje del Capitán", {"Habla con Tardo."}},
[8554] = {"Enfréntate a Negolash", {"Lleva 10 Alas de águila ratonera a la parrilla y 5 botellas de vino de vid de jungla al barco salvavidas del capitán Smotts.","","Mata a Negolash y lleva el alfanje de Smotts al capitán Smotts en Tuercespina."}},
[8555] = {"Encomienda a los Vuelos", nil},
[8556] = {"El sello de fuerza implacable", {"Llévale 1 anillo qiraji magistral, 2 ídolos luminiscentes, 5 escarabajos de bronce y 5 escarabajos de marfil a Clamavientos Yessendra en Silithus. También debes alcanzar la reputación de honorable ante el Círculo Cenarion para completar esta misión."}},
[8557] = {"El mantón de fuerza implacable", {"Llévale 1 mantón marcial qiraji, 2 ídolos de ónice, 5 escarabajos de plata y 5 escarabajos de hueso a Keyl Patacerce en Silithus. También debes alcanzar la reputación de venerado ante el Círculo Cenarion para completar esta misión."}},
[8558] = {"La hoz de fuerza implacable", {"Llévale 1 puño con pinchos qiraji, 2 ídolos de alabastro, 5 escarabajos de cristal y 5 escarabajos de piedra al celador Haro en Silithus. También debes alcanzar la reputación de exaltado ante el Círculo Cenarion para completar esta misión."}},
[8559] = {"Las grebas de conquistador", {"Llévale las ataduras de mando qiraji, 2 ídolos de la guerra, 5 escarabajos de marfil y 5 escarabajos de oro a Kandrostrasz en Ahn'Qiraj. Esta misión requiere la reputación neutral con la facción Linaje de Nozdormu."}},
[8560] = {"Las musleras de conquistador", {"Llévale la piel intacta de Ouro, 2 ídolos de muerte, 5 escarabajos de bronce y 5 escarabajos de marfil a Kandrostrasz en Ahn'Qiraj. También debes alcanzar la reputación de amistoso ante el Linaje de Nozdormu para completar esta misión."}},
[8561] = {"La corona de conquistador", {"Llévale el aro de Vek'lor, 2 ídolos del sol, 5 escarabajos de piedra y 5 escarabajos de cristal a Andorgos en Ahn'Qiraj. También debes alcanzar la reputación de amistoso ante el Linaje de Nozdormu para completar esta misión."}},
[8562] = {"La coraza de conquistador", {"Llévale el caparazón del dios antiguo, 2 ídolos de la guerra, 5 escarabajos de plata y 5 escarabajos de hueso a Vethsera en Ahn'Qiraj. También debes alcanzar la reputación de honorable ante el Linaje de Nozdormu para completar esta misión."}},
