[8789] = {"Armamentos imperiales qiraji", {"Arygos en el Templo de Ahn'Qiraj creará armamento imbuido de elementium para ti si le llevas armamento imperial qiraji y 3 lingotes de elementium."}},
[8790] = {"Atavío imperial qiraji", {"Merithra del Sueño en el Templo de Ahn'Qiraj creará armamento imbuido de elementium para ti si le llevas un atavío imperial qiraji y 3 lingotes de elementium."}},
