[9356] = {"Suave como una pluma", {"Llévale 12 alas de águila ratonera rollizas a Legassi en el Zepelín Caído."}},
[9357] = {"Informar a Aeldon Marcasol", {"Preséntate ante Aeldon Marcasol en la Puerta Elfa Interior, en el Bosque Canción Eterna."}},
[9358] = {"La forestal Sareyn", {"Preséntate ante la forestal Sareyn en las afueras de Aldea Brisa Pura en el Bosque Canción Eterna."}},
[9359] = {"El Retiro del Errante", {"Preséntate ante la teniente Correalba en el Retiro del Errante, en el Bosque Canción Eterna."}},
[9360] = {"La invasión Amani", {"Entrega los planes de la invasión Amani a la teniente Correalba en El Retiro del Errante."}},
[9361] = {"Huevos fritos con jabinferno", {"Legassi en el Zepelín Caído quiere que consigas 8 unidades de carne purificada de jabinferno. Para purificar la carne, utiliza la mezcla purificadora en la carne de jabinferno máculo que consigas encontrar."}},
[9362] = {"Señor de la guerra Krellian", {"Recupera la concha centelleante para el archimago Xylem. El archimago vive en una torre en lo alto del precipicio de Azshara."}},
[9363] = {"Aviso a la Aldea Brisa Pura", {"Dirígete a Aldea Brisa Pura en el Bosque Canción Eterna y habla con el forestal Degolien."}},
[9364] = {"Magia fragmentada", {"Aplica el hechizo polimórfico a las sirenas Látigo de Ira de Azshara y mata a los clones que aparezcan pasados unos segundos. Cuando hayas matado a 50, vuelve junto al archimago Xylem en Azshara."}},
[9365] = {"Una recompensa de ladrón", {"Devuelve la llama de Ventormenta a (NAME)."}},
[9366] = {"Se busca: Sangrevil", {"Ryathen el Sombrío en la Avanzada del Halcón, en la Península del Fuego Infernal, quiere que le lleves 6 muestras de sangrevil de los terroadictos que viven en las Pozas de Aggonar."}},
[9367] = {"El Festival del Fuego", {"Toca las hogueras de Ventormenta, Forjaz y Darnassus y habla con un maestro cultural del Festival en cada capital."}},
[9368] = {"El Festival del Fuego", {"Toca las hogueras de Orgrimmar, Cima del Trueno y Entrañas y habla con un cuentacuentos del Festival en cada capital."}},
[9369] = {"Recargar los cristales de sanación", {"Consigue 8 viales de sangre de polilla del valle y llévaselos a Proenitus a Lugar del Accidente en Valle Ammen."}},
[9370] = {"Detengamos la purificación", {"Coloca la gema de señalización cerca del Altar de Aggonar en las Pozas de Aggonar y derrota a los anacoretas draenei que respondan a tu invocación. Luego lleva la gema a Ryathen el Sombrío a la Avanzada del Halcón."}},
[9371] = {"La botánica Taerix", {"Habla con la botánica Taerix en el Lugar del Accidente en el Valle Ammen."}},
[9372] = {"Contaminación demoníaca", {"Thiah Melenarroja en el Puesto Cenarion, en la Península del Fuego Infernal, te ha pedido que consigas 6 muestras de sangre de jabinfernos de los jabinfernos descomunales."}},
[9373] = {"Carta perdida", {"Llévale el estuche de cuero erosionado a Thiah Melenarroja, que está acampado cerca de las Ruinas de Sha'naar, al oeste de la Península del Fuego Infernal."}},
[9374] = {"El diario de Arelion", {"La magistrix Carinda de la Avanzada del Halcón en la Península del Fuego Infernal quiere que vayas a las Pozas de Aggonar y recuperes el diario de Arelion."}},
[9375] = {"Hacia la Avanzada del Halcón", {"Protege a la peregrina elfa de sangre herida en su viaje a la Avanzada del Halcón, luego habla con Taleris Observalba."}},
[9376] = {"Una peregrina afligida", {"A la peregrina elfa de sangre herida la atacaron los devastadores jabacolmillo cuando deambulaba por el Barranco Pluma Polvorienta. Encuentra los devastadores y mátalos hasta que recuperes la talega desaparecida de la peregrina."}},
[9377] = {"Sed de poder", {"Recupera 1 esencia potente de abisario de los abisarios vengativos y ve a ver a Taleris Observalba a la Avanzada del Halcón."}},
