[9381] = {"Esas flechas sí que vuelan", {"Recolecta 8 plumas de cola de limpiahuesos de buitres limpiahuesos y llévaselos a la halconera Drenna Ríobrisa Avanzada del Halcón."}},
[9382] = {"El sino de los uñagrietas", nil},
