[9386] = {"Una luz en la oscuridad", nil},
[9387] = {"El origen de la corrupción", {"Viaja a las Ruinas de Sha'naar en la Península del Fuego Infernal y consigue 5 esencias demoníacas de los capataces Illidari. Vuelve a ver al boticario Azethen a la Avanzada del Halcón cuando hayas completado la tarea."}},
[9388] = {"La oscilación de las llamas de Kalimdor", {"Toca las hogueras de Vallefresno, Los Baldíos, Costa Oscura y Sierra Espolón y ve a ver al guardián de la llama del Festival."}},
[9389] = {"La oscilación de las llamas de los Reinos del Este", {"Ve a las hogueras de las Laderas de Trabalomas, el Bosque de Argénteos, los Páramos de Poniente y Los Humedales y habla con el guardián de la llama del Festival."}},
