[9396] = {"La magia de los arakkoa", {"Ve a la Avanzada del Halcón, en la Península del Fuego Infernal, y llévale 4 pergaminos Haal'eshi al arcanista Calesthris Estrella del Alba."}},
[9397] = {"En compañía de pájaros", {"Ve a El Cubil de Haal'esh en la Península del Fuego Infernal y busca en los nidos de kaliri una cría de kaliri hembra. Usa la jaula de pájaros vacía para capturarla y llévasela a la halconera Drenna Ríobrisa en la Avanzada del Halcón."}},
[9398] = {"Depredadores letales", {"La exploradora Vanura del Templo de Telhamat en la Península del Fuego Infernal quiere que mates 8 crías de guadaña de piedra y 4 alfas guadaña de piedra."}},
[9399] = {"Capataces crueles", {"Mata a 4 capataces de Illidari en las Ruinas de Sha'naar y vuelve a ver a Ikan en el Templo de Telhamat, en la Península del Fuego Infernal."}},
