[9434] = {"Probando el tónico", {"Entrega el cajón de componentes a la magistrix Elosai en el Poblado Viento Libre."}},
[9435] = {"Los cristales desaparecidos", {"Recupera el envío de cristales raros de los Renegados y devuélveselo a Huraan en Costasur."}},
[9436] = {"Técnicas Sangrapellejo", {"Nemeth Ojohalcón del campamento Grom'gol quiere que le lleves el tótem de un chamán Sangrapellejo."}},
