[9446] = {"La Tumba del Iluminado", {"Acompaña al anacoreta Truuen a la Tumba de Uther en las Tierras de la Peste del Oeste. Después habla con la suma sacerdotisa MacDonnell en el Campamento del Orvallo en las Tierras de la Peste del Oeste."}},
[9447] = {"El bálsamo", {"La clamatierras Ryga quiere que administres el bálsamo de sanación a 10 brutos Mag'har debilitados cerca del Puesto Mag'har en la Península del Fuego Infernal."}},
