[9452] = {"Delicioso pargo rojo", {"Usa la red de pescar draenei para pescar 10 pargos rojos. Lleva la red y el pescado a Diktynna a la Isla Bruma Azur."}},
[9453] = {"Busca a Acteon", {"Entrega la caja de pargo rojo a Acteon en la Avanzada Azur."}},
