[9643] = {"Parras constrictoras", {"El rastreador Lyceon en la Avanzada de Sangre quiere que le lleves 6 parras constrictoras espinosas."}},
[9644] = {"Nocturno", {"Ve a El Bancal del Maestro en Karazhan y usa la urna ennegrecida para invocar a Nocturno. Recupera la esencia arcana intangible del cadáver de Nocturno y llévasela al archimago Alturus."}},
[9645] = {"El Bancal del Maestro", {"Ve a El Bancal del Maestro en Karazhan y lee el diario de Medivh. Regresa junto al archimago Alturus con el diario de Medivh después de completar esta tarea."}},
[9646] = {"SE BUSCA: Garraletal", {"Lleva la garra de Garraletal al presagista Mikolaas en la Avanzada de Sangre."}},
[9647] = {"Sacrificar a los aleteadores", {"El rastreador Lyceon en la Avanzada de Sangre quiere que mates 10 aleteadores azul real."}},
[9648] = {"La colección de champiñones de Maatparm", {"Maatparm en la Avanzada de Sangre quiere 1 cuernohediondo acuático, 1 champiñón sanguino, 1 poliespora ruinosa y 1 hongo de bellota vil."}},
[9649] = {"Las lágrimas de Ysera", {"Maatparm en la Avanzada de Sangre quiere 2 lágrimas de Ysera."}},
[9663] = {"La carrera de Kessel", {"Kessel de la Encrucijada de Kessel, en la Isla Bruma de Sangre, quiere que avises al gran jefe Semprepino del Bastión Semprepino, al exarca Menelaous de la Avanzada Azur y al almirante Odesyus del Desembarco de Odesyus sobre la inminente invasión de los elfos de sangre. Tienes 15 minutos. Regresa junto a Kessel cuando hayas completado esta tarea. (Asegúrate de que no toque el agua)."}},
[9664] = {"Nuevas avanzadas", {"Captura la Torre de la Corona, la Torre de la Muralla del Este, la Torre del Paso Norte y la Torre del Bosque de la Peste en las Tierras de la Peste del Este. Tras hacerlo, regresa y habla con el Emisario Barbablanca en la Capilla de la Esperanza de la Luz."}},
[9665] = {"Fortalecimiento de nuestras defensas", {"Captura la Torre de la Corona, la Torre de la Muralla del Este, la Torre del Paso Norte y la Torre del Bosque de la Peste en las Tierras de la Peste del Este. Tras hacerlo, regresa y habla con el Emisario Gormok en la Capilla de la Esperanza de la Luz."}},
[9666] = {"Declaración de poder", {"Kessel de la Encrucijada de Kessel, en la Isla Bruma de Sangre, quiere que mates a Lord Xiz, de la Guarida Escama de Cólera, y atravieses su cadáver con el estandarte draenei."}},
[9667] = {"Salvar a la princesa Semprepino", {"Libera a la Princesa Semprepino de su jaula y habla después con el embajador Semprepino Olorg, en la Avanzada de Sangre.","","Tienes que matar al gran jefe Erizapúas para conseguir la llave de la jaula."}},
[9668] = {"Informar al exarca Admetius", {"Habla con el exarca Admetius en la Avanzada de Sangre."}},
[9669] = {"La expedición desaparecida", {"Mata 8 hiladoras de bruma, 8 parasitadoras de bruma y a su líder, Zarakh. Vuelve a ver a Achelus en la Avanzada de Sangre cuando hayas completado la tarea."}},
[9670] = {"¡Viven! A lo mejor...", {"El investigador Cornelius ha pedido que liberes 5 investigadores de la expedición."}},
[9671] = {"Entrega urgente", nil},
[9672] = {"El legado de la Sangre Maldita", {"El almirante Odesyus te ha pedido que encuentres al capitán Edward Hanes y hables con él."}},
[9673] = {"Doma de bestias", {"Ve a la Ciudad de Lunargenta y habla con Halthenis."}},
[9674] = {"Los nagas Sangre Maldita", {"El capitán Edward Hanes de la Isla Cicatriz de Vermis quiere que mates a 10 nagas Sangre Maldita.|n"}},
[9675] = {"Doma de bestias", {"Habla con Ganaar en La Grada de los Mercaderes de El Exodar."}},
[9676] = {"Instrucción de paladín", {"Habla con Jesthenis Golpesol, el instructor de clase de paladines, en La Aguja del Sol en la Isla del Caminante del Sol."}},
[9677] = {"El llamamiento del Lord caballero Sangrevalor", {"Habla con el Lord caballero Sangrevalor en la Plaza del Errante de la Ciudad de Lunargenta."}},
[9678] = {"La primera prueba", {"Viaja a la isla que el Lord caballero Sangrevalor describió, encuentra la caverna, y enciende el blandón. Cuando acabe la primera prueba vuelve junto al Lord caballero Sangrevalor en la Ciudad de Lunargenta."}},
[9680] = {"Resucitar el pasado", {"El archimago Alturus quiere que vayas a las montañas al sur de Karazhan en el Paso de la Muerte y consigas un trozo de hueso carbonizado."}},
[9681] = {"Un estudio sobre el poder", {"Habla con el magister Astalor Jurasangre en la cámara oculta debajo del cuartel general de los Caballeros de sangre."}},
[9682] = {"Los Desesperados...", {"El capitán Edward Hanes de la Isla Cicatriz de Vermis quiere que consigas 4 almas de Sangre Maldita."}},
[9683] = {"El fin de la Sangre Maldita", {"El capitán Edward Hanes de la Isla Cicatriz de Vermis quiere que destruyas la estatua de la reina Azshara y mates a Atoph, el Sangre Maldita."}},
[9684] = {"Buscando la Luz", {"Llena la vasija refulgente en magistri elfos de sangre y llévasela al Lord caballero Sangrevalor a Ciudad de Lunargenta."}},
[9685] = {"Redimir a los muertos", {"Lleva la vasija refulgente llena a la posada de la Ciudad de Lunargenta y utiliza su magia para resucitar a Sangrias Hojafirme."}},
[9686] = {"La segunda prueba", {"Completa la segunda prueba derrotando a los Campeones Furiasangre, Rasgaluz, Hojágil y Golpesol en el pabellón cerca del maestro Kelerun Lamento de Sangre."}},
[9687] = {"Recuperando huesos sacros", {"El príncipe Toreth de Isla Cicatriz de Vermis quiere que le lleves 8 huesos de dragón."}},
[9688] = {"Entrando en el Sueño", {"El príncipe Toreth de Isla Cicatriz de Vermis quiere que mates 5 crías y 5 estirpes viridianas."}},
[9689] = {"Tajobuche", {"El príncipe Toreth de la Isla Cicatriz de Vermis ha pedido que mates a Tajobuche."}},
[9690] = {"La segunda prueba", {"Preséntate ante el maestro Kelerun Lamento de Sangre."}},
[9691] = {"Regresa a Lunargenta", {"Ve a ver al Lord caballero Sangrevalor en Ciudad de Lunargenta."}},
[9692] = {"El camino de los adeptos", {"Lleva 1 gema kor corrupta, 1 caja de lingotes forjados con sangre, sangre del Colérico y 1 insignia de Caballero de sangre al Lord caballero Sangrevalor a Ciudad de Lunargenta."}},
[9693] = {"¿Qué es Argus para ti?", {"El exarca Admetius de la Avanzada de Sangre quiere que hables con el vindicador Boros."}},
[9694] = {"Avanzada de Sangre", {"El vindicador Boros de la Avanzada de Sangre quieres que mates a 10 espías Halcón del Sol."}},
[9695] = {"Las órdenes del Rey del Sol", {"Lleva la orden del Rey del Sol al vindicador Boros a la Avanzada de Sangre.|n"}},
[9696] = {"Traducciones", {"Lleva la misiva de los Halcones del Sol a la interrogadora Elysia a la Avanzada de Sangre."}},
[9697] = {"La vigía Leesa'oh", {"Ve al Puesto de Vigilancia Cenarion de la Marisma de Zangar y habla con la vigía Leesa'oh."}},
[9698] = {"Audiencia con el Profeta", {"Lleva la traducción de la carta de los Halcón del Sol al profeta Velen a El Exodar."}},
[9699] = {"Verdad o mentira", {"Lleva las órdenes de Velen al vindicador Boros a la Avanzada de Sangre."}},
[9700] = {"Disparando magia en la oscuridad", {"El vindicador Boros de la Avanzada de Sangre quiere que encuentres el portal del Sol y mates 5 anomalías del vacío."}},
[9701] = {"Observación de esporinos", {"Investiga La Cañada Emergente en la Marisma de Zangar e informa a la vigía Leesa'oh del Puesto de Vigilancia Cenarion en la Marisma de Zangar de tus pesquisas."}},
[9702] = {"Cuestión de glotonería", {"Recoge 10 restos de alimentos y llévaselos a la vigía Leesa'oh al Puesto de Vigilancia Cenarion de la Marisma de Zangar."}},
[9703] = {"El Crionúcleo", {"El vindicador Kuros de la Avanzada de Sangre quiere que recuperes 12 cajas de suministros médicos."}},
[9704] = {"Ejecutados por los desdichados", {"Ve hacia el sur a las Ruinas de Ciudad de Lunargenta y busca a la avanzada asesinada en Calle del Alba."}},
[9705] = {"Recuperación de paquete", {"Regresa junto a la avanzada Alarion con el paquete de Erona."}},
[9706] = {"El diario de Galaen: El destino del vindicador Saruan", {"Lleva el diario de Galaen al vindicador Kuros a la Avanzada de Sangre.|n"}},
[9707] = {"Forjando el arma", {"Lleva el cajón de materiales a Bemarrin a Ciudad de Lunargenta."}},
[9708] = {"Ese hongo me suena", {"Recolecta 15 muestras de champiñones y llévaselas a la vigía Leesa'oh al Puesto de Vigilancia Cenarion de la Marisma de Zangar."}},
[9709] = {"Volver a robar los champiñones", {"Recolecta 10 cajas de champiñones y llévaselas a la vigía Leesa'oh al Puesto de Vigilancia Cenarion en la Marisma de Zangar."}},
[9710] = {"La corcesca templada en sangre", {"Espera mientras Bemarrin forja tu arma."}},
[9711] = {"Matis el Cruel", {"El vindicador Kuros de Avanzada de Sangre quiere que captures a Matis el Cruel."}},
[9712] = {"El caballo de guerra thalassiano", {"Habla con el Lord caballero Sangrevalor para aprender a invocar a tu caballo de guerra thalassiano."}},
[9713] = {"Recogiendo fluochampiñones", nil},
[9714] = {"¡Tráeme otra mata!", nil},
[9715] = {"¡Tráeme una mata!", {"Recolecta 5 hibiscos sanguinos y llévaselos a Gzhun'tt en Esporaggar en la Marisma de Zangar."}},
[9716] = {"Problemas en el Lago Umbropantano", {"Investiga el origen de la pérdida de agua en Lago Umbropantano. Luego ve a ver a Ysiel Vientocantor al Refugio Cenarion, en la Marisma de Zangar."}},
[9717] = {"El esqueje", {"Recolecta un esqueje de sotoespora y llévaselo a T'shu a Esporaggar en la Marisma de Zangar."}},
[9718] = {"A vuelo de pájaro", {"Ysiel Vientocantor quiere que uses el amuleto de cuervo tormentoso para explorar los lagos principales de la Marisma de Zangar."}},
[9719] = {"El acechador acechado", {"Lleva el cerebro de la Acechadora Negra a Khn'nix en Esporaggar en la Marisma de Zangar."}},
[9720] = {"Restaurar el equilibrio", {"Ysiel Vientocantor quiere que utilices las semillas de Parraférrea en los controles de las bombas de vapor en el Lago Serpiente, el Lago Umbropantano, el Lago Luz Pantanosa y La Laguna. A continuación vuelve a verla al Refugio Cenarion en la Marisma de Zangar y llévale las sobras que tengas."}},
[9721] = {"Lord Solanar te convoca", {"Habla con Lord Solanar Sangre Colérica en la Ciudad de Lunargenta."}},
[9722] = {"El camino del maestro", {"Habla con Lord Solanar Sangre Colérica y acepta su ofrecimiento de patrocinio."}},
[9723] = {"Un gesto de entrega", {"Lleva 40 paños rúnicos, 6 barras de arcanita, 10 soleas, 5 runas oscuras y 150 piezas de oro a Lord Solanar Sangre Colérica en la Ciudad de Lunargenta."}},
[9724] = {"Advertir al Círculo Cenarion", {"Habla con Amythel Caminaniebla en el Puesto Cenarion, en la Península del Fuego Infernal."}},
[9725] = {"Una demostración de lealtad", {"Lord Solanar Sangre Colérica en la Ciudad de Lunargenta quiere que destruyas 3 carros de despojos de la Plaga y mates a 15 ingenieros de asedio de la Plaga."}},
[9726] = {"Ahora que somos amigos...", {"Mata a 12 explotadores Escamas de Sangre y a 6 encantadoras Escamas de Sangre, y vuelve junto a Gzhun'tt en Esporaggar, en la Marisma de Zangar."}},
[9727] = {"Ahora que aún somos amigos...", {"Mata a 12 explotadores Escamas de Sangre y a 6 encantadoras Escamas de Sangre, y vuelve junto a Gzhun'tt en Esporaggar, en la Marisma de Zangar."}},
[9728] = {"Una cálida bienvenida", {"El celador Hamoot del Refugio Cenarion quiere que le lleves 30 garras de naga."}},
[9729] = {"¡Fhwoor da el golpe!", {"Escolta a Fhwoor hasta la zona de la bomba de vapor de la Luz Pantanosa para recuperar el Arca de Ssslith. Asegúrate de que Fhwoor y el arca vuelven sin peligro e informa a Gzhun'tt en Esporaggar, en la Marisma de Zangar."}},
[9730] = {"El líder de los Cresta Oscura", {"Mata al rajá Brujobruma en La Laguna y regresa junto al celador Hamoot de la Expedición Cenarion, en la Marisma de Zangar, por tu recompensa."}},
[9731] = {"Planos de conducto", {"Busca en el fondo del Lago Serpiente signos de un conducto. Regresa junto a Ysiel Vientocantor en el Refugio Cenarion con las noticias de lo que descubras."}},
[9732] = {"Regresa a la Marisma", {"Regresa junto a Ysiel Vientocantor en el Refugio Cenarion, en la Marisma de Zangar."}},
[9733] = {"Advertir al Círculo Cenarion", {"Habla con Mahuram Pezuña Recia en Thrallmar, en la Península del Fuego Infernal."}},
[9734] = {"Regresa a la Marisma", {"Regresa junto a Ysiel Vientocantor en el Refugio Cenarion, en la Marisma de Zangar."}},
[9735] = {"Verdaderos maestros de la Luz", {"Lord Solanar Sangre Colérica, en la Ciudad de Lunargenta, quiere le lleves 1 vial de agua sagrada de la Mano de Tyr."}},
[9736] = {"Verdaderos maestros de la Luz", {"Lord Solanar Sangre Colérica de Ciudad de Lunargenta quiere que le lleves 1 catalizador arcano, 1 partículas Crepusculares, 1 diamante de Azeroth y 1 diamante negro prístino."}},
[9737] = {"Verdaderos maestros de la Luz", {"Utiliza la mezcla de extinción cerca de la llama eterna de la Capilla de Alonsus para eliminar la protección de la Luz. Prepárate para luchar contra cualquiera que pretenda defender la capilla."}},
[9738] = {"Desaparecidos en combate", {"Averigua qué le ha ocurrido al vinculador terrestre Rayge, al naturalista Mordisco, al desherbador Pulgarverde y al clamavientos Zarpa. Después, vuelve junto al vigía Jhang en la Reserva Colmillo Torcido, en la Marisma de Zangar."}},
[9739] = {"La aflicción de los esporinos", {"Fahssn, de La Cañada Emergente, quiere que reúnas 10 bolsas de esporas maduras."}},
[9740] = {"El portal solar", {"El vindicador Aesom de la Avanzada de Sangre quiere que destruyas el portal solar."}},
[9741] = {"Alimañas del vacío", {"Mata 12 alimañas del vacío e informa luego al vindicador Aesom en la Avanzada de Sangre.|n"}},
[9742] = {"Más bolsas de esporas", nil},
[9743] = {"Enemigos naturales", {"Fahssn, de La Cañada Emergente en la Marisma de Zangar, quiere que le lleves 6 zarcillos de señor de la marisma."}},
[9744] = {"¡Más zarcillos!", nil},
[9746] = {"Los límites del agotamiento", {"El vindicador Aesom de la Avanzada de Sangre quiere que mates a 10 pirománticos de los Halcones del Sol y a 10 defensores de los Halcones del Sol.|n"}},
[9747] = {"La tribu Umbropantano", {"Ikeyen del Refugio Cenarion quiere que vayas a la Aldea Umbropantano y mates a Kataru, 8 videntes de Umbropantano, 6 médicos brujos de Umbropantano y 6 oráculos de Umbropantano."}},
[9748] = {"Agua que no has de beber...", {"El vindicador Aesom de la Avanzada de Sangre quiere que uses el frasco para recoger una muestra de agua de Bruma de Sangre."}},
[9749] = {"¡Viven! A lo mejor...", {"El investigador Cornelius ha pedido que liberes 5 investigadores de la expedición."}},
[9750] = {"UNUSED Urgent Delivery", nil},
[9751] = {"El legado de la Sangre Maldita", {"El almirante Odesyus te ha pedido que encuentres al capitán Edward Hanes y hables con él."}},
[9752] = {"Evasión de Umbropantano", {"Acompaña a Kayra Crin Larga al Refugio Cenarion en la Marisma de Zangar. Después ve a ver a Ysiel Vientocantor."}},
[9753] = {"Saber es poder", {"Habla con el exarca Admetius en Avanzada de Sangre."}},
[9756] = {"Lo que no sabemos", {"Habla con un agente Halcón del Sol capturado en Avanzada de Sangre y consigue información. Luego ve a ver al exarca Admetius."}},
[9757] = {"La cazadora Kella Arconocturno", {"Habla con la cazadora Kella Arconocturno cerca del Atracadero de Valaar."}},
[9758] = {"Regresa junto al arcanista Vandril", {"Preséntate ante el arcanista Vandril en Tranquillien, en las Tierras Fantasma."}},
[9759] = {"El fin de su mundo", {"Sigue y protege al demoledor Legoso mientras intenta destruir La Espiral Vectorial y matar a Sironas. Ve a ver al exarca Admetius en la Avanzada de Sangre si completas la misión."}},
[9760] = {"El Reposo del Vindicador", {"Habla con el vindicador Corin en El Reposo del Vindicador en Isla Bruma de Sangre.|n"}},
[9761] = {"Despejando el camino", {"El vindicador Corin de El Reposo del Vindicador quiere que mates a 8 saboteadores y 8 agentes Halcón del Sol.|n"}},
[9762] = {"La profecía no escrita", nil},
[9763] = {"La guarida del Señor de la Guerra", {"La vigía Jhang quiere que encuentres y mates al señor de la guerra Kalithresh dentro de la Reserva Colmillo Torcido."}},
[9764] = {"Órdenes de Lady Vashj", {"Entrega las órdenes de Lady Vashj a Ysiel Vientocantor en el Refugio Cenarion, en la Marisma de Zangar."}},
[9765] = {"Preparativos de guerra", {"Consigue armamentos Colmillo Torcido de los nagas en la Reserva Colmillo Torcido y llévaselos a Ysiel Vientocantor en el Refugio Cenarion, en la Marisma de Zangar."}},
[9766] = {"Armamentos de Colmillo Torcido", nil},
[9767] = {"Conoce a tu enemigo", {"Consigue un libro de hechizos Colmillo Torcido de los nagas de la Reserva Colmillo Torcido y llévaselo a Ashyen en el Refugio Cenarion en la Marisma de Zangar."}},
[9769] = {"Antes muertos que sencillos", {"Lleva ocho alas diáfanas de cualquier especie de aguijonero de la Marisma de Zangar a Magasha, en la Avanzada Rata del Pantano."}},
[9770] = {"La amenaza de los Colmillo de la Marisma", {"Reavij de la Avanzada Rata del Pantano quiere que mates a 10 destripadores Colmillo de la Marisma."}},
[9771] = {"En busca del explorador Jyoba", {"Busca al explorador Jyoba en El Lodo Muerto, en la Marisma de Zangar."}},
[9772] = {"El informe de Jyoba", {"Recupera el informe del explorador Jyoba de los gigantes marchitos y llévaselo a Zurai, en la Avanzada Rata del Pantano."}},
[9773] = {"¡Ya basta de champiñones!", {"Recolecta 8 filetes de anguila de las anguilas Umbropantano y llévaselos a Magasha en la Avanzada Rata del Pantano."}},
[9774] = {"Escama de hidra gruesa", {"Zurai en la Avanzada Rata del Pantano quiere que le lleves 12 escamas de hidra gruesas."}},
[9775] = {"Cazador de las Sombras Denjai", {"Lleva el informe de Zurai al cazador de las Sombras Denjai a Zabra'jin en la Marisma de Zangar."}},
[9776] = {"El Puerto Orebor", {"Habla con Ikuti en el Puerto Orebor, en la Marisma de Zangar."}},
[9777] = {"Esporas refulgentes", {"Lleva 6 esporas refulgentes a Ruam en Telredor."}},
[9778] = {"El celador Hamoot", {"Preséntate ante el celador Hamoot en el Refugio Cenarion, en la Marisma de Zangar."}},
[9779] = {"Interceptando el mensaje", {"Mata elfos de Halcón del Sol hasta que encuentres la misiva de Halcón del Sol. Después, vuelve a hablar con el vindicador Boros en Avanzada de Sangre."}},
[9780] = {"Filetes de anguila de Umbropantano", {"Noraani de Telredor quiere que le traigas 8 filetes de anguila."}},
[9781] = {"Demasiadas bocas que alimentar", {"Mata 10 hidras de lodazal y vuelve a ver a Haalrun en Telredor."}},
[9782] = {"El Lodo Muerto", {"Lleva una muestra de tierra de El Lodo Muerto al vindicador Idaar, en Telredor."}},
[9783] = {"Una sequía no natural", {"El vindicador Idaar en Telredor quiere que mates 12 gigantes marchitos."}},
[9784] = {"Identificar partes de plantas", nil},
[9785] = {"Bendición de los ancestros", {"Clamavientos Pezuñanegra quiere que hables con los ancianos Ashyen y Keleth en el Refugio Cenarion y que obtengas su bendición."}},
[9786] = {"Las Ruinas Boha'mu", {"El anacoreta Ahuurn de Telredor quiere que explores las Ruinas Boha'mu."}},
[9787] = {"Ídolos de Feropantano", {"Recolecta 6 ídolos de Feropantano y llévaselos al anacoreta Ahuurn a Telredor."}},
[9788] = {"Un lugar húmedo y sombrío", {"Busca las pertenencias de Ikeyen en una cueva al sur de Umbropantano. Llévaselas de vuelta a Ikeyen en el Refugio Cenarion, en la Marisma de Zangar."}},
[9789] = {"Cacería de uñagrietas", {"Caza 12 uñagrietas y vuelve a ver a Hemet Nesingwary en el Safari Nesingwary, en Nagrand, para demostrar tu valía."}},
[9790] = {"Alas diáfanas", {"Haalrun en Telredor quiere que le lleves 8 alas diáfanas de cualquier especie voladora de la Marisma de Zangar."}},
[9791] = {"La amenaza de los Colmillo de la Marisma", {"Mata 10 destripadores Colmillo de la Marisma y vuelve a ver a Noraani en Telredor."}},
[9792] = {"Un mensaje para Telaar", {"Habla con Nahuud en Telaar, en Nagrand."}},
[9793] = {"El destino de Tuurem", {"Lleva la carta del vindicador Idaar a Andarl en el Bastión Allerian, en el Bosque de Terokkar."}},
[9794] = {"No hay tiempo para la curiosidad", {"Lleva la carta de Timothy a Kialon en Sylvanaar, en las Montañas Filospada."}},
[9795] = {"La amenaza de los ogros", {"Ve al Bastión Señor del Trueno en las Montañas Filospada y habla con Nekthar."}},
[9796] = {"Noticias de la Marisma de Zangar", {"Habla con Mokasa en el Bastión Rompepedras, en el Bosque de Terokkar."}},
[9797] = {"Refuerzos para Garadar", {"Habla con el capitán Kroghan en Garadar, en Nagrand."}},
[9798] = {"Planes de los elfos de sangre", {"Lleva los planes de los elfos de sangre al vindicador Aldar en el Lugar del Accidente, en el Valle Ammen."}},
[9799] = {"Trabajo de campo", {"Recolecta 3 flores corruptas y llévaselas a la aprendiza Vishael a Lugar del Accidente, en Valle Ammen."}},
[9800] = {"Una extraña judía", {"El elementalista Lo'ap en El Trono de los Elementos, en Nagrand, quiere que le consigas 8 anacardos digeridos."}},
[9801] = {"Recogiendo componentes", {"El anacoreta Ahuurn de Telredor quiere que le lleves 4 ojos de esporiélago y 4 tentáculos de zancudo pantanoso."}},
[9802] = {"Plantas de Marisma de Zangar", {"Lleva 10 fragmentos de plantas sin identificar a Lauranna Thar'well al Refugio Cenarion en Marisma de Zangar."}},
[9803] = {"Mensajero de los Feropantanos", {"Bebe el elixir de Ahuurn cuando estés en las Ruinas Boha'mu. Habla con el ancestro Kuruti cuando hayas adoptado la forma de un arakkoa."}},
[9804] = {"Espíritus agitados de Sol Celeste", {"El elementalista Lo'ap en El Trono de los Elementos, en Nagrand, quiere que destruyas 8 espíritus del lago."}},
[9805] = {"Bendición de Incineratus", {"El elementalista Lo'ap en El Trono de los Elementos, en Nagrand, quiere que destruyas la Cabaña Grande, la Cabaña del Oeste, la Cabaña del Sur y la Cabaña del Este en la Aldea Junco Alabeado.","","Devuelve el fuego viviente al elementalista Lo'ap cuando hayas completado tu tarea."}},
[9806] = {"Esporas fértiles", {"Gshaff quiere que reúnas 6 esporas fértiles entre los esporiélagos y los caminantes de marismas de la Marisma de Zangar. Vuelve a ver a Ghsaff en Esporaggar cuando hayas completado la tarea."}},
