[10123] = {"El Barranco Llama Infernal", {"El sargento Trizacráneo de la Caravana de Provisiones al este de Thrallmar en la Península del Fuego Infernal quiere que mates a 4 diablillos Despiertallamas, 6 belisarios infernales y 1 invocamiedo."}},
[10124] = {"Base de la vanguardia: Caída del Atracador Vil", {"Preséntate ante el comandante de vanguardia To'arch en la Caída del Atracador Vil."}},
[10125] = {"Misión: Interrumpir las comunicaciones", {"El comandante de vanguardia To'arch de la Caída del Atracador Vil en la Península del Fuego Infernal quiere que uses los explosivos para destruir las Antenas Legión Maldad, Ira, Odio y Miedo."}},
[10126] = {"Órdenes del mandón de guerra Nekrogg", nil},
[10127] = {"Misión: Cortar la unión", {"El comandante de vanguardia To'arch en la Caída del Atracador Vil en la Península del Fuego Infernal, quiere que mates a 4 cuidadores viles, 8 guardias de cólera y al subyugador Shi'aziv."}},
[10128] = {"Salvar al soldado Imarion", nil},
[10129] = {"Misión: Puerta Murketh y Puerta Shaadraz", {"Habla con el comandante del aire Brack, bombardea Puerta Murketh y Puerta Shaadraz y después regresa junto al comandante de vanguardia To'arch en la Caída del Atracador Vil."}},
[10130] = {"El flanco oeste", {"Mata a 10 guardias Mano Destrozada, 10 rabiosos Mano Destrozada y 5 acólitos Mano Destrozada, e informa después a la teniente Amadi en la torre de vigilancia oeste del Bastión del Honor."}},
[10131] = {"Planear la huida", nil},
[10132] = {"La amenaza colosal", {"Mata a 5 colosos enfurecidos y regresa junto a Tola'thion en el Puesto Cenarion, en la Península del Fuego Infernal."}},
[10133] = {"Misión: Matar al mensajero", nil},
[10134] = {"Pista para el cristal carmesí", {"Entrega el fragmento de cristal carmesí a Tola'thion en el Puesto Cenarion, en la Península del Fuego Infernal."}},
[10135] = {"Misión: Sé el mensajero", nil},
[10136] = {"Crueles intenciones", {"Mata a Arazzius el Cruel y vuelve con Nazgrel en Thrallmar."}},
[10137] = {"Provocando al mandón de guerra", nil},
[10138] = {"¿Quién manda aquí?", nil},
[10139] = {"Vencer al comandante", nil},
[10140] = {"Viaje al Bastión del Honor", {"Vuela hasta el Bastión del Honor y entrega el informe de Duron al mariscal Isildor."}},
[10141] = {"El renacer de la Legión", {"Habla con la sargento Altumus en la Caravana de Provisiones del Este justo fuera del Bastión del Honor, hacia el este."}},
[10142] = {"El Camino del Tormento", {"La sargento Altumus en la Caravana de Provisiones del Este del Bastión del Honor en la Península del Fuego Infernal, quiere que mates a 4 diablillos despiertallamas, 6 belisarios infernales y 1 invocamiedo."}},
[10143] = {"Punta de Expedición", {"Preséntate ante el comandante de vanguardia Kingston en la Punta de Expedición."}},
[10144] = {"Perturbar sus refuerzos", {"Vence a los enemigos que hay alrededor del Portal Grimh y el Portal Kaalez para reunir piedras rúnicas demoníacas.","","Usa el cebo explosivo de Kingston dentro del Portal Grimh y del Portal Kaalez.","","Vuelve con el comandante de vanguardia Kingston con los explosivos restantes."}},
[10145] = {"Mission: Sever the Tie UNUSED", {"El comandante de vanguardia Kingston en la Punta de Expedición, en la Península del Fuego Infernal, quiere que mates 4 cuidadores viles, 8 guardias de cólera y al subyugador Yalqiz."}},
[10146] = {"Misión: La Puerta Murketh y la Puerta Shaadraz", {"Habla con el comandante del aire Dabir'ee, bombardea la Puerta Murketh y la Puerta Shaadraz y, a continuación, vuelve a ver al comandante de vanguardia Kingston en la Punta de Expedición."}},
[10147] = {"Misión: Matar al mensajero", nil},
[10148] = {"Misión: Sé el mensajero", nil},
[10149] = {"Misión: Acaba con todo, sé todo", nil},
[10150] = {"Espiando en la Ciudadela", {"Busca alguna pista de la exploradora Makha en el campamento más al norte junto a la Muralla Norte."}},
[10151] = {"Órdenes del dirigente de guerra Nekrogg", nil},
[10152] = {"El flanco oeste", {"Mata 10 guardias Mano Destrozada, 10 rabiosos Mano Destrozada y 5 acólitos Mano Destrozada. A continuación, preséntate ante el guardia de piedra Ambelan en la Avanzada Rompeloma, cerca de Zeth'Gor."}},
[10153] = {"Rescate de la exploradora Makha", nil},
[10154] = {"Planear la huida", nil},
[10155] = {"Provocando al mandón de guerra", nil},
[10156] = {"¿Quién manda aquí?", nil},
[10157] = {"Vencer al comandante", nil},
[10158] = {"Suministros Foso Sangrante", nil},
[10159] = {"Mantener despejada la Colina Colmillespinado", {"Mata 8 devastadores Colmillespinados y 8 escupetósigos Colmillespinados. A continuación ve a ver a Mahuram Pezuña Recia en el Puesto Cenarion, en la Península del Fuego Infernal."}},
[10160] = {"Conoce a tu enemigo", {"Habla con la teniente Amadi en la vieja torre vigía justo al oeste del Bastión del Honor."}},
[10161] = {"En caso de emergencia...", {"Consigue 30 restos del zepelín y llévaselas a \"Alaridos\" Screed Sinsuerte en el Zepelín Caído."}},
[10162] = {"Misión: La Plataforma Abisal", {"El comandante de vanguardia To'arch de la Caída del Atracador Vil en la Península del Fuego Infernal quiere que destruyas 20 peones de Gan'arg, 5 sobrestantes Mo'arg y 5 cañones viles."}},
[10163] = {"Misión: La Plataforma Abisal", {"El comandante del aire Grifongar del Puesto Devastación, en la Península del Fuego Infernal, ha solicitado que destruyas 20 peones de Gan'arg, 5 sobrestantes Mo'arg y 5 cañones viles."}},
[10164] = {"Todo irá bien", {"Abuelo Aldrimus, fuera de las Criptas Auchenai en Auchindoun, quiere que entres en las criptas y mates al exarca Maladaar."}},
[10165] = {"Eliminar a la competencia", {"El príncipe-nexo Haramad, que está junto a las Tumbas de Maná, quiere que mates al príncipe-nexo Shaffar y le lleves su mortaja."}},
[10166] = {"La memoria de Cortezablanca", {"Larianna Ríobrisa quiere que entierres el colgante del viejo Cortezablanca junto a la piedra rúnica de La Arboleda Agostada."}},
[10167] = {"Auchindoun...", {"Ve a las Criptas Auchenai, en El Vertedero de Huesos del Bosque de Terokkar, y mata al exarca Maladaar para liberar al espíritu de D'ore.|n"}},
[10168] = {"Reflejos del alma", {"Encuentra un espejo de alma en las Criptas Auchenai y úsalo para llamar a un espíritu oscurecido de los antepasados orcos ancestrales en Nagrand. Destruye 15 espíritus oscurecidos para que los antepasados puedan descansar en paz.","","Después ve a ver a Madre Kashur a las Tierras Ancestrales."}},
[10169] = {"Saber perder", {"El magister Falris de Shattrath quiere que lleves el vial de suero sedativo a Bancal de la Luz y lo viertas en la olla del regimiento de Haronem."}},
[10170] = {"Regresa junto a la Abuela", {"Vuelve a Garadar y habla con la Abuela Geyah."}},
[10171] = {"El inconsolable jefe", {"La Abuela Geyah en Garadar te ha pedido que hables con Garrosh."}},
[10172] = {"No hay esperanza", {"Habla con la Abuela Geyah y cuéntale lo que Garrosh te ha dicho."}},
[10173] = {"El bastón del archimago", {"Quítale el bastón del archimago Vargoth a Ekkorash la Inquisidora y llévaselo a Ravandwyr al Área 52. Para sacar a Ekkorash de su escondite, espolvorea el polvo de conjuro en el blandón que hay en el centro de las ruinas."}},
[10174] = {"La maldición de la Torre Violeta", {"Utiliza el bastón del archimago Vargoth para contactar con él.","","Si pierdes el bastón del archimago Vargoth, habla con Ravandwyr en el Área 52 para que te dé otro."}},
[10175] = {"Thrall, hijo de Durotan", {"Ve a Orgrimmar y entrega a Thrall el mensaje de Geyah."}},
[10176] = {"Ar'kelos el Guardián", {"Entra en la Torre Violeta en el centro del Poblado Kirin'Var y derrota a Ar'kelos. A continuación, habla con el archimago Vargoth."}},
[10177] = {"Problemas en Auchindoun", {"Preséntate ante el comandante de operaciones Mahfuun en la entrada del Laberinto de las Sombras en Auchindoun, en el Bosque de Terokkar."}},
[10178] = {"Encontrar al espía To'gun", {"Localiza al espía To'gun en el Laberinto de las Sombras, en Auchindoun."}},
[10179] = {"El custodio de Kirin'Var", {"Habla con el custodio Valemuerte en el Poblado Kirin'Var, en Tormenta Abisal."}},
[10180] = {"No puedo estar lejos", {"Habla con Isfar. Le encontrarás cerca de la entrada de las Salas Sethekk en Auchindoun."}},
[10182] = {"Mago de batalla Dathric", {"Encuentra las dependencias del mago de batalla Dathric en el Pasaje del Zahorí y devuelve la espada al expositor. A continuación habla con el custodio Valemuerte en el Poblado Kirin'Var."}},
[10183] = {"Al Área 52", {"Lleva las notas del abisólogo al jefe de cohetes Fuselaje en el Área 52, en la Tormenta Abisal."}},
[10184] = {"Restos malévolos", {"El custodio Valemuerte en el Poblado Kirin'Var quiere que mates 20 espíritus aislados en la Plaza de la Ciudad de Kirin'Var."}},
[10185] = {"Terrible destino", {"Mata a 10 matamagos y 10 buscamanás y ve a ver al custodio Valemuerte al Poblado Kirin'Var."}},
[10186] = {"¡Te contrato!", {"Reúne 10 cristales de la matriz de eterlitio y vuelve a ver al jefe de cohetes Fuselaje en el Área 52 en la Tormenta Abisal."}},
[10187] = {"Mensaje del archimago", {"Habla con el archimago Vargoth en la cima de la Torre Violeta, en Tormenta Abisal."}},
[10188] = {"El sigilo de Krasus", {"Quítale el sigilo de Krasus a la vinculahechizos Maryana en la Forja de Maná Coruu, al noroeste de la Torre Violeta."}},
[10189] = {"Forja de Maná B'naar", {"El maestro de espías Thalodien del Área 52 quiere que te dirijas a las afueras de la Forja de Maná B'naar y recuperes lista de personal de B'naar del capitán Arathyn.","","A medida que completas misiones para los Arúspices disminuye tu nivel de reputación con los Aldor."}},
[10190] = {"Recargando las baterías", {"Usa la carga reponbatería en suficientes cazadores de fase para que el nivel de carga suba a 10. Regresa entonces junto a la especialista en robots Alley, en las Ruinas de Enkaat, en Tormenta Abisal."}},
[10191] = {"¡Mark V está vivo!", {"Escolta el Maxx Y. Millón nº. V a través de las Ruinas de Enkaat y llévalo hasta un lugar seguro. Después habla con la especialista en robots Alley, en las afueras de las Ruinas de Enkaat en Tormenta Abisal."}},
[10192] = {"El Compendio de Krasus", {"Recoge el Compendio de Krasus - Capítulo 1, el Compendio de Krasus - Capítulo 2 y el Compendio de Krasus - Capítulo 3 de la plaza del Poblado Kirin'Var."}},
[10193] = {"Objetivos de gran valor", {"El maestro de espías Thalodien del Área 52 quiere que te dirijas a las afueras de la Forja de Maná B'naar y mates 2 maestros de distorsión Furia del Sol, 6 ingenieros de distorsión Furia del Sol y 8 geólogos Furia del Sol.","","Completar misiones para los Arúspices hará que disminuya tu reputación con los Aldor."}},
[10194] = {"Vuelo sigiloso", {"Habla con Veronia fuera del Área 52 y vuela hasta Forja de Maná Coruu.","","Completar misiones para los Arúspices hará que disminuya tu reputación con los Aldor."}},
[10195] = {"Sombrero veo, sombrero quiero", nil},
[10196] = {"Más plumas de arakkoa", {"Lleva 30 plumas de arakkoa a Malukaz en el Bastión Rompepedras."}},
[10197] = {"Un disfraz convincente", {"Consigue las togas de arcanista Furia del Sol, un par de guantes de investigador Furia del Sol y un medallón de custodio Furia del Sol y entrégaselos a Caledis Alba Brillante, en Forja de Maná Coruu de Tormenta Abisal.","","Completar misiones para los Arúspices hará que disminuya tu reputación con los Aldor."}},
[10198] = {"Reuniendo pistas", {"Use el disfraz de Furia del Sol, ve a la Forja de Maná Coruu y escucha la conversación entre el comandante Forjalba y el arcanista Ardonis. Informa de todo a Caledis Alba Brillante en la Forja de Maná Coruu después de completar esta tarea.","","A medida que completas tareas para los Arúspices disminuye tu nivel de reputación Aldor."}},
[10199] = {"Ese pequeño toque extra", {"Consigue 5 aguijones de rayas abisales para Botas en el Área 52 de Tormenta Abisal."}},
[10200] = {"Regresa junto a Thalodien", {"Ve a ver al maestro de espías Thalodien en el Área 52, en la Tormenta Abisal."}},
[10201] = {"Y ahora, el momento de la verdad", {"Encuentra a Grek y pídele que pruebe el aceite en su arma. Cuando lo haya hecho, vuelve a ver a Rakoria con los resultados."}},
[10202] = {"Un desertor", {"Ve a la Forja de Maná Ara y habla con el magister Theledorn.","","Completar misiones para los Arúspices hará que disminuya tu nivel de reputación con los Aldor."}},
[10203] = {"El ultra-desconsolidador es muy útil", {"Utiliza el transportador ultra-desconsolidador para enviar al Área 52 la excavamática hiperrotacional, el cangilón de arrastre servoneumático, el analizador de terreno multiespectro y el vagón grande lleno de explosivos. A continuación preséntate ante el jefe de zapadores Estampido en la fisura del Área 52 en la Tormenta Abisal."}},
[10204] = {"Cristales de gema de sangre", {"La magistrix Larynna quiere que vayas a la Forja de Maná B'naar y obtengas un fragmento de gema de sangre de un magister Furia del Sol. Utiliza el fragmento cerca de los cristales grandes de gema de sangre y ve a verla en el Área 52.","","Completar misiones para los Arúspices hará que tu nivel de reputación con los Aldor disminuya."}},
[10205] = {"Asaltante de distorsión Nesaad", {"Mata al asaltante de distorsión Nesaad y ve a ver al acechador abisal Khay'ji al Área 52 en Tormenta Abisal."}},
[10206] = {"Tú eliges", {"Reúne 10 artilugios de tecnología etérea y llévaselos a Papá Ruedas en el Área 52, en la Tormenta Abisal."}},
[10207] = {"Forward Base: Reaver's Fall REUSE", nil},
[10208] = {"Perturbar sus refuerzos", {"Derrota a enemigos alrededor del Portal Xilus y del Portal Kruul para recolectar piedras rúnicas demoníacas.","","Usa el cebo explosivo de To'arch del Portal Xilus y del Portal Kruul.","","Regresa junto a To'arch con los cebos de To'arch en la Caída del Atracador Vil, en la Península del Fuego Infernal."}},
[10209] = {"El premio del invocador Kanthin", {"Derrota al invocador Kanthin en la Forja de Maná Duro, en la isla que está al norte del Bastión Furia del Sol y reclama la Piedra de Glacius."}},
[10210] = {"A'dal", {"Habla con A'dal, el jefe de los Sha'tar, en el centro del Bancal de la Luz."}},
[10211] = {"La Ciudad de la Luz", {"Sigue al sirviente de Khadgar y escucha la historia de la ciudad. Luego ve a ver a Khadgar."}},
[10212] = {"Héroe Mag'har", {"Ve a ver a Abuela Geyah a Garadar en Nagrand.|n"}},
[10213] = {"Investigar el accidente", {"Busca supervivientes en el lugar del accidente."}},
[10214] = {"Esta mina es un caos", {"Mata 15 zapadores Gan'arg y ve a ver al supervisor Razelcraz."}},
[10216] = {"La seguridad es prioritaria", {"El artificiero Morphalius quiere que mates 10 asaltantes de tumbas etéreos, 5 brujas etéreas, 5 acechadores nexo y 5 vinculahechizos etéreos.","","Cuando lo hayas conseguido, encuentra el transportador etéreo en la cámara anterior a la de Shaffar y actívalo."}},
[10218] = {"El trabajo duro de alguien más nos beneficia", {"Escolta al crioingeniero Sha'heen a través de las Tumbas de Maná para que pueda recoger el éter que está dentro de los recolectores de Shaffar.","","Preséntate ante el príncipe-nexo Haramad en las Tumbas de Maná, en el campamento del Consorcio si tienes éxito."}},
[10219] = {"Pasear al perro", nil},
[10220] = {"Oblígales a escuchar", {"Mordiba quiere que derrotes a 12 lacayos Implacables, 8 caballeros Implacables y 6 hechiceros Implacables en la Armería de Expedición, al oeste de la Avanzada Rompeloma."}},
[10221] = {"¡Dr. Bum!", {"Mata al Dr. Bum y ve a darle la buena noticia al jefe de zapadores Estampido al Área 52 en Tormenta Abisal."}},
[10222] = {"El cuartel Furia del Sol", {"El custodio Valemuerte en el Poblado Kirin'Var quiere que mates 10 arqueros Furia del Sol."}},
[10223] = {"Abajo con Daellis", {"El custodio Valemuerte, en el Poblado Kirin'Var quiere que mates al maestro Daellis Golpe del Amanecer."}},
[10224] = {"Esencia para los motores", {"Reúne 7 esencias de ánima de maná y regresa junto al ingeniero jefe Trep en el Área 52, en Tormenta Abisal."}},
[10225] = {"Informe para lngeniería", {"Entrégale los cristales de la matriz de eterlitio al ingeniero jefe Trep en el Área 52, en Tormenta Abisal."}},
[10226] = {"Extracción de energía elemental", {"Extrae 5 unidades de energía elemental para el ingeniero jefe Trep en el Área 52, en la Tormenta Abisal."}},
[10227] = {"Veo draenei muertos", {"Habla con Ramdor el Loco junto a la pila de huesos fuera de las Criptas Auchenai."}},
[10228] = {"Ezekiel", {"Busca a Ezekiel de Shattrath en Ciudad de Shattrath."}},
[10229] = {"Descifrar el escrito", {"Lleva el escrito misterioso a Althen, el historiador de la Avanzada Rompeloma."}},
[10230] = {"El cuerno de batalla", {"Toma el cuerno de batalla Implacable del comandante Thalvos y llévaselo Althen, el historiador de la Avanzada Rompeloma."}},
[10231] = {"¿Libro? Yo no veo ninguno", {"Ezekiel dijo que habían robado el libro Será mejor que encuentres a esos rufianes y veas si ellos tienen alguna información.|n"}},
[10232] = {"Movida con la Legión", {"Mata 5 forjadestinos Mo'arg y 15 ingenieros Gan'arg. Después, vuelve a hablar con Papá Ruedas en el Área 52, en Tormenta Abisal."}},
[10233] = {"Fuego en el Bastión Furia del Sol", {"Con una antorcha llameante, acaba con 4 balistas Furia del Sol y 4 tiendas Furia del Sol y regresa junto al teniente hechicero Morran en el Poblado Kirin'Var."}},
[10234] = {"Basura del demonio...", {"Consigue 10 piezas de atracador vil y llévaselas a Mamá Ruedas en el Puesto de la Tierra Media dentro del Ecodomo de la Tierra Media, en la Tormenta Abisal."}},
[10235] = {"Deszarpar a Zarpaletal", {"Consigue la Mano de Zarpaletal y entrégasela a Mamá Ruedas en el Puesto de la Tierra Media, en el Ecodomo de la Tierra Media, en la Tormenta Abisal."}},
[10236] = {"¡Terrallende es un asco!", {"Encuentra 6 piezas de trituradora y regresa junto al supervisor Razelcraz en la mina al noroeste de Thrallmar."}},
[10237] = {"¡Avisa al Área 52!", {"Entrega el manual de construcción de atracadores viles y lleva las malas noticias al jefe de cohetes Fuselaje en el Área 52, en la Tormenta Abisal."}},
[10238] = {"Cómo servir a los goblins", {"Rescata a Manni, Moh y Jakk de los campamentos de los orcos viles y regresa junto al supervisor Razelcraz en la mina al noroeste de Thrallmar."}},
[10239] = {"Fuente de energía potencial", {"El teniente hechicero Morran en el Poblado Kirin'Var quiere que captures 10 cubos de aislamiento de energía de los elfos de sangre en la Forja de Maná Coruu."}},
[10240] = {"Construyendo un perímetro", {"Utiliza el aparato de activación de runa cerca de la runa del este, la runa del noroeste y la runa del oeste. Puedes encontrar las runas alrededor del perímetro del Pasaje del Zahorí y la Plaza de la Ciudad del Poblado Kirin'Var. Ve a ver al teniente hechicero Morran cuando hayas completado la tarea."}},
[10241] = {"Distracción en la Forja de Maná B'naar", {"Mata 8 magistri Furia del Sol y 8 depositarios de sangre Furia del Sol. Después vuelve a ver al exarca Orelis en el Área 52.","","Completar misiones para los Aldor hará que disminuya tu nivel de reputación con los Arúspices."}},
[10242] = {"La Avanzada Rompeloma", {"La boticaria Zelana en la Caída del Atracador Vil, quiere que hables con el comandante del aire Brack para tomar un dracoleón hasta la Avanzada Rompeloma y llevar la muestra de sangre Foso Sangrante al boticario Albreck en la Avanzada Rompeloma."}},
[10243] = {"Tecnología naaru", {"Entra en la Forja de Maná B'naar y encuentra la consola de control B'naar.","","Completar misiones para los Aldor hará que disminuya tu nivel de reputación con los Arúspices."}},
[10244] = {"R.T.F.R.C.M.", {"Lleva el manual de construcción de atracadores viles a Mamá Ruedas en el Puesto de la Tierra Media, dentro del Ecodomo de la Tierra Media, en la Tormenta Abisal."}},
[10245] = {"Trascripción de la consola de B'naar", {"Entrega la trascripción de consola B'naar a la Anacoreta Karja del Área 52, en Tormenta Abisal.","","Completar misiones para los Aldor hará que disminuya tu nivel de reputación con los Arúspices."}},
[10246] = {"Ataque a la Forja de Maná Coruu", {"Ve a la Forja de Maná Coruu y mata 8 arcanistas Furia del Sol y 5 investigadores Furia del Sol. Vuelve a hablar con el exarca Orelis cuando hayas cumplido esta misión.","","Completar misiones para los Aldor hará que disminuya tu nivel de reputación con los Arúspices."}},
[10247] = {"Doctor Vomisa, Ph.T.", {"Entrega el manual de construcción de atracadores viles al doctor Vomisa Ph.T. en el terreno de pruebas, en la Tormenta Abisal."}},
[10248] = {"Tú, Robot", {"Activa el Atracador desguazador X6000 y prueba todas sus funciones. Después informa al doctor Vomisa, Ph.T en el Terreno de Pruebas de Tormenta Abisal. Encárgate de cualquier problema que pueda surgir."}},
[10249] = {"¡El jefe de nuevo!", {"Preséntate inmediatamente ante el jefe de cohetes Fuselaje en el Área 52, en la Tormenta Abisal."}},
[10250] = {"Venganza sangrienta", {"Haz que suene el cuerno de batalla Implacable cerca del estandarte de la Alianza. Mata a Urtrak y vuelve a hablar con Althen el historiador en la Avanzada Rompeloma."}},
[10251] = {"¿La obra maestra del maestro?", {"Encuentra a Nitrin el Erudito en la Armería Abandonada, en Nagrand."}},
[10252] = {"Visión de los muertos", {"Nitrin, en la Armería Abandonada, en Nagrand, quiere que le lleves 1 globo ocular de gronn montés, 1 pico de vientorroc superior perfecto y 1 grasa de uñagrieta envejecido."}},
[10253] = {"Levixus el Invocador de Almas", {"Destruye a Levixus y toma el libro de los muertos.","","Entrega el libro de los muertos a Ramdor el Loco fuera de las Criptas Auchenai, en la entrada de Auchindoun.","","Tenías un trato, ¿lo recuerdas?"}},
[10254] = {"Comandante en jefe Danath", {"El mariscal Isildor quiere que te presentes ante el comandante en jefe Danath Aterratrols en el Bastión del Honor."}},
[10255] = {"Pruebas de antídoto", {"Usa el antídoto Cenarion sobre un jabinferno descomunal y observa sus efectos. Cuando tengas los resultados del experimento, regresa junto a Thiah Melenarroja del Puesto Cenarion, en la Península del Fuego Infernal."}},
[10256] = {"Buscando a la Maestra de llaves", {"Encuentra a Cumbre y quítale un foco de cristal de Cumbre. Ve a la Torre Violeta y úsalo cerca del orbe del archimago Vargoth para descubrir quién tiene la llave para romper la maldición de la torre."}},
[10257] = {"La piedra angular", {"Adéntrate en El Invernáculo de El Castillo de la Tempestad y recupera la piedra angular de la comandante Sarannis. Llévasela al archimago Vargoth en la Torre Violeta."}},
[10258] = {"Honrar a los caídos", {"Preséntate al comandante Hogarth en la Armería de Expedición."}},
[10259] = {"Abriendo brecha", {"Mata 6 guardias viles incursores e informa al emisario Argenta Pozobravo."}},
[10260] = {"Abisólogo Nicuproso", {"Habla con el abisólogo Nicuproso en el puente a Tormenta Abisal desde Filospada."}},
[10261] = {"Se busca: Servoaniquilador", {"Consigue un servoaniquilador y entrégaselo a Papá Ruedas en el Área 52 en Tormenta Abisal."}},
[10262] = {"Un montón de etéreos", {"Recoge 10 insignias de Zaxxis y llévaselas al acechador abisal Khay'ji al Área 52 en Tormenta Abisal."}},
[10263] = {"Ayudar al Consorcio", {"Habla con el acechador abisal Khay'ji del Área 52, en la Tormenta Abisal."}},
[10264] = {"Ayudar al Consorcio", {"Habla con el acechador abisal Khay'ji del Área 52, en la Tormenta Abisal."}},
[10265] = {"Colección de cristales de El Consorcio", {"Consigue un artefacto de cristal de Arklon y llévaselo al acechador abisal Khay'ji al Área 52 en Tormenta Abisal."}},
[10266] = {"Petición de ayuda", {"Busca a Gahruj y ofrécele tus servicios. Se encuentra en el Puesto de la Tierra Media, en el Ecodomo de la Tierra Media de Tormenta Abisal."}},
[10267] = {"Legítima recuperación", {"Recoge 10 cajas de equipo de análisis y llévaselas a Gahruj al Puesto de la Tierra Media, en el Ecodomo de la Tierra Media, en Tormenta Abisal."}},
[10268] = {"Una audiencia con el príncipe", {"Entrega el equipo de análisis a la Imagen del príncipe-nexo Haramad en La Flecha de la Tormenta, en Tormenta Abisal."}},
[10269] = {"Punto de triangulación uno", {"Usa el aparato de triangulación para localizar el primer punto de triangulación. Informa de su ubicación al tratante Hazzin en la Avanzada del Protectorado en la isla de la Forja de Maná Ultris en Tormenta Abisal."}},
[10270] = {"Proposición poco decente", {"Recupera el envase de energía de teletransportador y llévalo a la plataforma de teletransporte etérea en la Cresta Celestial, al este de la Forja de Maná Ultris. Activa la plataforma y dale la fuente de energía a la imagen del comerciante de viento Marid para que la instale."}},
[10271] = {"A trabajar", {"Recolecta 8 esencias de dragón abisal y vuelve a la plataforma de teletransporte etérea. Puedes obtener la esencia de dracos abisales o de dragones abisales."}},
[10272] = {"Un buen comienzo", {"Recolecta 15 huevos de dragonante abisal y llévaselos a Tyri y Jorad a la Cresta Celestial."}},
[10273] = {"Problemas a la vista", {"Habla con el comerciante de viento Marid y aléjalo de su tienda. Ocúpate de él y ve a ver a Tyri y Jorad a la Cresta Celestial."}},
[10274] = {"Proteger la Cresta Celestial", {"Usa el desafío del Vuelo Azul para provocar a Veraku en el extremo sur de Cresta Celestial. Derrótalo y ve a ver a Tyri y Jorad a Cresta Celestial."}},
[10275] = {"Punto de triangulación dos", {"Usa el aparato de triangulación para localizar el segundo punto de triangulación. Informa al comerciante de viento Tuluman en Alto de Tuluman, justo al cruzar el puente de la isla de Forja de Maná Ara en Tormenta Abisal."}},
[10276] = {"Triángulo completo", {"Recupera el cristal de Ata'mal y dáselo a la imagen del príncipe-nexo Haramad en La Flecha de la Tormenta, en Tormenta Abisal."}},
[10277] = {"Las Cavernas del Tiempo", {"Andormu de las Cavernas del Tiempo quiere que sigas a la custodia del Tiempo."}},
[10278] = {"Las fallas de distorsión", {"Usa el generador de fallas de distorsión inestable en Los Campos Alabeados. Recoge 3 abismos de distorsión de abisarios inestables y llévaselos a Ogath el Loco a la Avanzada Rompeloma."}},
[10279] = {"La caverna del maestro", {"Habla con Andormu en las Cavernas del Tiempo."}},
[10280] = {"Una entrega especial a la Ciudad de Shattrath", {"Entrega el cristal de Ata'mal a A'dal en el Bancal de la Luz en la Ciudad de Shattrath."}},
[10281] = {"Presentaciones formales", {"Encuentra a Tyri en el extremo norte de Cresta Celestial."}},
[10282] = {"Antigua Trabalomas", {"Andormu de las Cavernas del Tiempo quiere que vayas a la Antigua Trabalomas para hablar con Erozion."}},
[10283] = {"La maniobra de Taretha", {"Ve al Castillo de Durnholde y coloca 5 cargas incendiarias del paquete de bombas incendiarias que te dio Erozion en los barriles que hay en cada pabellón de internamiento.","","Después habla con Thrall en la prisión subterránea del castillo."}},
[10284] = {"Huida de Durnholde", {"Cuando estés listo para proceder, díselo a Thrall. Sigue a Thrall al exterior del Castillo de Durnholde y ayúdale a liberar a Taretha y así cumplir su destino.","","Habla con Erozion en Antigua Trabalomas cuando completes esta tarea."}},
[10285] = {"Regresa junto a Andormu", {"Regresa junto al niño, Andormu, en las Cavernas del Tiempo, en el Desierto de Tanaris."}},
[10286] = {"El secreto de Arelion", {"La magistrix Carinda quiere que interrogues al magister Aledis, que salió de la Avanzada del Halcón en dirección a la Marisma de Zangar."}},
[10287] = {"Amante descubierta", {"Ve a ver a la magistrix Carinda a la Avanzada del Halcón en la Península del Fuego Infernal."}},
[10288] = {"Llegada a Terrallende", {"El comandante Duron de El Portal Oscuro en la Península del Fuego Infernal quiere que entregues su informe a Amish Martillo Salvaje."}},
[10289] = {"Viaje a Thrallmar", {"Lleva el jinete del viento de Vlagga Plumacalma a Thrallmar. Entrega el informe de Orion al general Krakork."}},
[10290] = {"Buscando faralita", {"Recolecta 4 piezas de faralita en bruto y llévaselas a Zuben Elgenubi a La Flecha de la Tormenta."}},
[10291] = {"Informar a Nazgrel", {"El general Krakork en Thrallmar quiere que hables con Nazgrel."}},
[10292] = {"¡Más potencia!", {"Zuben Elgenubi quiere que captures 8 cañones de la Legión y se los lleves a La Flecha de la Tormenta."}},
[10293] = {"A por la veta", {"Zuben Elgenubi de La Flecha de la Tormenta quiere que le lleves un núcleo de faralita."}},
[10294] = {"La Cresta del Vacío", {"Ve a la Cresta del Vacío y mata las criaturas que encuentres. Recolecta 40 fragmentos de alma de la Cresta del Vacío y llévaselos a Ogath el Loco, en la Avanzada Rompeloma."}},
[10295] = {"Desde el abismo", {"Mata al barón del vacío Galaxis y recolecta un fragmento de su alma. Llévale el fragmento a Ogath el Loco en la Avanzada Rompeloma."}},
[10296] = {"La Ciénaga Negra", {"Viaja por las Cavernas del Tiempo hasta la Ciénaga Negra mientras esté abierto El Portal Oscuro y habla con Sa'at."}},
[10297] = {"La apertura de El Portal Oscuro", {"Sa'at en la Ciénaga Negra de las Cavernas del Tiempo te ha encargado que defiendas a Medivh hasta que consiga abrir El Portal Oscuro.","","Vuelve junto a Sa'at si consigues completar esta tarea."}},
[10298] = {"Adalid del linaje", {"Regresa junto al niño, Andormu, en las Cavernas del Tiempo, en el Desierto de Tanaris."}},
[10299] = {"El cierre de la Forja de Maná B'naar", {"Vuelve a la Forja de Maná B'naar para obtener un cristal de acceso del sobrestante Theredis. Úsalo en la consola de la Forja de Maná B'naar para cerrarla y ve a informar a la Anacoreta Karja.","","Completar misiones para los Aldor hará que disminuya tu nivel de reputación con los Arúspices."}},
[10300] = {"Reconstrucción del bastón", {"Consigue 4 fragmentos de cristal perfectos de los fantasmas de las Ruinas de Enkaat y llévaselos a Ravandwyr en el Área 52."}},
[10301] = {"Abrir el Compendio", {"Consigue el óculo de heliotropo de la atracahechizos Marathelle en el Bastión Furia del Sol."}},
[10302] = {"Mutaciones volátiles", {"Mata 8 mutaciones volátiles y ve a ver a la botánica Taerix al Lugar del Accidente en el Valle Ammen."}},
[10303] = {"Los elfos de sangre", {"Mata a 10 exploradores elfos de sangre y ve a ver a Tolaan a la Cresta de las Sombras en el Valle Ammen."}},
[10304] = {"El vindicador Aldar", {"Habla con el vindicador Aldar en el Lugar del Accidente en el Valle Ammen."}},
[10305] = {"Abjuradora Belmara", {"Encuentra las dependencias de la abjuradora Belmara en el Pasaje del Zahorí y devuelve el libro a la estantería. A continuación, habla con el custodio Valemuerte en el Poblado Kirin'Var."}},
[10306] = {"Conjurador Luminrath", {"Encuentra las dependencias del conjurador Luminrath, en el Pasaje del Zahorí y devuelve la capa a su vestidor. A continuación, habla con el custodio Valemuerte en el Poblado Kirin'Var."}},
[10307] = {"Cohlien Tejescarcha", {"Encuentra las dependencias de Cohlien Tejescarcha, en el Pasaje del Zahorí y devuelve el sombrero a su baúl. A continuación, habla con el custodio Valemuerte en el Poblado Kirin'Var."}},
[10308] = {"Otro montón de etéreos", nil},
[10309] = {"Es un atracador vil... pero con corazón", {"Recupera el corazón del atracador vil y entrégaselo a N. D. Malcampo en La Pila, en Tormenta Abisal."}},
[10310] = {"¡Sabotead el portal de distorsión!", {"Escolta a Drijya hasta el portal de distorsión en el Punto de Invasión: Destructor, y cúbrelo mientras intenta sabotearlo. Después habla con Gahruj en el Puesto de la Tierra Media dentro del Ecodomo de la Tierra Media en Tormenta Abisal."}},
[10311] = {"Drijya necesita tu ayuda", {"Habla con Drijya cerca del Punto de Invasión: Destructor en Tormenta Abisal."}},
[10312] = {"Las Crónicas de Kirin'Var", {"Recupera las Crónicas de Kirin'Var en el ayuntamiento del Poblado Kirin'Var y llévaselas al custodio Valemuerte."}},
[10313] = {"Medir energías de distorsión", {"El exarca Orelis del Área 52 quiere que te lleves el orbe armonizado con la distorsión a la Forja de Maná B'naar y lo uses al final de sus 4 tuberías.","","Completar misiones para los Aldor hará que disminuya tu nivel de reputación con los Arúspices."}},
[10314] = {"Una sospecha latente", {"Consigue 10 restos repugnantes de los espíritus malignos del Patio de la Capilla del Poblado Kirin'Var y llévaselos al custodio Valemuerte."}},
[10315] = {"Neutralizar a los abisálicos", {"Mata a 15 abisálicos Furia del Sol y ve a ver al acechador abisal Oazul al Alto de Tuluman en Tormenta Abisal."}},
[10316] = {"En busca de pruebas", {"Busca pistas sobre el responsable de la manipulación de los espíritus en el Patio de la Capilla del Poblado Kirin'Var."}},
[10317] = {"Tratar con el supervisor", {"Encárgate del supervisor Ocaso en la Mina Trelleum, que está bajo la Forja de Maná Ara en Tormenta Abisal."}},
[10318] = {"Conversaciones con el maestro Supremo", {"Mata al maestro supremo Yugogarr. A continuación ve a ver al comerciante de viento Tuluman en el Alto de Tuluman, en la Tormenta Abisal."}},
[10319] = {"Captura de la filacteria", {"Recupera la filacteria de Naberius en el Patio de la Capilla del Poblado Kirin'Var y llévasela al custodio Valemuerte."}},
[10320] = {"¡Destruir a Naberius!", {"El custodio Valemuerte, en el Poblado Kirin'Var quiere que derrotes a Naberius en el Patio de la Capilla del poblado."}},
[10321] = {"El cierre de la Forja de Maná Coruu", {"Ve a la Forja de Maná Coruu, al este del Área 52, y obtén el cristal de acceso de Coruu del sobrestante Seylanna. Úsalo en la consola de Forja de Maná Coruu para desactivarla y vuelve a hablar con la Anacoreta Karja.","","Completar misiones para los Aldor hará que disminuya tu nivel de reputación con los Arúspices."}},
[10322] = {"El cierre de la Forja de Maná Duro", {"La Anacoreta Karja quiere que vayas a la Forja de Maná Duro y consigas el cristal de acceso del sobrestante Athanel. Utilízalo en la consola de la Forja de Maná Duro para desactivarla.","","Completar misiones para los Aldor hará que disminuya tu nivel de reputación con los Arúspices."}},
[10323] = {"El cierre de la Forja de Maná Ara", {"Ve a la Forja de Maná Ara y obtén el cristal de acceso de Ara del sobrestante Azarad. Úsalo en la consola de Forja de Maná Ara para desactivarla.","","Completar misiones para los Aldor hará que disminuya tu nivel de reputación con los Arúspices."}},
[10324] = {"La gran cacería lunar", {"Lleva 6 pieles de ciervos lunares a Acteon a la Avanzada Azur."}},
[10325] = {"Marcas de Kil'jaeden", {"Lleva 10 marcas de Kil'jaeden a Adyen el Celador de la Luz en la Ciudad de Shattrath.","","Completar misiones para los Aldor hará que disminuya tu nivel de reputación con los Arúspices."}},
[10326] = {"Más marcas de Kil'jaeden", nil},
[10327] = {"Marca de Kil'jaeden única", nil},
[10328] = {"Informes Furia del Sol", {"Ve a la Forja de Maná Duro y consigue el informe militar de Furia del Sol y el informe Arcano de Furia del Sol de las unidades Furia del Sol allí asentadas. Ve a ver al exarca Orellis cuando hayas completado la tarea.","","Completar misiones para los Aldor hará que disminuya tu nivel de reputación con los Arúspices."}},
[10329] = {"El cierre de la Forja de Maná B'naar", {"Vuelve a la Forja de Maná B'naar y obtén el cristal de acceso de B'naar del sobrestante Theredis. Úsalo en la consola de control B'naar para desactivarla y vuelve a hablar con el maestro de espías Thalodien.","","Completar misiones para los Arúspices hará que disminuya tu nivel de reputación con los Aldor."}},
[10330] = {"El cierre de la Forja de Maná Coruu", {"Consigue el cristal de acceso de Coruu del sobrestante Seylanna. Utilízalo en la consola de control Coruu para cerrar la Forja de Maná y ve a hablar con Caledis Alba Brillante..","","Completar misiones para los Arúspices hará que disminuya tu nivel de reputación con los Aldor."}},
[10331] = {"Herramienta indispensable", {"Busca el martillo de herrería que tienen los aprendices de Kirin'Var y llévaselo al aprendiz Andrethan al Poblado Kirin'Var."}},
[10332] = {"El herrero maestro Rhonsus", {"El aprendiz Andrethan en el Poblado Kirin'Var quiere que mates al fantasma de Rhonsus, el herrero maestro del poblado."}},
[10333] = {"Ayuda a Mamá Ruedas", {"Habla con Mamá Ruedas en el Puesto de la Tierra Media dentro del Ecodomo de la Tierra Media de Tormenta Abisal."}},
[10334] = {"Necesita un cencerro", {"Encuentra a Bessy en los campos cerca de la Colina de la Capilla del Poblado Kirin'Var en Tormenta Abisal."}},
[10335] = {"Inspeccionar las ruinas", {"Coloca los tres marcadores de reconocimiento y vuelve a ver a Zephyrion en La Flecha de la Tormenta, en la Tormenta Abisal."}},
[10336] = {"Los esbirros de Culuthas", {"Mata 10 canes de Culuthas y 5 ojos de Culuthas. Después ve a ver al acechador abisal Nauthis en La Flecha de la Tormenta, en la Tormenta Abisal."}},
[10337] = {"Cuando las vacas vuelven a casa", {"Escolta a Bessy de vuelta con su dueño, Thadell."}},
[10338] = {"El cierre de la Forja de Maná Duro", {"Vuelve a la Forja de Maná Duro y obtén el cristal de acceso de Duro del sobrestante Athanel. Úsalo en la consola de control de Duro para desactivarla y vuelve a hablar con el maestro de espías Thalodien.","","Completar misiones para los Arúspices hará que disminuya tu nivel de reputación con los Aldor."}},
[10339] = {"El Etereum", {"El comandante Ameer quiere que mates a 5 asesinos de El Etereum, 5 soldados de choque de El Etereum, 2 investigadores de El Etereum y al capitán Zovax y que, a continuación, actives el transpondedor de El Etereum Zeta."}},
[10340] = {"Puesto Devastación", {"El comandante de vanguardia Kingston quiere que hables con el comandante del aire Dabir'ee, vayas en grifo a Puesto Devastación y te presentes ante Runetog Martillo Salvaje."}},
[10341] = {"A por ellos cuando no se pueden defender", {"Mata 8 conjuradores Furia del Sol, 6 asaeteadores Furia del Sol y 4 centuriones Furia del Sol. Vuelve a ver a la magistrix Larynna en el Área 52 cuando hayas completado la tarea.","","Completar tareas para los Arúspices hará que disminuya tu nivel de reputación con los Aldor."}},
[10342] = {"Asegurar los esquistos Piel de esquisto", {"Recolecta 5 esquistos Piel de esquisto y llévaselos a Botas del Área 52, en la Tormenta Abisal."}},
[10343] = {"La invasión interminable", {"Busca en la zona del Poblado Kirin'Var infestada de criaturas de maná un trozo de bomba de maná y llévasela al teniente hechicero Morran."}},
[10344] = {"Comandante del aire Grifongar", {"Habla con el comandante del aire Grifongar en el Puesto Devastación."}},
[10345] = {"La carne sí engaña", {"Usa el encendedor del Protectorado en 12 cadáveres marchitos y devuélveselo al agente Araxes fuera del Eje de Acceso Zeon cuando hayas acabado.|n"}},
[10346] = {"Regresa a La Plataforma Abisal", {"La grifonera Bramavientos, en el Puesto Devastación, en la Península del Fuego Infernal, te ha pedido que destruyas 20 peones de Gan'arg, 5 sobrestantes Mo'arg y 5 cañones viles."}},
[10347] = {"Regresa a La Plataforma Abisal", {"El comandante del aire Brack, en la Caída del Atracador Vil, en la Península del Fuego Infernal, te ha pedido que destruyas 20 peones de Gan'arg, 5 sobrestantes Mo'arg y 5 cañones viles."}},
[10348] = {"Nuevas oportunidades", {"Recupera 15 campanas de marfil y regresa junto a Mehrdad en el Puesto de la Tierra Media."}},
[10349] = {"La Vinculadora terrestre", {"Lleva el fragmento de cristal carmesí a la Vinculadora terrestre Galandria Brisa Nocturna en el Puesto Cenarion en la Península del Fuego Infernal."}},
[10350] = {"Maestro Behomat", {"Habla con Behomat en La Grada de los Mercaderes de El Exodar."}},
[10351] = {"Remedios naturales", {"Usa la semilla de revitalización en el Círculo de los Vinculadores terrestres para sanar la tierra alrededor del cristal. Después ve a informar a la Vinculadora terrestre Galandria Brisa Nocturna al Puesto Cenarion en la Península del Fuego Infernal."}},
[10352] = {"Un donativo de lana", nil},
[10353] = {"Arconus el Insaciable", {"El agente Ya-six en el Eje de Acceso Zeon, en la Tormenta Abisal, te ha pedido que mates a Arconus el Insaciable y vayas a ver al comandante Ameer en la Avanzada del Protectorado, en la Tormenta Abisal."}},
[10354] = {"Un donativo de seda", nil},
[10355] = {"Carne marchita", {"Recolecta 5 muestras de hidra sedienta y 5 muestras de señor de la marisma marchito y llévaselas a Ruam a Telredor."}},
