[10365] = {"El cierre de la Forja de Maná Ara", {"Ve a la Forja de Maná Ara y consigue un cristal de acceso del sobrestante Valdrin. Utilízalo en la consola de la Forja de Maná Ara para cerrarla.","","Completar misiones para los Arúspices hará que disminuya tu nivel de reputación con Los Aldor."}},
[10366] = {"Jol", {"Habla con Jol en el Sagrario de los Vindicadores, en El Exodar."}},
[10367] = {"Un traidor entre nosotros", {"Naladu, en las Ruinas de Sha'naar, quiere que le consigas la llave Sha'naar de una choza próxima."}},
[10368] = {"Los ancianos Zarrapucha", {"Libera a Morod el Agitavientos, a Akoru el Clamafuegos y a Aylaan el Levantaguas en las Ruinas de Sha'naar. Regresa junto a Naladu cuando hayas completado esta tarea."}},
[10369] = {"La desaparición de Arzeth", {"Usa el bastón de los ancianos Zarrapucha sobre Arzeth el Despiadado y mátalo cuando haya perdido sus poderes. Regresa junto a Naladu, en las Ruinas de Sha'naar, cuando hayas completado esta tarea."}},
[10370] = {"El mando de Nazgrel <TXT>", nil},
[10371] = {"Yorus Cebadiz", {"Habla con Yorus Cebadiz en la posada de Villa del Lago en las Montañas Crestagrana."}},
[10372] = {"Una investigación discreta", {"Habla con Eralan en Tranquillien."}},
[10373] = {"Un llamamiento a las armas: las Tierras de la Peste", {"Busca al comandante Ashlam Puñovalor. Su campamento base se encuentra en Campamento del Orvallo, al norte de las Montañas de Alterac."}},
[10374] = {"Un llamamiento a las armas: las Tierras de la Peste", {"Busca al sumo ejecutor Derrington; su campamento base está en El Baluarte, al este de Claros de Tirisfal y Entrañas."}},
