[10381] = {"Se acabaron los Aldor", {"Informa de todo al exarca Orelis, en el Área 52.","","Completar misiones para los Aldor hará que disminuya tu nivel de reputación con los Arúspices."}},
[10382] = {"¡Ve al frente!", {"Toma un grifo para ir al Alto del Honor y habla con el mariscal de campo Brock."}},
[10383] = {"¡Migajas!", {"Habla con Jon L'Artesano sobre los conejos."}},
[10384] = {"Datos de El Etereum", {"La imagen del comandante Ameer, en el Punto de Escala de El Etereum: Transpondedor de El Etereum Zeta, quiere que recuperes la célula de datos de El Etereum."}},
[10385] = {"Potencial de daño cerebral = Alto", {"La imagen del comandante Ameer, en el Punto de Escala de El Etereum: Transpondedor de El Etereum Zeta, quiere que recuperes 15 piezas de los datos del repetidor de El Etereum."}},
