[10388] = {"Regresa a Thrallmar", {"Regresa a Thrallmar y habla con Nazgrel.|n"}},
[10389] = {"La agonía y la oscuridad", {"El magister Halcón de sangre quiere que mates a 10 terroadictos en las Pozas de Aggonar."}},
[10390] = {"Campamento Forja: Mageddon", {"Nazgrel, en Thrallmar, quiere que ataques el Campamento Forja: Mageddon, mates a 10 sirvientes Gan'arg y vuelvas con la cabeza de Navajafilada."}},
[10391] = {"Cañones de ira", {"Destruye 3 cañones viles MKI en el Campamento Forja: Ira y regresa junto a Nazgrel en Thrallmar."}},
[10392] = {"Una puerta hacia el abismo", {"Mata a Arix'Amal. Toma la llave de la puerta de la Legión Ardiente. Usa la llave de la puerta de la Legión Ardiente con la runa de maldad. Después vuelve a ver a Nazgrel en Thrallmar."}},
[10393] = {"Planes malvados", {"Lleva la misiva de la Legión Ardiente al magister Halcón de sangre en Thrallmar."}},
[10394] = {"Desbarajuste en el Campamento Forja: Mageddon", {"Mata a 10 sirvientes Gan'arg y a Navajafilada, en el Campamento Forja: Mageddon y regresa junto al mariscal de campo Brock en el Alto del Honor."}},
[10395] = {"La oscura misiva", {"Lleva la misiva al arúspice de distorsión Kryv en el fuerte principal del Bastión del Honor."}},
[10396] = {"Enemigo de mi enemigo...", {"Destruye 3 cañones viles MKl en el Campamento Forja: Ira y regresa después junto al mariscal de campo Brock en el Alto del Honor."}},
[10397] = {"Punto de invasión: Aniquilador", {"Mata a Arix'Amal. Toma la llave del portal de la Legión Ardiente. Usa la llave del portal de la Legión Ardiente con la runa de maldad."}},
[10398] = {"Regresa al Bastión del Honor", nil},
[10399] = {"El corazón de la oscuridad", {"Mata a 10 terroadictos en las Pozas de Aggonar y regresa junto al arúspice de distorsión Kryv en el fuerte principal del Bastión del Honor."}},
[10400] = {"Señor Supremo", {"Mata a Arazzius el Cruel en las Pozas de Aggonar y regresa junto al comandante en jefe Danath Aterratrols en el Bastión del Honor.|n"}},
[10401] = {"Misión: Acaba con todo, sé todo", nil},
[10402] = {"<TXT>", nil},
[10403] = {"Naladu", {"Busca a Naladu en las Ruinas de Sha'naar."}},
[10404] = {"Contra la Legión", {"El exarca Orelis del Área 52 quiere que vayas a la Base Forja: Olvido y a la Base Forja: Gehenna y mates a 12 peones forjadores Gan'arg, a 6 señores de la forja Mo'arg y a 6 encolerizadores.","","Completar misiones para los Aldor hará que disminuya tu nivel de reputación con los Arúspices."}},
[10405] = {"S-A-B-O-T-A-J-E", {"La imagen del comandante Ameer, en el Punto de Escala de El Etereum: Transpondedor de El Etereum Zeta, quiere que recuperes 1 vendaje de El Etereum preparado."}},
[10406] = {"Entregar el mensaje", {"La imagen del comandante Ameer, en el Punto de Escala de El Etereum: Transpondedor de El Etereum Zeta, quiere que escoltes al demoledor de protectorado a Forja de Maná Ultris y lo cubras mientras sabotea las tuberías."}},
[10407] = {"La sombra de Socrethar", {"La Anacoreta Karja del Área 52 quiere que recuperes la primera mitad de la piedra de Socrethar del maestro de forja Morug en la Base Forja: Olvido y la segunda mitad de la piedra de Socrethar de Silroth en la Base Forja: Gehenna.","","Completar misiones para los Aldor hará que disminuya tu nivel de reputación con los Arúspices."}},
[10408] = {"El rey-nexo Salhadaar", {"La imagen del comandante Ameer, en el Punto de Escala de El Etereum: Transpondedor de El Etereum Zeta, quiere que uses el perturbador de Protectorado para neutralizar los campos de fuerza de Salhadaar y destruir después al rey-nexo Salhadaar."}},
[10409] = {"Golpe mortal a la Legión", {"La suma sacerdotisa Ishanah quiere que vayas al teletransportador de la Legión del extremo noroeste de Tormenta Abisal y lo uses para teletransportarte al Trono de Socrethar. Una vez allí, derrota a Socrethar.","","Completar misiones para los Aldor hará que disminuya tu nivel de reputación con los Arúspices."}},
[10410] = {"La ayuda de Ishanah", {"Llévale la piedra de teletransporte de Socrethar a la suma sacerdotisa Ishanah del Santuario de Luz Inagotable, en el Alto Aldor de la Ciudad de Shattrath.","","Completar misiones para los Aldor hará que disminuya tu nivel de reputación con los Arúspices."}},
[10411] = {"¡Divino electrochoque!", {"El investigador Navuud, de la Avanzada del Protectorado en la Tormenta Abisal, ha pedido que destruyas 30 glóbulos de residuo del vacío y 30 glóbulos de lodo acuoso.|n"}},
[10412] = {"Sellos Ala de Fuego", {"La magistrix Fyalenn de la Ciudad de Shattrath quiere que le lleves 10 sellos Ala de Fuego.","","Completar misiones para los Arúspices hará que disminuya tu nivel de reputación con los Aldor."}},
[10413] = {"El horror de la contaminación", {"Llévale el vial de moco de horror de vacío al investigador Navuud, de la Avanzada del Protectorado en la Tormenta Abisal."}},
[10414] = {"Sello Ala de Fuego único", nil},
[10415] = {"Más sellos Ala de Fuego", nil},
[10416] = {"Síntesis de poder", {"Voren'thal el vidente de la Ciudad de Shattrath quiere que recuperes un escrito Arcano.","","A medida que completas tareas para los Arúspices disminuye tu nivel de reputación con los Aldor."}},
[10417] = {"¡Realizar un diagnóstico!", {"Recupera los resultados de diagnóstico y regresa junto a Mehrdad en el Puesto de la Tierra Media."}},
[10418] = {"Trato con los saboteadores", {"Mehrdad del Puesto de la Tierra Media quiere que mates 8 crocoliscos escamapúas."}},
[10419] = {"Escritos Arcanos", nil},
[10420] = {"La Luz purificadora", {"Llévale 1 pieza de armamento vil a Ishanah en la Ciudad de Shattrath.","","Completar misiones para los Aldor hará que disminuya tu nivel de reputación con los Arúspices."}},
[10421] = {"Armamento vil", nil},
[10422] = {"El capitán Tyralius", {"El tratante de carne Viridius de la Avanzada del Protectorado, en la Tormenta Abisal, te ha pedido que encuentres y liberes al capitán Tyralius.|n"}},
[10423] = {"Hacia La Flecha de la Tormenta", {"Habla con Ghabar en La Flecha de la Tormenta, en Tormenta Abisal."}},
[10424] = {"Diagnóstico: grave", {"Utiliza el aparato de diagnóstico cuando estés cerca del generador del Ecodomo Sutheron y lleva los resultados del diagnóstico a Ghabar en La Flecha de la Tormenta."}},
[10425] = {"Huida del punto de escala", {"Escolta al soldado de vanguardia del Protectorado capturado a la Avanzada del Protectorado, en la Tormenta Abisal."}},
[10426] = {"Flora de los Ecodomos", {"Utiliza el modulador de campo de energía en los azotadores Farahlon. Observa los resultados y ve a ver a Aurine Lunardiente en La Flecha de la Tormenta cuando hayas realizado 10 pruebas."}},
[10427] = {"Criaturas de los Ecodomos", {"Marca 12 talbuks para Aurine Lunardiente en La Flecha de la Tormenta. Puedes marcar soberanos talbulks o ciervas talbuks utilizando el marcador talbuk."}},
[10428] = {"El pescador desaparecido", {"Encuentra a Cowlen en el puerto sureste de la Isla Bruma de Plata, frente a la costa de Bruma Azur."}},
[10429] = {"Cuando la naturaleza va demasiado lejos", {"Aurine Lunardiente de La Flecha de la Tormenta quiere que le lleves un corazón de hidra descomunal."}},
[10430] = {"Probando el prototipo", {"Lleva el artefacto de reparación a Tashar en el Ecodomo Campolejano, en Tormenta Abisal."}},
[10431] = {"Ayuda externa", {"Ve al Alto de Tuluman, al norte del Área 52, y habla con Kaylaan.","","Completar misiones para los Aldor hará que disminuya tu nivel de reputación con los Arúspices."}},
[10432] = {"Pruebas condenatorias", {"Consigue 8 órdenes de Kael'thas de los demonios de la Forja de Maná Ara y llévaselas al maestro de espías Thalodien en el Área 52.","","Completar misiones para los Arúspices hará que disminuya tu nivel de reputación con los Aldor."}},
[10433] = {"Guardando las apariencias", {"Lleva diez pelambres de lince Rasgacolmillo a Shauly Poro, en el Puesto de la Tierra Media."}},
[10434] = {"El dúo dinámico", {"Habla con Audi la Aguja en la Flecha de la Tormenta, en Tormenta Abisal."}},
[10435] = {"Recuperar las mercancías", {"Audi la Aguja, de la Flecha de la Tormenta, quiere que le lleves diez segmentos de generador de domo."}},
[10436] = {"¡Todo despejado!", {"Tashar, destacado en el Ecodomo Campolejano, quiere que mates a 12 raptores dienteguadaña."}},
[10437] = {"Receta para la destrucción", {"El profesor Dabiri de la Avanzada del Protectorado en la Tormenta Abisal quiere que recuperes 8 trozos de Dimensius."}},
[10438] = {"En alas abisales", {"El profesor Dabiri de la Avanzada del Protectorado en la Tormenta Abisal quiere que uses el perturbador de fase cuando estés en el radio de alcance del conducto del vacío que se encuentra sobre Ultris. Suelta tantas descargas con el perturbador de fase como sea necesario hasta asegurar la aniquilación total. Las cargas del perturbador de fase alcanzarán directamente el conducto del vacío siempre que estés lo suficientemente cerca para usarlo.","","Si lo consigues, regresa junto al profesor Dabiri.|n"}},
[10439] = {"Dimensius el Devoratodo", {"El profesor Dabiri de la Avanzada del Protectorado, en la Tormenta Abisal, quiere que hables con el capitán Saeed, te unas a su ejército que irá a Forja de Maná Ultris ¡y mates a Dimensius el Devoratodo!"}},
[10440] = {"¡Éxito!", {"Regresa a La Flecha de la Tormenta, en Tormenta Abisal, y habla con Ghabar."}},
[10441] = {"Tráfico de mercancías", {"Habla con Aurine Lunardiente al final de La Flecha de la Tormenta en Tormenta Abisal."}},
[10442] = {"Ayudar al Puesto Cenarion", {"La halconera Drenna Ríobrisa desea que ofrezcas tus servicios a Thiah Melenarroja del Puesto Cenarion, en la Península del Fuego Infernal."}},
[10443] = {"Ayudar al Puesto Cenarion", {"Amaan el Sabio desea que ofrezcas tus servicios a Thiah Melenarroja del Puesto Cenarion, en la Península del Fuego Infernal."}},
[10444] = {"Informa en el Puesto Allerian", {"Jenai Susurrestelar quiere que informes al teniente Meridiano del Puesto Allerian en el Bosque de Terokkar."}},
[10445] = {"Los viales de la eternidad", {"Soridormi de las Cavernas del Tiempo quiere que recuperes los restos del vial de Vashj de Lady Vashj en la Reserva Colmillo Torcido, y los restos del vial de Kael de Kael'thas Caminante del Sol, en El Castillo de la Tempestad."}},
[10446] = {"El código final", {"El teniente Meridiano quiere que uses el código final para detonar la bomba de maná. Informa después a Jenai Susurrestelar del Bastión Allerian en el Bosque de Terokkar."}},
[10447] = {"El código final", {"La sargento Chawni quiere que uses el código final para desactivar la bomba de maná. A continuación preséntate ante Tooki en el Bastión Rompepedras, en el Bosque de Terokkar."}},
[10448] = {"Preséntate en el Campamento Rompepedras", {"Tooki quiere que hables con la sargento Chawni en el Campamento Rompepedras, en el Bosque de Terokkar."}},
[10449] = {"La boticaria Zelana", {"Vurtox Rompehachas de Thrallmar quiere que lleves muestras de sangre de Mascahuesos a la boticaria Zelana en la Caída del Atracador Vil."}},
[10450] = {"Sangre de Mascahuesos", {"Llévale 12 viales de sangre de Mascahuesos a Vurtok Rompehachas en Thrallmar."}},
[10451] = {"Huida de la Cisterna Cicatriz Espiral", {"Escolta a la ensalmadora de la tierra Wilda hasta salir de la Cisterna Cicatriz Espiral y después busca al ensalmador de la tierra Torlok en El Altar de Condenación que se encuentra en la parte oeste de las afueras de La Mano de Gul'dan."}},
