[10481] = {"Espíritus de aire iracundos", {"El ensalmador de la tierra Torlok de El Altar de Condenación, en el Valle Sombraluna, quiere que uses el Tótem de espíritus para capturar 10 almas aéreas."}},
[10482] = {"Orcos viles carroñeros", {"Mata a 20 orcos Mascahuesos y vuelve con Amadi al Bastión del Honor."}},
