[10484] = {"Dijes malditos", {"Lleva 12 dijes malditos al cabo Crestahierro, en la Punta de Expedición."}},
[10485] = {"Señor de la guerra del Foso Sangrante", {"Lleva la armadura destrozada del señor de la guerra Morkh al cabo Crestahierro, en la Punta de Expedición."}},
