[10487] = {"Polvo de los dracos", {"Reúne cuatro polvos de draco hada."}},
[10488] = {"Proteger a los nuestros", {"Usa el ungüento de Gor'drek en 5 de los lobos temibles del Señor del Trueno."}},
[10489] = {"Talar un antiguo árbol", {"Consigue el tronco de Manofirme Raizhonda."}},
[10490] = {"La llamada del agua", {"Habla con el clarividente Nobundo en La Sala de Cristal dentro de El Exodar, en la Isla Bruma Azur."}},
[10491] = {"La llamada del aire", {"Habla con el clarividente Nobundo en La Sala de Cristal dentro de El Exodar, en la Isla Bruma Azur."}},
[10492] = {"Una propuesta seria", {"Lleva 15 muestras de sangre de Cuna del Invierno, 20 piezas de oro y 1 par de ataduras de elementos a Deliana, en Forjaz."}},
[10493] = {"Una propuesta seria", {"Lleva 15 muestras de veneno de Silithus, 20 piezas de oro y 1 par de brazales Forjaluz a Mokvar, en Orgrimmar."}},
