[10801] = {"¡Es una trampa!", {"Lleva la trampa de fuego de dragón al comandante Haephus Muropiedra en Soto Eterno en las Montañas Filospada."}},
[10802] = {"Gorgrom el Comedragones", {"Consigue 3 Tótems repelentes de los ogros Peña'mok. Después, utiliza la trampa de Sablecrín en el altar de Gorgrom para invocar y matar a Gorgrom el Comedragones.","","Cuando esté muerto, coloca los 3 Tótems repelentes cerca de su cadáver."}},
[10803] = {"Carnicería en Peña'mok", {"Mata 5 toscos Peña'mok y 3 chamanes Peña'mok."}},
[10804] = {"Bondad", {"Mordenai, de los Campos del Ala Abisal, en el Valle Sombraluna, quiere que alimentes a ocho dracos Ala Abisal maduros."}},
[10805] = {"Masacre en la Guarida de Gruul", {"Mata 10 déspotas Aguja del Filo, 5 magos de batalla Aguja del Filo, 5 devastadores Aguja del Filo y a su líder, Fingrom."}},
[10806] = {"Enfrentamiento", {"Utiliza el sello de Sablecrín en el altar de Goc y mata a Goc."}},
[10807] = {"Los Tábidos Lengua de ceniza", {"Varen el Reivindicador quiere que vayas a las Ruinas de Baa'ri y mates a 3 tratantes Lengua de ceniza, 4 guerreros Lengua de ceniza y 6 chamanes Lengua de ceniza.","","Completar misiones para los Arúspices hará que disminuya tu nivel de reputación con los Aldor."}},
[10808] = {"Frustra los planes del Cónclave", {"Mata a los ritualistas del Cónclave Oscuro y usa el bastón de Parshah para acabar con el ritual de invocación del Cónclave Oscuro. Después, vuelve a Parshah, a los Campos de Magma."}},
[10809] = {"Se busca: Maestro de huargos Kruush", {"Mata al maestro de huargos Kruush y entrega su cabeza al capitán Aullaoscuro en Avanzada Rompeloma."}},
[10810] = {"La máscara dañada", {"Entrega la máscara dañada a O'Mally Pillazas en Soto Eterno, en las Montañas Filoespada."}},
[10811] = {"Buscar a Neltharaku", {"Busca a Nelthakaru, patrón de los dracos Ala Abisal."}},
[10812] = {"La máscara misteriosa", {"Lleva la máscara misteriosa al Señor Salvaje Antelarion en Soto Eterno, en las Montañas Filospada."}},
[10813] = {"Los ojos de Grillok", {"Usa el fragmento de Zezzak para capturar un ojo de Grillok y acércate a la caldera de Zezzak para extraerlo. Una vez que lo hayas sacado, devuélvele el fragmento a Zezzak."}},
[10814] = {"La historia de Neltharaku", {"Habla con Neltharaku y escucha su historia."}},
[10815] = {"El diario de Val'zareq: augurios de guerra", {"Localiza a Marcus Auralion, alto general de los Sha'tar en la Atalaya Carmesí."}},
[10816] = {"Reclamar los terrenos sagrados", {"El vindicador Aluumen quiere que mates 8 asesinos Sombraluna, 8 elegidos Sombraluna y 4 tejeoscuros Sombraluna.","","Completar misiones para los Aldor hará que disminuya tu nivel de reputación con los Arúspices."}},
[10817] = {"El gran castigo", {"Varen el Reivindicador quiere que mates 8 asesinos Sombraluna, 8 elegidos Sombraluna y 4 tejeoscuros Sombraluna.","","Completar misiones para los Arúspices hará que disminuya tu nivel de reputación con los Aldor."}},
[10818] = {"El barón Sablecrín ha solicitado tu presencia", {"Habla con el barón Sablecrín en el Anillo de Sangre, en las Montañas Filospada."}},
[10819] = {"La máscara de gas jurapenas", {"Ponte la máscara de gas Jurapenas y usa el comunicador de la Legión en Campamento Forja: Inquina, en las Montañas Filoespada."}},
[10820] = {"Engañar al enemigo", {"Mata 4 auxiliares de la Forja Maldita y 4 ingenieros de la Forja Maldita."}},
[10821] = {"¡Largo de aquí!", {"Mata a la pregonera de fatalidad."}},
[10822] = {"Sello Furia del Sol único", nil},
[10823] = {"Más sellos Furia del Sol", nil},
[10824] = {"Sellos Furia del Sol", {"La maga de batalla Vyara en el Sagrario de las Estrellas quiere que le lleves 10 sellos Furia del Sol.","","Completar misiones para los Arúspices hará que disminuya tu nivel de reputación con los Aldor."}},
[10825] = {"La verdad sin orbes", {"Entrega el Orbe de los Grishna al celador de árboles Chawn, de Soto Eterno, en las Montañas Filospada."}},
[10826] = {"Marcas de Sargeras", {"Lleva 10 marcas de Sargeras al presagista Saronen en el Valle Sombraluna.","","Completar misiones para los Aldor hará que disminuya tu nivel de reputación con los Arúspices."}},
[10827] = {"Más marcas de Sargeras", nil},
[10828] = {"Marca de Sargeras única", nil},
[10829] = {"Troncárbol debe saber", {"Habla con Troncárbol, un anciano del Conocimiento que vive en el Bosque del Cuervo de las Montañas Filospada."}},
[10830] = {"El exorcismo de los árboles", {"Consigue 5 orbes de Grishnath y 5 plumas nacientes atroces y después combínalos para crear plumas de exorcismo. Utiliza las plumas para realizar el exorcismo y matar a 5 espíritus koi-koi de los hojabarba del Bosque del Cuervo."}},
[10831] = {"Convertirse en un sastre de tela lunar", {"Utiliza el retal de tejido abisal imbuido cuando estés en la Poza de la Luna del Refugio Cenarion para crear una muestra de tela lunar primigenia. Lleva la prueba a Nasmara Canción de Luna en el Bajo Arrabal de la Ciudad de Shattrath.","","*¡ATENCIÓN!* Solo puedes seleccionar una especialidad de sastrería."}},
[10832] = {"Convertirse en sastre de fuego de hechizo", {"Lleva una muestra de esencia de ánima abisal a Gidge Tejehechizos en el Bajo Arrabal de Shattrath.","","*¡ATENCIÓN!* Solo puedes seleccionar una especialidad de sastrería."}},
[10833] = {"Convertirse en un sastre de tejido de sombra", {"Utiliza el cristal de Sombras profundas cerca de El Altar de las Sombras para estar más en sintonía con el altar. A continuación, vuelve a ver a Andrion Giroscuro en el Bajo Arrabal de Shattrath.","","*¡ATENCIÓN!* Solo puedes seleccionar una especialidad de sastrería."}},
[10834] = {"Grillok \"Ojosombra\"", {"Mata a Grillok Ojosombra y lleva el parche del ojo de Grillok a Zezzak en la Avanzada Rompeloma."}},
[10835] = {"El boticario Antonivich", {"Lleva los hallazgos de Albreck al boticario Antonivich a Thrallmar, en la Península del Fuego Infernal."}},
[10836] = {"Infiltrarse en la Fortaleza Faucedraco", {"Neltharaku, que sobrevuela los Campos del Ala Abisal en el Valle Sombraluna, quiere que mates a quince orcos Faucedraco.","","Bastará con cualquier orco Faucedraco de la Fortaleza Faucedraco."}},
[10837] = {"¡Al Arrecife del Ala Abisal!", {"Neltharaku, que sobrevuela los Campos del Ala Abisal en el Valle Sombraluna, quiere que recojas doce cristales de vid abisal del Arrecife del Ala Abisal.|n"}},
[10838] = {"El cristal de adivinación demoníaco", {"Usa el cristal de adivinación demoníaco en la Cuenca del Fuego Infernal, espera a que se sintonice, pide una trascripción.","","Devuelve el cristal de adivinación demoníaco y la trascripción del cristal de adivinación demoníaco al boticario Antonivich de Thrallmar."}},
[10839] = {"Velo Skith: Rocanegra de Terokk", {"Usa la vara de purificación sobre la Rocanegra de Terokk, en Velo Skith, y vuelve a Kirrik el Despierto a la Caravana de Refugiados de El Vertedero de Huesos."}},
[10840] = {"La Tumba de las Luces", {"El sumo sacerdote Orglum quiere que vayas a la Tumba de las Luces y mates a 10 abisálicos etéreos y 10 desvalijadores etéreos. A continuación vuelve a verle a la Caravana de Refugiados."}},
[10841] = {"El heraldo vengativo", nil},
[10842] = {"Almas vengativas", {"El sumo sacerdote Orglum quiere que viajes a la Tumba de las Luces y derrotes a 5 draenei vengativos."}},
[10843] = {"Desde tiempos olvidados...", {"Mata a Gnosh Brognat, líder de los ogros en la Avanzada Aguja del Filo."}},
[10844] = {"Campamento Forja: Inquina", nil},
[10845] = {"Matar a la madre de linaje", {"Mata a Alatemible."}},
[10846] = {"Comprender a los Mok'Nathal", {"Mata a Vekh, líder de los arakkoa Vekh'nir."}},
[10847] = {"Los ojos de Skettis", {"Lleva el ojo de Reskk y el ojo de Shienor a Rilak el Redimido en el Bajo Arrabal, en Shattrath."}},
[10848] = {"Velo Rhaze: el mal no viviente", {"Mata 4 espíritus Garramuerte, 4 espíritus estridentes, 2 espíritus de cuervo y después ve a ver a Kirrik el Despierto a la Caravana de Refugiados."}},
[10849] = {"Busca a Kirrik", {"Lleva la misiva de Rilak a Kirrik el Despierto en la Caravana de Refugiados, en El Vertedero de Huesos."}},
[10850] = {"Gas abisal en una máquina de fuego vil", nil},
[10851] = {"Los tótems de mi enemigo", {"Recoge 5 tótems Aguja del Filo."}},
[10852] = {"Amigos desaparecidos", {"Ethan quiere que encuentres a doce de sus amigos desaparecidos en Velo Skith y que luego vuelvas con él a la Caravana de Refugiados."}},
[10853] = {"Llamamiento de espíritus", {"Usa el Tótem Llamada de espíritu para recoger ocho espíritus de draco abisal inferiores."}},
[10854] = {"La fuerza de Neltharaku", {"Neltharaku, que sobrevuela los Campos del Ala Abisal, en el Valle Sombraluna, quiere que liberes a 5 dracos Ala Abisal esclavizados."}},
[10855] = {"¡Atracadores viles, no gracias!", {"Consigue 5 unidades de gas abisal condensado de los mekigenieros Gan'arg de la Base Forja: Olvido, al noroeste de La Flecha de la Tormenta y mételas en un atracador vil cercano inactivo. Vuelve a ver al acechador abisal Nauthis cuando hayas completado la tarea."}},
[10856] = {"La mejor defensa", {"El acechador abisal Nauthis quiere que mates 12 encolerizadores en la Base Forja: Gehenna, al norte de La Flecha de la Tormenta."}},
[10857] = {"¡Teletransporta esto!", {"El acechador abisal Nauthis quiere que utilices la Vara de interferencia mental con los Mo'arg en la Base Forja: Gehenna y uses su habilidad de detonar teletransportadores en los tres teletransportadores del Campamento Forja."}},
[10858] = {"Karynaku", {"Busca a Karynaku en la Fortaleza Faucedraco."}},
[10859] = {"Reunir los orbes", {"Usa el tótem colector de orbes para recoger 15 orbes de Luz Razaani."}},
[10860] = {"Regalos de Mok'Nathal", {"Reúne 3 costillas de raptor y 3 piezas de carne de serpiente."}},
[10861] = {"Velo Lítico: ataque preventivo", {"Rompe los huevos malditos de Velo Lítico. Redime a 3 proles y mata a 3 proles malévolas antes de volver con Kirrik el Despierto a la Caravana de Refugiados."}},
[10862] = {"Ríndete ante la Horda", {"Rokag quiere que busques a Rilak el Redimido en el Bajo Arrabal de Shattrath y exijas que él y los suyos se rindan ante la Horda."}},
[10863] = {"Secretos de los arakkoa", {"Lady Dena Kennedy quiere que busques a Rilak el Redimido en el Bajo Arrabal de Shattrath y descubras los secretos que sabe sobre los arakkoa."}},
[10864] = {"Una carga de almas", {"Mata a 20 orcos Mano Destrozada y vuelve con el boticario Antonivich, a Thrallmar."}},
[10865] = {"¡Informa a Leoroxx!", {"Habla con Leoroxx sobre lo que los etéreos de Razaani están tramando. Se le puede encontrar en la Aldea Mok'Nathal, en las Montañas Filospada."}},
[10866] = {"Zuluhed el Demente", {"Mata a Zuluhed el Demente y consigue la llave de Zuluhed. Utiliza la llave de Zuluhed en las cadenas de Zuluhed para liberar a Karynaku."}},
[10867] = {"Solo puede haber una respuesta", {"Recupera la colección de almas."}},
[10868] = {"La ruta de guerra de los arakkoa", {"La consejera Faila te ha pedido que mates a 14 garrosos Shienor, 6 hechiceros Shienor y que, después, vuelvas a verla en el Bastión Rompepedras."}},
[10869] = {"Disminuir la manada", {"El teniente Gravamartillo te ha pedido que mates 14 garrosos Shienor, 6 hechiceros Shienor y que, después, vuelvas a verle en el Bastión Allerian."}},
[10870] = {"Aliado del Ala Abisal", {"Deja que Karynaku te envíe de vuelta a Mordenai en los Campos del Ala Abisal."}},
[10871] = {"Aliado del Ala Abisal", {"Deja que Karynaku te envíe de vuelta a Mordenai en los Campos del Ala Abisal."}},
[10872] = {"Zuluhed el Demente", {"Mata a Zuluhed el Demente y consigue la llave de Zuluhed. Utiliza la llave de Zuluhed en las cadenas de Zuluhed para liberar a Karynaku."}},
[10873] = {"Tomados en la noche", {"El explorador Navrin quiere que vayas a la Cresta Red Abisal, liberes a 6 guerreros atrapados con telaraña de Sha'tar y vuelvas con él al Campamento Sha'tari."}},
[10874] = {"Velo Shalas: señales de fuego", {"Kirrik el Despierto de la Caravana de Refugiados quiere que extingas las cuatro señales de fuego de Velo Shalas."}},
[10875] = {"Informar a Nazgrel", {"Habla con Nazgrel en Thrallmar, en la Península del Fuego Infernal."}},
[10876] = {"El pie de la ciudadela", {"Mata al comandante en jefe Gorax, coloca el Desafío de la Horda sobre su cadáver, mata a la Mano de Kargath, y lleva la cabeza de la Mano de Kargath a Nazgrel, en Thrallmar."}},
[10877] = {"La reliquia de pavor", {"Roblun quiere que viajes al este, hasta la Caravana Derelicta para recuperar la reliquia de pavor. Vuelve con Roblun cuando hayas completado la tarea."}},
[10878] = {"Antes de que caiga la oscuridad", {"Mekeda, de la Caravana de Refugiados quiere que mates a 8 hostigadores de la Cábala, 4 tejehechizos de la Cábala y 2 iniciados a la Cábala."}},
[10879] = {"La ofensiva de Skettis", {"Resiste a los atacantes y habla con Rilak el Redimido."}},
[10880] = {"Órdenes de la Cábala", {"Lleva las órdenes de la Cábala a Mekeda, en la Caravana de Refugiados en el Vertedero de Huesos."}},
[10881] = {"La Tumba Umbría", {"Ve a la Tumba Umbría, al oeste de la Caravana de Refugiados, y recupera el mantón de Arunen, el mazo de K'alen y el pergamino de Atalor. Vuelve con Mekeda a la Caravana de Refugiados cuando hayas completado esta tarea."}},
[10882] = {"Presagista de la Fatalidad", {"Se te ha encomendado que vayas al satélite Arcatraz de El Castillo de la Tempestad y mates al Presagista Cieloriss. Vuelve con A'dal al Bancal de la Luz, en la Ciudad de Shattrath, cuando lo hayas hecho."}},
[10883] = {"La llave de la tempestad", {"Habla con A'dal en la Ciudad de Shattrath.|n"}},
[10884] = {"Prueba de los naaru: piedad", {"A'dal de la Ciudad de Shattrath quiere que recuperes el hacha del verdugo sin usar en Las Salas Arrasadas de la Ciudadela del Fuego Infernal.","","Esta misión debe completarse en dificultad de mazmorra heroica."}},
[10885] = {"Prueba de los naaru: fuerza", {"A'dal de la Ciudad de Shattrath quiere que recuperes el tridente de Kalithresh y la esencia de Murmullo.","","Esta misión debe completarse en dificultad de mazmorra heroica."}},
[10886] = {"Prueba de los naaru: tenacidad", {"A'dal, de la Ciudad de Shattrath, quiere que rescates a Molino Tormenta de Maná del Arcatraz de El Castillo de la Tempestad.","","Esta misión debe completarse en dificultad de mazmorra heroica."}},
[10887] = {"Escapar de la tumba", {"Ayuda a Akuno a encontrar su camino hasta la Caravana de Refugiados. Habla con Mekeda cuando hayas completado esta misión."}},
[10888] = {"Prueba de los naaru: Magtheridon", {"A'dal en la Ciudad de Shattrath quiere que mates a Magtheridon."}},
[10889] = {"Regresa a Shattrath", {"Viaja a la Ciudad de Shattrath y habla con Rilak el Redimido en el Bajo Arrabal."}},
[10890] = {"[UNUSED] <NYI> ", nil},
[10891] = {"Armadura de placas imperiales", {"Habla con Derotain Sorbelodo en Gadgetzan, en Tanaris.|n"}},
[10892] = {"Armadura de placas imperiales", {"Habla con Derotain Sorbelodo en Gadgetzan, en Tanaris.|n"}},
[10893] = {"Largacola es el eje", {"Elimina a Draaca Largacola, la líder de los cultores del Culto Vermis, en el Túnel Calavermis."}},
[10894] = {"Vigía Calavermis", {"Entrega la nota de reunión al vigía Sombra Lunar en la entrada al Túnel Calavermis, en las Montañas Filospada."}},
[10895] = {"¡Zeth'Gor debe arder!", {"Utiliza la baliza de humo en cada una de las torres de Zeth'Gor y, después, vuelve con el comandante del aire Dabir'ee a Punta de Expedición."}},
[10896] = {"Los protectores infestados", {"Lakotae quiere que mates 25 cucarachas de bosque y después vuelvas a verle a la Caravana de Refugiados. Puedes encontrar a las cucarachas viviendo en los cuerpos de furibundos de bosque en podredumbre y caminarraíces infectados."}},
[10897] = {"Maestro en pociones", {"Lauranna Thar'well quiere que vayas a El Invernáculo de El Castillo de la Tempestad y consigas la Guía de Campo para Botánicos del gran botánico Freywenn. Además, quiere que le lleves 5 superpociones de sanación, 5 superpociones de maná y 5 pociones de letargo sin sueño sublimes.","","*¡ADVERTENCIA!* Solo podrás elegir una especialización de alquimia."}},
[10898] = {"Alacielo", {"Escolta a Alacielo y preséntate ante Rilak el Redimido en la Ciudad de Shattrath."}},
[10899] = {"Maestro de transmutación", {"Zarevhi, de la Flecha de la Tormenta, en Tormenta Abisal, quiere que le lleves 4 muestras de poderío primigenio.","","*¡ATENCIÓN!* Solo puedes seleccionar una especialidad de alquimia."}},
[10900] = {"La marca de Vashj", nil},
[10901] = {"La cayada de Kar'desh", {"Skar'this el Herético, en El Reciento de los Esclavos heroico, en la Reserva Colmillo Torcido, quiere que le lleves el sello terráneo y el sello llameante."}},
[10902] = {"Maestro en elixires", {"Ve a La Ciénaga Negra, en las Cavernas del Tiempo, y consigue 10 esencias de infinidad de los señores de la falla y los vigilantes de la falla. Llévalas, junto con 5 elixires de defensa sublime, 5 elixires de maestría y 5 elixires de agilidad sublime a Lorokeem, en el Bajo Arrabal de Shattrath.","","*¡ATENCIÓN!* Solo puedes seleccionar una especialidad de alquimia."}},
[10903] = {"Regresa al Bastión del Honor", {"Habla con el ayudante Klatu, en la posada del Bastión del Honor."}},
[10904] = {"Recoger la munición vil", {"Recoge cinco balas de cañón vil."}},
[10905] = {"Maestro en pociones", {"Habla con Lauranna Thar'well en el Refugio Cenarion en la Marisma de Zangar.","","*¡ADVERTENCIA!* Solo podrás elegir una especialización de alquimia."}},
[10906] = {"Maestro en elixires", {"Habla con Lorokeem en el Bajo Arrabal de Shattrath.","","*¡ADVERTENCIA!* Solo podrás elegir una especialización de alquimia."}},
[10907] = {"Maestro de transmutación", {"Habla con Zarevhi en La Flecha de la Tormenta, en la Tormenta Abisal.","","*¡ADVERTENCIA!* Solo podrás elegir una especialización de alquimia."}},
[10908] = {"Hablar con Rilak el Redimido", {"Kirrik el Despierto quiere que hables con Rilak el Redimido en el distrito del Bajo Arrabal de Shattrath."}},
[10909] = {"Espíritus viles", {"Klatu, del Bastión del Honor quiere que uses la reliquia anacoreta en la Avanzada Gor'gaz, al suroeste del Bastión. Mata a todos los rabiosos Mano Destrozada que encuentres cerca de la reliquia y luego mata a 10 espíritus viles liberados para vengar al coronel Jules."}},
[10910] = {"La Puerta de la Muerte", {"Usa la señal para druida en la Puerta de la Muerte para llamar a un druida Soto Eterno para poder hablar con él."}},
[10911] = {"¡Fuego a discreción!", {"Usa la munición naturalizada para controlar los cañones viles de la Puerta de la Muerte. Úsalos para destruir el portal de distorsión del sur y el portal de distorsión del norte."}},
[10912] = {"El Maestro de canes", {"Mata a Baelmon, el Maestro de canes."}},
[10913] = {"Un entierro indecoroso", {"El comandante Ra'vaj, de la Avanzada Sha'tari, en El Vertedero de Huesos del Bosque de Terokkar, quiere que quemes a 8 guerreros Auchenai asesinados y a 8 vindicadores Sha'tar asesinados."}},
[10914] = {"Se necesita un héroe", {"El comandante Ra'vaj de la Avanzada Sha'tari, en El Vertedero de Huesos, del Bosque de Terokkar, quiere que mates a 12 iniciados Auchenai y a 5 decidores del destino Auchenai."}},
[10915] = {"El exarca caído", {"El comandante Ra'vaj de la Avanzada Sha'tari, en El Vertedero de Huesos del Bosque de Terokkar, quiere que destruyas el contenido del ataúd de Auchenai."}},
[10916] = {"Desenterrando abalorios de oración", {"Recupera los abalorios de oración Draenei y llévaselas al ayudante Klatu, al Bastión del Honor."}},
[10917] = {"La situación apremiante del marginado", {"Lleva 30 plumas de arakkoa a Vekax en el Bajo Arrabal de Shattrath."}},
[10918] = {"Más plumas", nil},
[10919] = {"El tesoro de Fei Fei", nil},
[10920] = {"Por los caídos", {"El vindicador Haylen quiere que mates a 20 viudas Colminferno y, después, vuelvas con él, justo al oeste de Cresta Red Abisal."}},
[10921] = {"Terokkarántula", {"El vindicador Haylen quiere que mates a la Terokkarántula y, después, vuelvas con él, al oeste de Cresta Red Abisal."}},
[10922] = {"Excavando huesos", {"Escolta a Letoll y a sus hombres y protégelos mientras excavan. Vuelve a ver a Sesoenanof a la Avanzada Sha'tari si tienes éxito.|n"}},
[10923] = {"El mal se acerca", {"Roblun quiere que lleves la reliquia de pavor al Alcor Tortuoso. Cuando estés allí tienes que matar médiums y oradores del Sino Auchenai para conseguir 20 calaveras de fatalidad. Después tendrás que encontrar el círculo de invocación del Alcor Tortuoso y usar la reliquia de pavor para invocar y acabar con Teribus el Maldito. Vuelve a ver a Roblun cuando lo hayas hecho."}},
[10924] = {"¡Totalmente im-posible!", {"Lleva 8 viales de sangre de persecutor de distorsión a Sab'aoth, en Cosmotirón."}},
[10925] = {"El mal se acerca", nil},
[10926] = {"Regresa al Campamento Sha'tari", {"El vindicador Haylen quiere que vuelvas al Campamento Sha'tari, en el Vertedero de Huesos, y hables con el explorador Navrin."}},
[10927] = {"Matando a los reptadores", {"Mata 6 reptadores de cavernas."}},
[10928] = {"Matando a los reptadores", {"Mata 6 reptadores de cavernas."}},
[10929] = {"Gusanos", {"Enaniski en Campamento Sha'tari, en El Vertedero de Huesos, quiere que le lleves 8 cadáveres de matizahuesos adultos."}},
[10930] = {"El gran gusano de hueso", {"Enaniski de Campamento Sha'tari, en El Vertedero de Huesos, quiere que consigas los órganos del gran gusano de hueso.","","También quiere su tambor.|n"}},
[10931] = {"Regresa a El Exodar", {"Habla con Caedmos en El Exodar."}},
[10932] = {"Regresa a El Exodar", {"Habla con Caedmos en El Exodar."}},
[10933] = {"Regresa a Lunargenta", {"Habla con Aldrae en La Ciudad de Lunargenta."}},
[10934] = {"Regresa a Lunargenta", {"Habla con Aldrae en La Ciudad de Lunargenta."}},
[10935] = {"El exorcismo del coronel Jules", {"Habla con el anacoreta Barada. Utiliza los abalorios de oración para ayudar con el ritual y después habla con el coronel Jules cuando esté bien. Por último, vuelve a ver al ayudante Klatu."}},
[10936] = {"Aterratrols te está buscando", {"El asistente Klatu te ha dicho que el comandante en jefe Danath Aterratrols te está buscando. Ve a verle al cuartel del Bastión del Honor, en la Península del Fuego Infernal."}},
[10937] = {"Acaba con el maestro de maniobras", {"El Comandante en Jefe Danath Aterratrols te ha pedido que mates al maestro de maniobras Zurok inmediatamente. Vuelve a ver al Comandante en Jefe del Bastión del Honor en la Península del Fuego Infernal cuando hayas matado al maestro de maniobras."}},
[10938] = {"La baraja de Bendiciones de la Luna Negra", {"Lleva la baraja de Bendiciones a la Feria de la Luna Negra cuando pase por la ciudad."}},
[10939] = {"La baraja de Tormentas de la Luna Negra", {"Lleva la baraja de Tormentas a la Feria de la Luna Negra cuando pase por la ciudad."}},
[10940] = {"La baraja de Furias de la Luna Negra", {"Lleva la baraja de Furias a la Feria de la Luna Negra cuando pase por la ciudad."}},
[10941] = {"La baraja de Locuras de la Luna Negra", {"Lleva la baraja de Locuras a la Feria de la Luna Negra cuando pase por la ciudad."}},
[10942] = {"Semana de los Niños", {"Usa el silbato de huérfano elfo de sangre para llamar a la niña a la que cuidarás durante la Semana de los Niños."}},
[10943] = {"Semana de los Niños", {"Usa el silbato de huérfano draenei para llamar a la niña a la que cuidarás durante la Semana de los Niños."}},
[10944] = {"El secreto en peligro", {"Viaja hasta la Jaula de la Guardiana del Valle Sombraluna y habla con Akama."}},
[10945] = {"Hch'uu y el pueblo champiñón", {"Lleva a tu huérfana, Salandria a Esporaggar en la Marisma de Zangar. Asegúrate de llamarla si no está presente cuando llegues. Luego habla con Hch'uu."}},
[10946] = {"Artimaña de los Lengua de ceniza", {"Viaja hasta El Castillo de la Tempestad y mata a Al'ar con la capucha de Lengua de ceniza puesta. Vuelve junto a Akama en el Valle Sombraluna cuando hayas terminado."}},
[10947] = {"Un artefacto del pasado", {"Ve a las Cavernas del Tiempo en Tanaris y consigue entrar en la Batalla del Monte Hyjal. Una vez dentro, vence a Ira Fríoinvierno y llévale la filacteria de fase temporal a Akama en el Valle Sombraluna."}},
[10948] = {"El alma rehén", {"Viaja hasta la Ciudad de Shattrath y háblale a A'dal de lo que pide Akama."}},
[10949] = {"La entrada a El Templo Oscuro", {"Viaja hasta la entrada del Templo Oscuro en el Valle Sombraluna y habla con Xi'ri."}},
[10950] = {"Auchindoun y El Círculo de la Observancia", {"Lleva a tu huérfana, Dornaa, a la roca de encuentro que hay en el Círculo de la Observancia, en medio de Auchindoun. Auchindoun, por su parte, está en medio de El Vertedero de Huesos del Bosque de Terokkar. Asegúrate de que la llamas si no está presente cuando llegues."}},
[10951] = {"Un viaje al Portal Oscuro", {"Lleva a tu huérfana, Salandria, a ascender por Los Peldaños del Destino para plantarse delante del Portal Oscuro en la Península del Fuego Infernal. Asegúrate de llamarla si no está ahí cuando llegues."}},
[10952] = {"Un viaje al Portal Oscuro", {"Lleva a tu huérfana, Dornaa, a ascender por Los Peldaños del Destino para plantarse delante del Portal Oscuro en la Península del Fuego Infernal. Asegúrate de llamarla si no está ahí cuando llegues."}},
[10953] = {"Visita a El Trono de los Elementos", {"Lleva a tu huérfana, Salandria, hasta El Trono de los Elementos en Nagrand. Asegúrate de llamarla si no está ya allí cuando llegues. Luego, habla con el elementalista Sharvak."}},
[10954] = {"¡Jheel está en el Desembarco Aeris!", {"Lleva a tu huérfana, Dornaa, al Desembarco Aeris en Nagrand. Asegúrate de llamarla si no está allí cuando llegues. Luego habla con Jheel."}},
[10955] = {"Morthis Alasusurro", {"Busca a Morthis Alasusurro en el Refugio Cenarion de la Marisma de Zangar."}},
[10956] = {"El Trono de los Naaru", {"Lleva a tu huérfana, Dornaa, hasta O'ros a los pies del Trono de los Naaru, dentro de El Exodar, que está en la Isla Bruma Azur. Asegúrate de que la llamas si no está ya allí cuando llegues.","","Recuerda que puedes usar el mapa dentro de la ciudad."}},
[10957] = {"Redención de los Lengua de ceniza", {"Ayuda a Akama a recuperar el control de su alma derrotando a la Sombra de Akama dentro del Templo Oscuro. Vuelve junto al vidente Kanai cuando hayas completado esta misión."}},
[10958] = {"Búsqueda de los Lengua de ceniza", {"Encuentra a los Juramorte de Akama dentro del Templo Oscuro."}},
[10959] = {"La caída de El Traidor", {"El vidente Kanai quiere que derrotes a Illidan dentro del Templo Oscuro."}},
[10960] = {"Cuando sea mayor...", nil},
[10961] = {"El resguardo de despertar", {"Lleva 10 cardos de Mantar, 10 líquenes antiguos y 10 glorias de ensueño a Morthis Alasusurro al Refugio Cenarion."}},
[10962] = {"Hora de visitar las Cavernas", {"Lleva a tu huérfana, Dornaa, ante Zaladormu, el dragón del estrado que se encuentra en el centro de las Cavernas del Tiempo. Asegúrate que la llamas si no está presente cuando llegas.","","Luego, cómprale un dragón de juguete al intendente de los Vigilantes del Tiempo, Alurmi, cerca del fin del túnel de la entrada."}},
[10963] = {"Hora de visitar las Cavernas", {"Lleva a tu huérfana, Salandria, ante Zaladormu, el dragón del estrado que se encuentra en el centro de las Cavernas del Tiempo. Asegúrate que la llamas si no está presente cuando llegas.","","Luego, cómprale un dragón de juguete al intendente de los Vigilantes del Tiempo, Alurmi, cerca del fin del túnel de la entrada."}},
[10964] = {"Despertar al durmiente", {"Usa el resguardo de despertar para ayudar a Clintar Caminasueños a salir del Sueño Esmeralda. Cuando recobre el conocimiento, habla con él."}},
[10965] = {"Se acabó el sueño", {"Protege a Clintar Caminasueños mientras reúne las reliquias de Aviana, luego habla con el celador de sueños Lurosa."}},
[10966] = {"De vuelta al orfanato", {"Devuelve a tu pupila al orfanato de la Ciudad de Shattrath. Entrégale el silbato de draenei huérfano a la supervisora de huérfanos Piedad en el Bajo Arrabal."}},
[10967] = {"De vuelta al orfanato", nil},
[10968] = {"Llamada al clarividente", nil},
[10969] = {"Busca a Ameer", {"Busca al comandante Ameer a la Avanzada del Protectorado."}},
[10970] = {"Una misión de piedad", {"Consigue la Llave de la prisión de El Etereum rescatada para el comandante Ameer en la Avanzada del Protectorado de Tormenta Abisal."}},
[10971] = {"Secretos de El Etereum", {"El comandante Ameer de la Avanzada del Protectorado de Tormenta Abisal quiere que le lleves una etiqueta de identificación de prisionero de El Etereum."}},
[10972] = {"Catálogo de identificación de prisioneros de El Etereum", nil},
[10973] = {"Mil mundos", {"El comandante Ameer de la Avanzada del Protectorado de Tormenta Abisal quiere que le lleves 5 llaves de prisión de El Etereum."}},
[10974] = {"Cámaras de Estasis de Bash'ir", {"Usa la tablilla de llave de El Etereum - Alfa para abrir la Cámara de Estasis Alfa en el Alto Bash'ir de las Montañas Filospada.","","Vuelve con evidencias de Alfa a la imagen del comandante Ameer en el Alto Bash'ir."}},
[10975] = {"Purgar las cámaras de Bash'ir", nil},
[10976] = {"La marca del rey-nexo", {"La imagen del comandante Ameer en el Alto Bash'ir de las Montañas Filospada quiere que le traigas una marca del rey-nexo."}},
[10977] = {"Cámaras de Estasis de las Tumbas de Maná", {"La imagen del comandante Ameer del Alto Bash'ir en las Montañas Filospada quiere que uses la llave de la Cámara de Estasis de las Tumbas de Maná en las Tumbas de Maná de Auchindoun.","","Esta misión solo se puede completar en modo heroico."}},
[10978] = {"Regresa junto a Morthis Alasusurro", {"Llévale las reliquias de Aviana a Morthis Alasusurro al Refugio Cenarion de la Marisma de Zangar."}},
[10979] = {"A Soto Eterno", {"Habla con Arthorn Son del Viento de Soto Eterno en las Montañas Filospada."}},
[10980] = {"El Libro del Cuervo", {"Usa el ojo de raya de éter con tu piedra de vidente para que se muestren los fantasmas del culto del cuervo. Busca La Cumbre del Vórtice para el espíritu de Sai'kkal el Anciano e interrógalo sobre el Libro del Cuervo. Después vuelve a Arthorn Son del Viento."}},
[10981] = {"Cámara personal del príncipe-nexo Shaffar", nil},
[10982] = {"El ojo de Haramad", nil},
[10983] = {"Mog'dorg el Marchito", {"Visita a Mog'dorg el Marchito en lo alto de una de las torres que hay justo fuera del Anillo de Sangre en las Montañas Filospada."}},
[10984] = {"Habla con el ogro", {"Habla con Grok, el ogro, en el Bajo Arrabal de la Ciudad de Shattrath."}},
[10985] = {"Una distracción para Akama", {"Asegúrate de que Akama y Maiev entran en El Templo Oscuro, en el Valle Sombraluna, cuando las fuerzas de Xi'ri creen una distracción."}},
[10986] = {"Ojos en el cielo", {"Habla con la vigía Elaira en La Cresta del Crepúsculo en Nagrand."}},
[10987] = {"Atrapar un gavilán", {"Usa la red para gavilanes para capturar un gavilán salvaje y llévaselo a la vigía Elaira en la Cresta del Crepúsculo."}},
[10988] = {"Las piedras del Cuervo", {"Reúne 8 Piedras del Cuervo de Skettis y llévaselas a Arthorn Son del Viento a Soto Eterno, en las Montañas Filospada."}},
[10989] = {"Mog'dorg el Marchito", {"Visita a Mog'dorg el Marchito, que se encuentra en lo alto de la torre donde está Chort, justo fuera del Anillo de Sangre en las Montañas Filospada."}},
[10990] = {"La esencia del Águila", {"Derrota al guardián del Águila y obtén la esencia del Águila. Usa el silbato para gavilanes de Arthorn para llamar al gavilán de Arthorn para que lleve las noticias de tu éxito.","","Si pierdes el silbato de gavilanes de Arthorn, vuelve a ver a Arthorn Son del Viento en Soto Eterno para que te dé otro."}},
[10991] = {"La esencia del Falcón", {"Derrota al guardián del Falcón y obtén la esencia del Falcón. Usa el silbato para gavilanes de Arthorn para llamar al gavilán de Arthorn para que lleve las noticias de tu éxito.","","Si pierdes el silbato de gavilanes de Arthorn, vuelve a ver a Arthorn Son del Viento en Soto Eterno para que te dé otro."}},
[10992] = {"La esencia del Halcón", {"Derrota al guardián del Halcón y lleva la esencia del Halcón a Arthorn Son del Viento en Soto Eterno."}},
[10993] = {"Regresa al Refugio Cenarion", {"Lleva el paquete de Arthorn a Morthis Alasusurro al Refugio Cenarion."}},
[10994] = {"Tras la piedra lunar", {"Lleva una piedra lunar de Furia del Sur a Morthis Alasusurro al Refugio Cenarion."}},
[10995] = {"Grulloc tiene dos calaveras", {"Consigue la calavera de dragón de Grulloc."}},
[10996] = {"La arqueta de Maggoc", {"Consigue la arqueta de Maggoc."}},
[10997] = {"Incluso los gronn tienen confalones", {"Consigue el confalón de Slaag."}},
[10998] = {"Un asunto grimoso", {"Consigue el grimorio de Vim'gol el Vil."}},
[10999] = {"Un tiro. Un muerto.", {"Tráeme 8 dientes de trogg de piedra."}},
[11000] = {"Dentro del Moledor de Almas", {"Recoge el alma de Skulloc."}},
[11001] = {"Derrota al Dios Cuervo", {"Mata al Dios Cuervo y vuelve con Morthis Alasusurro en el Refugio Cenarion.","","Esta misión se debe completar en el modo de dificultad de mazmorras Heroico."}},
[11002] = {"La caída de Magtheridon", {"Devuelve la cabeza de Magtheridon al comandante en jefe Danath Aterratrols en el Bastión del Honor en la Península del Fuego Infernal."}},
[11003] = {"La caída de Magtheridon", {"Devuelve la cabeza de Magtheridon a Nazgrel en Thrallmar en la Península del Fuego Infernal."}},
[11004] = {"Mundo de Sombras", {"Severin quiere que te adentres en Skettis y consigas 6 muestras de polvo de las Sombras de los arakkoa que allí moran."}},
[11005] = {"Secretos de los sacerdotes de la Garra", {"Obtén el elixir de Sombras de Severin y úsalo para encontrar y matar a los sacerdotes de la garra Ishaal, Skizzik y Zellek en Skettis. Cuando completes la tarea, informa al comandante Adaris."}},
[11006] = {"Más polvo de las sombras", nil},
[11007] = {"Kael'thas y la esfera verdeante", {"Lleva la esfera verdeante a A'dal en la Ciudad de Shattrath."}},
[11008] = {"Fuego sobre Skettis", {"Busca los huevos de kaliri monstruosos sobre los hogares de Skettis y usa las cargas explosivas de la Guardia del cielo para destruirlos. Preséntate ante el sargento del cielo Doryn."}},
[11009] = {"El cielo de los ogros", {"Habla con Chu'a'lor en Ogri'la, en las Montañas Filospada."}},
[11010] = {"¡Bomba va!", {"Utiliza bombas de la Guardia del Cielo para destruir 15 montones de balas de cañón vil."}},
[11011] = {"Vigilancia eterna", {"Habla con Morthis Alasusurro para que te dé una piedra lunar imbuida de esencia."}},
[11012] = {"Juramento de sangre de los Ala Abisal", nil},
[11013] = {"Al servicio de los Illidari", {"Viaja hasta el Arrecife del Ala Abisal y entrega los documentos de servicio Illidari al señor supremo Mor'ghor en el Campamento Faucedraco.|n"}},
[11014] = {"Presentación ante el capataz", {"Habla con el capataz Varkule Aliento de Dragón en el Campamento Faucedraco."}},
[11015] = {"Cristales de Ala Abisal", {"El capataz Varkule Aliento de Dragón del Campamento Faucedraco en el Valle Sombraluna quiere que le traigas 30 cristales de Ala Abisal."}},
[11016] = {"Pellejo de despellejador mina abisal", {"El capataz Varkule Aliento de Dragón del Campamento Faucedraco en el Valle Sombraluna quiere que le traigas 35 pellejos de despellejadores mina abisal."}},
[11017] = {"Polen de polvo abisal", {"El capataz Varkule Aliento de Dragón del Campamento Faucedraco en el Valle Sombraluna quiere que le lleves 40 unidades de polen de polvo abisal."}},
[11018] = {"Mineral de abisalita", {"El capataz Varkule Aliento de Dragón del Campamento Faucedraco en el Valle Sombraluna quiere que le lleves 40 unidades de mineral de abisalita."}},
[11019] = {"Tu amigo en el interior", nil},
[11020] = {"Una muerte lenta", {"Yarzill el Condotiero se encuentra en el Campamento Faucedraco del Valle Sombraluna y quiere que uses su añojo y glándulas viles para envenenar a los peones Faucedraco de 12 asentamientos.|n"}},
[11021] = {"El anuario de Ishaal", {"Lleva el anuario de Ishaal al comandante del cielo Adaris al norte de Skettis."}},
[11022] = {"Habla con Mog'dorg", {"Habla con Mog'dorg el Marchito. Se encuentra en lo alto de la torre al este del Anillo de Sangre, en las Montañas Filospada."}},
[11023] = {"¡Bombardéalos de nuevo!", {"Utiliza bombas de la Guardia del Cielo para destruir 15 montones de balas de cañón vil."}},
[11024] = {"Un aliado en el Bajo Arrabal", {"Lleva el anuario de Ishaal a Rilak el Redimido en el Bajo Arrabal dentro de Shattrath."}},
[11025] = {"Los cristales", {"Reúne 5 fragmentos de ápices."}},
[11026] = {"Destierra a los demonios", {"Usa el cristal desterrador para desterrar a 15 demonios en el Campamento Forja: Cólera o en el Campamento Forja: Terror."}},
[11027] = {"¿Tú tener runaoscura?", nil},
[11028] = {"Cuenta atrás hacia la Muerte", {"Vuelve donde el comandante del cielo Adaris, en el Alto de los Vientonegro, en el Bosque de Terokkar, e infórmale acerca del regreso de Terokk."}},
[11029] = {"Un disfraz raído", {"Usa el disfraz arakkoa desgastado para conseguir la Línea de Sangre de Adversarios de Sahaakk y vuelve junto a Hazzik."}},
[11030] = {"Nuestro chico quiere ser un forestal Guardia del cielo", {"Consigue un frasco inestable de la bestia."}},
[11031] = {"Ya no es archimago", nil},
[11032] = {"Ya no es protector", nil},
[11033] = {"Ya no es asesino", nil},
[11034] = {"Ya no es restaurador", nil},
[11035] = {"Los cielos no tan amistosos...", {"Yarzill el Condotiero del Campamento Faucedraco en el Valle Sombraluna quiere que recuperes 10 reliquias de Ala Abisal."}},
[11036] = {"¡Un producto de fuera de este mundo!", {"Llévale la fruta en conserva al jefe de cohetes Fuselaje al Área 52, en Tormenta Abisal."}},
[11037] = {"Una extraña visión", {"Habla con el jefe de cohetes Fuselaje en el Área 52."}},
[11038] = {"Ayuda al exarca Orelis", {"Habla con el exarca Orelis en el Área 52."}},
[11039] = {"Informa al maestro de espías Thalodien", {"Preséntate ante el maestro de espías Thalodien en el Área 52."}},
[11040] = {"Piezas para el jefe de cohetes", {"Llévale las piezas que le sobran a Bossi al jefe de cohetes Fuselaje al Área 52, en Tormenta Abisal."}},
[11041] = {"Un trabajo sin terminar...", {"Mata 10 despellejadores sobremina y a Barash, la madre del cubil. Si tienes éxito, regresa a donde Mor'ghor al Campamento Faucedraco."}},
[11042] = {"Una visión mistificadora", {"Habla con el jefe de cohetes Fuselaje en el Área 52."}},
[11043] = {"Crear un grifo mejor", {"Habla con Brunn Barballamas en el Bastión Martillo Salvaje, en el Valle de Sombraluna."}},
[11044] = {"Visiones de destrucción", {"Habla con el comandante del aire Nuainn en el Bastión Martillo Salvaje."}},
[11045] = {"Zorus el Justiciero", {"Habla con Zorus el Justiciero en el Bastión Martillo Salvaje."}},
[11046] = {"Boticaria jefe Hildagard", {"Habla con la boticaria jefe Hildagard en la Aldea Sombraluna."}},
[11047] = {"La petición del aprendiz", {"Habla con Dama Ferocrín en la Aldea Sombraluna, en el Valle de Sombraluna."}},
[11048] = {"El informe de Kroghan", {"Habla con el Guardia de sangre Gulmok en la Aldea Sombraluna."}},
[11049] = {"La gran búsqueda de huevos de Ala Abisal", {"Yarzill el Condotiero en el Campamento Faucedraco en el Valle Sombraluna quiere que recuperes un huevo de Ala Abisal."}},
[11050] = {"Aceptar todos los huevos", nil},
[11051] = {"Destierra más demonios", {"Usa el cristal desterrador para desterrar a 15 demonios en el Campamento Forja: Cólera o en el Campamento Forja: Terror."}},
[11052] = {"La promesa de Akama", {"Llévale el medallón de Karabor a A'dal en la Ciudad de Shattrath."}},
[11053] = {"¡Levanta, sobrestante!", {"Habla con el señor supremo Mor'ghor en el Campamento Faucedraco en el Valle Sombraluna."}},
[11054] = {"La supervisión y tú: cómo tomar las decisiones adecuadas", {"El sobrestante jefe Limo, del Campamento Faucedraco en el Valle Sombraluna, quiere que le lleves 10 trozos de cuero de pellejo nudoso y un pellejo endurecido de Tyrantus.|n"}},
[11055] = {"El botarang: una cura para el insignificante trabajador común", {"El sobrestante jefe Limo, del Campamento Faucedraco en el Valle Sombraluna, quiere que disciplines a 20 peones Faucedraco vagos. También tendrás que devolver el botarang."}},
[11056] = {"La ganga de Hazzik", {"Obtén el paquete de Hazzik en su hogar del este de Skettis y llévaselo."}},
[11057] = {"El problema abajo", {"Habla con Mog'dorg el Marchito en lo alto de una de las torres que hay a las afueras del Anillo de Sangre en las Montañas Filospada.|n"}},
[11058] = {"Una reliquia de ápices", {"Consigue vibraciones de ápices de una reliquia de ápices."}},
[11059] = {"Guardián del monumento", {"Obtén la cabeza de un guardián de ápices."}},
[11060] = {"Una runaoscura de cristal forjado", nil},
[11061] = {"La obligación de un padre", {"Consigue un frasco inestable del hechicero."}},
[11062] = {"La Avanzada de la Guardia del Cielo", {"Habla con el comandante del cielo Keller en la Avanzada de la Guardia del Cielo, en lo alto de las Montañas Filospada."}},
[11063] = {"Ganándote las alas...", nil},
[11064] = {"Carrera Faucedraco: la balada del Viejo Viejete", {"Sigue a Murg Quijada Sucia \"el Viejo\" mientras intentas mantenerte en tu montura voladora. Si vences a Murg Quijada Sucia \"el Viejo\", informa de tu Victoria a Ja'y Nosliw en el Campamento Faucedraco, en el Valle Sombraluna."}},
[11065] = {"¡Enlaza algunas rayas de éter!", {"Utiliza el lazo para capturar 5 rayas de éter."}},
[11066] = {"¡Atrapa más rayas de éter!", {"Utiliza el lazo para capturar 5 rayas de éter."}},
[11067] = {"Carrera Faucedraco: Trope el Vomitador", {"Sigue a Trope el Vomitador mientras intentas mantenerte en tu montura voladora. Si vences a Trope el Vomitador, informa de tu Victoria a Ja'y Nosliw en el Campamento Faucedraco, en el Valle Sombraluna."}},
[11068] = {"Carrera Faucedraco: Corlok el Veterano", {"Sigue a Corlok el Veterano mientras intentas mantenerte en tu montura voladora. Si vences a Corlok el Veterano, informa de tu Victoria a Ja'y Nosliw en el Campamento Faucedraco, en el Valle Sombraluna."}},
[11069] = {"Carrera Faucedraco: Comandante del aire Ichman", {"Sigue al comandante del aire Ichman mientras intentas mantenerte en tu montura voladora. Si vences al comandante del aire Ichman, informa de tu Victoria a Ja'y Nosliw en el Campamento Faucedraco, en el Valle Sombraluna."}},
[11070] = {"Carrera Faucedraco: Comandante del aire Mulverick", {"Sigue al comandante del aire Mulverick mientras intentas mantenerte en tu montura voladora. Si vences al comandante del aire Mulverick, informa de tu Victoria a Ja'y Nosliw en el Campamento Faucedraco, en el Valle Sombraluna.|n"}},
[11071] = {"Carrera Faucedraco: Capitán Devastador del Cielo", {"Sigue al capitán Devastador del Cielo mientras intentas mantenerte en tu montura voladora. Si vences al capitán Devastador del Cielo, informa de tu Victoria a Ja'y Nosliw en el Campamento Faucedraco, en el Valle Sombraluna."}},
[11072] = {"Sangre adversaria", {"Encuentra los montones de cráneos en el centro de los círculos de invocación de Skettis. Invoca y derrota a cada uno de los descendientes usando 10 Pergaminos perdidos en el Tiempo en el montón de cráneos. Llévale a Hazzik una señal de cada uno al Alto de los Vientonegro."}},
[11073] = {"La caída de Terokk", {"Lleva las ofrendas tiempo perdido que ha preparado Hazzik al montón de cráneos en el centro de Skettis e invoca y vence a Terokk. Cuando termines, vuelve junto al comandante del cielo Adaris."}},
[11074] = {"Atributos de los descendientes", {"Recopila pergaminos perdidos en el tiempo de los arakkoa tiempo perdido en Skettis y llévalos a un montón de cráneos dentro de un círculo de invocación en Skettis. Invoca y derrota a los descendientes de los adversarios de Terokk y llévale a Hazzik la garfa de Akkarai, la espina de Karrog, la escama de Vekkaz y la garra de Gezzarak."}},
[11075] = {"Las Minas del Ala Abisal", {"Busca a la Maestra de las minas en el Arrecife del Ala Abisal."}},
