[11229] = {"La flota de El Brisaveloz", {"Habla con la cuidadora de murciélagos Camille en Campo Venganza y consigue llegar a El Brisaveloz. Preséntate ante la capitana Harker a bordo del barco."}},
[11230] = {"¡Una emboscada!", {"La capitana Harker, a bordo de El Brisaveloz, quiere que mates a 15 marinos de la Flota Norte."}},
[11231] = {"De llaves y jaulas", {"Padre Levariol te ha pedido que consigas tantas llaves de jaula de Gjalerbron como sean necesarias para liberar a 10 prisioneros de Gjalerbron. Vuelve a verlo a la Fortaleza de la Guardia Oeste cuando lo consigas."}},
[11232] = {"Sé nuestros ojos", {"Usa las bengalas de humo en el lugar donde se encuentran los cañones de la Alianza, en el muro norte de Playa Derelicta. Cuando hayas completado esta tarea, informa a la forestal oscura Lyana en la Vega Sangrante."}},
[11233] = {"Asestar el golpe de gracia", {"La forestal oscura Lyana, al sur de Campo Venganza, quiere que mates al capitán Olster, a la teniente Celeyne y al sargento Lorric en Playa Derelicta."}},
[11234] = {"Informa a Anselm", {"Informa al sumo ejecutor Anselm en Campo Venganza, en el Fiordo Aquilonal."}},
[11235] = {"Encargarse de Gjalerbron", {"El capitán Adams te ha pedido que mates 15 guerreros de Gjalerbron, 8 taumaturgos de runas de Gjalerbron y 8 vigías del sueño de Gjalerbron. Después vuelve a verle a la Fortaleza de la Guardia Oeste."}},
[11236] = {"Necroseñor Supremo Mezhen", {"Mata al Necroseñor Supremo Mezhen y vuelve a ver al capitán Adams en la Fortaleza de la Guardia Oeste."}},
[11237] = {"Los planes de ataque de Gjalerbron", {"Entrégale los planes de ataque de Gjalerbron al teniente mago Malister en la Fortaleza de la Guardia Oeste."}},
[11238] = {"La vermis de escarcha y su maestro", {"Mata al Clamavermis Vil y usa el cuerno de clamavermis para llamar y matar a Glacion. Después llévale el cuerno al teniente mago Malister a la Fortaleza de la Guardia Oeste."}},
[11239] = {"En servicio a la Luz", {"Mata a 10 vigías inextinguibles, 4 horrores aterradores y 2 criaturas pútridas. Después informa de tu éxito al Padre Levariol en la Fortaleza de la Guardia Oeste."}},
[11240] = {"Líder de los trastornados", {"Mata a Squeeg Cazador de Ídolos y después informa a Zapador Aro de Acero en la Fortaleza de la Guardia Oeste."}},
[11241] = {"Rastro de fuego", {"Escolta al boticario Hanes fuera de la Playa Derelicta. Informa al boticario Lysander de Campo Venganza en el Fiordo Aquilonal cuando hayas completado esta tarea."}},
[11242] = {"¡Por fin libre!", {"Lleva el Escrito de Thomas Thomson a la supervisora de huérfanos disfrazada de Villadorada, Kharanos o de la Avanzada Azur."}},
[11243] = {"Si Valgarde cae...", {"El vicealmirante Keller en el Puerto de Valgarde del Fiordo Aquilonal quiere que mates 12 invasores Desuelladragones o huargos Desuelladragones.|n"}},
[11244] = {"Rescatar a los rescatadores", {"El vicealmirante Keller del Puerto de Valgarde en el Fiordo Aquilonal quiere que encuentres a 8 exploradores de Valgarde que han sido empalados y abandonados hasta la muerte."}},
[11245] = {"Torres de cierta fatalidad", {"El Sargento de la Guardia Oeste te ha informado de que sería conveniente usar la Bengala de Sargento para fijar las cuatro torres de Skorn como objetivos para ataques con cañones."}},
[11246] = {"Horripilante, pero necesario", {"El sargento de la Guardia Oeste te ha pedido que uses el machete del Sargento para desmembrar a 20 vrykuls de la tribu Inbjerskorn en Skorn."}},
[11247] = {"¡Arde, Skorn, arde!", {"El sargento de la Guardia Oeste tiene órdenes de que, con la antorcha de Sargento, prendas fuego a las casas comunales del noreste y noroeste y a los barracones de Skorn."}},
[11248] = {"Operación: cólera de Skorn", {"El capitán Adams te ha pedido que uses la insignia de mando de la Guardia Oeste en Skorn, y que después hables con el Sargento de la Guardia Oeste."}},
[11249] = {"¡Detén la ascensión!", {"Presenta el Pergamino de ascensión vrykul cerca de la pira del señor feudal para hacerle salir y matarlo. Después, debido a la naturaleza del ritual, estás seguro de que a Padre Levariol, en la Fortaleza de la Guardia Oeste, le interesará ver el pergamino."}},
[11250] = {"¡Aclamad todos al conquistador de Skorn!", {"Devuélvele la Insignia de mando de la Guardia Oeste al capitán Adams en la Fortaleza de la Guardia Oeste."}},
[11251] = {"Piernas frescas", {"La exploradora Valory quiere que investigues los sonidos de batalla procedentes del noreste del Poblado Calavermis."}},
[11252] = {"¡A Utgarde!", {"El defensor Mordun te ha encargado la ejecución de Ingvar el Desvalijador que reside en las profundidades de Utgarde.","","Llévale su cabeza al Vicealmirante Keller."}},
[11253] = {"Sigue la pista del enemigo", {"Utiliza la correa de can de peste junto a las jaulas de can de peste en Campo Venganza y busca pistas en el lugar al que te lleve el can de peste rastreador."}},
[11254] = {"El mapa de piel de dragón", {"Lleva el mapa de piel de dragón al sumo ejecutor Anselm en Campo Venganza."}},
[11255] = {"Prisioneros de Calavermis", {"El vicealmirante Keller en el Puerto de Valgarde, en el Fiordo Aquilonal, quiere que rescates a 3 prisioneros de Valgarde."}},
[11256] = {"¡Skorn debe caer!", {"El cabecilla Tótem de Ceniza te ha pedido que uses el Emblema de Pezuña Invernal en Skorn y después hables con el Valiente Pezuña Invernal."}},
[11257] = {"Horripilante, pero necesario", {"El valiente Pezuña Invernal te ha pedido que uses el machete de Valiente para desmembrar a 20 vrykuls de la tribu Inbjerskorn en Skorn."}},
[11258] = {"¡Arde, Skorn, arde!", {"El valiente Pezuña Invernal te ha sugerido que uses la antorcha de Valiente para prender fuego a las casas comunales noreste y noroeste y a los barracones de Skorn."}},
[11259] = {"Torres de cierta fatalidad", {"El valiente Pezuña Invernal te ha informado de que sería conveniente usar la bengala de Valiente para fijar las cuatro torres de Skorn como objetivos para ataques aéreos."}},
[11260] = {"¡Detén la ascensión!", {"Presenta el Pergamino de ascensión vrykul cerca de la pira del señor feudal para hacerle salir y matarlo. Después, debido a la naturaleza del ritual, estás seguro de que a la abuela Ankha del Campamento Pezuña Invernal le interesará ver el pergamino."}},
[11261] = {"¡El conquistador de Skorn!", {"Devuelve el tótem Pezuña Invernal al cabecilla Tótem de Ceniza del Campamento Pezuña Invernal."}},
[11262] = {"¡Ingvar ha de morir!", {"La forestal oscura Marrah te ha pedido que mates a Ingvar el Desvalijador en la Fortaleza de Utgarde y que luego le lleves su cabeza al sumo ejecutor Anselm a Campo Venganza."}},
[11263] = {"Encargarse de Gjalerbron", {"El cabecilla Tótem de Ceniza te ha pedido que mates 15 guerreros de Gjalerbron, 8 taumaturgos de runas de Gjalerbron y 8 vigías del sueño de Gjalerbron. Después vuelve a verle al Campamento Pezuña Invernal."}},
[11264] = {"Necroseñor Supremo Mezhen", {"Mata al Necroseñor Supremo Mezhen y vuelve a ver al cabecilla Tótem de Ceniza en Campamento Pezuña Invernal."}},
[11265] = {"De llaves y jaulas", {"La abuela Ankha te ha pedido que consigas suficientes llaves de jaula de Gjalerbron para liberar a 10 prisioneros de Gjalerbron. Vuelve a verla al Campamento Pezuña Invernal cuando lo hayas conseguido."}},
[11266] = {"Los planes de ataque de Gjalerbron", {"Entrégale los planes de ataque de Gjalerbron a Celea Crines de Hielo en el Campamento Pezuña Invernal."}},
[11267] = {"La vermis de escarcha y su maestro", {"Mata al Clamavermis Vil y usa el cuerno de clamavermis para llamar y matar a Glacion. Después llévale el cuerno a Celea Crines de Hielo al Campamento Pezuña Invernal."}},
[11268] = {"Los muertos andantes", {"Mata a 10 vigías inextinguibles, 4 horrores aterradores y 2 criaturas pútridas. Después informa de tu éxito a la abuela Ankha del Campamento Pezuña Invernal."}},
[11269] = {"Esfuerzo final", {"Gil Grisert quiere que le lleves 10 montones de plumón de hipogrifo moteado."}},
[11270] = {"La guerra es un infierno", {"Estás en esta misión"}},
[11271] = {"Preparativos precipitados", {"Ahota Escarcha Blanca te ha pedido que le traigas 10 plumones de hipogrifo moteado."}},
[11272] = {"Ajuste de cuentas", {"El sumo ejecutor Anselm quiere que te adentres en Utgarde y mates al príncipe Keleseth."}},
[11273] = {"La liga de los humanos", {"Busca a Pulroy en el Poblado Calavermis."}},
[11274] = {"Es probable que Zedd esté muerto", {"Busca a Zedd en el Poblado Calavermis."}},
[11275] = {"Haciendo el cuerno", {"Nokoma Vidente de la Nieve del Campamento Pezuña Invernal quiere que le lleves 6 cuernos de carnero sin estropear."}},
[11276] = {"Solo quedaban dos...", {"Busca a Glorenfeld en las Catacumbas de Utgarde."}},
[11277] = {"Las profundidades de la depravación", {"Glorenfeld, de las Catacumbas de Utgarde, quiere que consigas 10 tablillas de Calavermis."}},
[11278] = {"Regresa a Valgarde", {"Lleva el paquete de Glorenfeld a Beltrand McSorf al Puerto de Valgarde."}},
[11279] = {"Huevos verdes con crías", {"El pesteador Tillinghast te ha pedido que reúnas 10 especímenes de protocría apestadas y que se las lleves a Nuevo Agamand."}},
[11280] = {"Draconis Gastritis", {"El pesteador Tillinghast en Nuevo Agamand quiere que uses la carne apestada de Tillinghast para atraer a un protodraco y que observes su reacción al comérsela."}},
[11281] = {"Imitando la llamada de la naturaleza", {"Prueba el cuerno tallado y ve a contarle los resultados que observes a Nokoma Vidente de la Nieve al Campamento Pezuña Invernal."}},
[11282] = {"Una lección de miedo", {"Gorth quiere que mates a Ulf el Flebotomista, a Oric el Torvo y a Gunnar Thorvardsson y que atravieses sus cuerpos con el estandarte de los Renegados. Mata vrykuls por la zona de bloqueo de los Renegados hasta que aparezcan."}},
[11283] = {"Recuento de cuerpos de Baleheim", {"El sargento Gorth quiere que mates a 16 vrykuls Inbjerskorn en el interior de Baleheim."}},
[11284] = {"El yeti de al lado", {"El supervisor Colbey en el Fuerte Vildervar quiere que derrotes a Modorro."}},
[11285] = {"¡Baleheim debe arder!", {"El sargento Gorth quiere que vayas a Baleheim y utilices la antorcha de Gorth para quemar 1 morada Inbjerskorn, 1 torre de observación Inbjerskorn, 1 puente Inbjerskorn y 1 barraca Inbjerskorn."}},
[11286] = {"Los artefactos de Las Puertas de Acero", {"El sabio Caminaniebla te ha pedido que consigas 10 artefactos de Las Puertas de Acero. Cuando los tengas todos, vuelve a verle a Las Puertas de Acero."}},
[11287] = {"Encuentra al sabio Caminaniebla", {"La abuela Ankha te ha pedido que averigües el estado del sabio Caminaniebla. Cree que se encuentra en o cerca de Las Puertas de Acero."}},
[11288] = {"La luz brillante", {"Ares el Juramentado en las Catacumbas de Utgarde quiere que recuperes el artefacto sacro.","","Esta es una misión contrarreloj."}},
[11289] = {"Guiado por el honor", {"Devuelve el artefacto sacro a Lord Irulon Filoveraz en Valgarde."}},
[11290] = {"Planes de batalla de los Desuelladragones", {"El vicealmirante Keller en el Puerto de Valgarde, en el Fiordo Aquilonal, te ha pedido que le lleves los planes de batalla de los Desuelladragones.|n"}},
[11291] = {"¡A la Fortaleza de la Guardia Oeste!", {"Lleva los planes de batalla de los Desuelladragones al capitán Adams a la Fortaleza de la Guardia Oeste en el Fiordo Aquilonal.|n"}},
[11292] = {"Acechando a los débiles", {"El trampero Jethan en el Fuerte Vildervar quiere que le lleves 8 trozos de presa atrapada."}},
[11293] = {"¡Grita por los Cebadiz!", nil},
[11294] = {"¡Grita por los Cebatruenos!", nil},
[11295] = {"La ofensiva comienza", {"Habla con el sargento Gorth en el bloqueo cerca del elevador oeste de Campo Venganza en el Fiordo Aquilonal."}},
[11296] = {"Cautivos de El Bosque Hendido", {"El enviado Nube del Cielo te ha pedido que liberes a sus 7 enviados Pezuña Invernal. Cuando lo hayas conseguido, vuelve junto a él a Las Puertas de Acero."}},
[11297] = {"Observando de cerca a los intrusos", {"Habla con el boticario Malthus en el Campamento de los Boticarios."}},
[11298] = {"¿Qué lleva esa bebida?", {"El boticario Malthus en el Campamento de los Boticarios quiere que le lleves 5 barriles enanos."}},
[11299] = {"El Círculo del Juicio", {"Encuentra a Daegarn en El Círculo del Juicio situado dentro de las Catacumbas de Utgarde."}},
[11300] = {"Una derrota asombrosa en el Círculo", {"Derrota a los gladiadores en el Círculo del Juicio y enfréntate a Oluf el Violento. Vence a Oluf y recupera la clave antigua.","","Devuelve la clave antigua a Glorenfeld en la entrada a las catacumbas de Utgarde."}},
[11301] = {"¡Cerebros! ¡Cerebros! ¡Cerebros!", {"El boticario Grick en el Campamento de los Boticarios quiere que le lleves 12 Cerebros de expedicionario perturbado."}},
[11302] = {"Las enigmáticas ninfas escarcha", {"Habla con Lurielle en El Claro Helado."}},
[11303] = {"La emboscada", {"Habla con Lydell en La Emboscada de Lydell."}},
[11304] = {"Nuevo Agamand", {"Llévale la cepa de Lysander al jefe pesteador Harris en Nuevo Agamand, al oeste del Fiordo Aquilonal."}},
[11305] = {"Una fórmula hecha a medida", {"Obtén la sangre de patriarca Desuelladragones de Thorvald en el Campamento de Thorvald y llévasela al jefe pesteador Harris en Nuevo Agamand."}},
[11306] = {"Calentar y remover", {"Llena el frasco de boticario vacío con el contenido de la caldera de sangre vrykul y luego mezcla el contenido del frasco de sangre vrykul con las muestras de peste de Harris cercanas hasta que obtengas un brebaje equilibrado.","","Preséntate ante el jefe pesteador Harris cuando hayas completado esta tarea."}},
[11307] = {"Ensayo de campo", {"Aventúrate en Haltorboll y utiliza el spray de peste con 10 vrykuls Desuelladragones apestados. Vuelve a ver al jefe pesteador Harris para informarle de los resultados."}},
[11308] = {"Es hora de limpiar", {"Habla con \"Sierra\" Jenny en Nuevo Agamand."}},
[11309] = {"Partes para el trabajo", {"\"Sierra\" Jenny en Nuevo Agamand quiere que consigas 6 ligamentos de colmipala y 1 porción de medio kilo de carne fresca."}},
[11310] = {"Aviso: requiere montaje", {"Utiliza el juego de montaje de abominación en Haltorboll y reúne vrykuls apestados con tu abominación descerebrada. Acaba por lo menos con 20 y vuelve a ver a \"Sierra\" Jenny a Nuevo Agamand cuando hayas terminado."}},
[11311] = {"Dar muerte a los elementos", {"El domador del viento Kajan, del Campamento Pezuña Invernal, quiere que mates 8 elementales de montaña. Puedes matar ciclones rugientes o elementales de fragmentos de hielo."}},
[11312] = {"El Claro Helado", {"Habla con Lurielle en El Claro Helado."}},
[11313] = {"Espíritus del hielo", {"Lurielle en El Claro Helado quiere que le lleves 15 núcleos helados."}},
[11314] = {"Las hermanas caídas", {"Lurielle, en El Claro Helado, quiere que uses su colgante con 7 ninfas escalofrío."}},
[11315] = {"Enredaderas salvajes", {"Lurielle, en El Claro Helado, quiere que mates 8 hiedras escarlata."}},
[11316] = {"Engendros de El Claro Retorcido", {"Lurielle en El Claro Helado quiere que mates a 10 trepadores viñaespina."}},
[11317] = {"La limpieza", {"El sabio Caminaniebla en Las Puertas de Acero te ha aconsejado que limpies tu alma de tu conflicto interior meditando en el Santuario Filoescarcha."}},
[11318] = {"Carrera de carneros... o algo parecido", {"Tienes 4 minutos para montar el carnero y mantener 3 niveles de velocidad diferentes durante 8 segundos."}},
[11319] = {"Semillas de los vigilantes Almanegra", {"Lurielle en El Claro Helado quiere que congeles 8 esporas."}},
