[11327] = {"Misión: Devolver el paquete", {"El explorador Knowles te ha pedido que recuperes el paquete de boticario que está en el interior de Haltorboll. Cuando lo tengas, vuelve a ver al explorador a la Torre Lanza Ámbar."}},
[11328] = {"Misión: Inteligencia Renegada", {"El explorador Knowles te ha pedido que entregues el paquete de boticario a Peppy Pedal en la Fortaleza de la Guardia Oeste."}},
[11329] = {"¡Probaré lo que sea!", {"Christopher Sloan de Fuerte Vildervar quiere que le traigas 5 rascacios del Norte."}},
[11330] = {"Pods shupuesshto... ¡Eshto fva a fvuncionar!", {"Peppy Pedal en la Fortaleza de la Guardia Oeste te ha sugerido que le lleves la mezcla especial de Peppy y se la administres al prisionero vrykul Desuelladragones para observar los resultados."}},
[11331] = {"Se lo cuentas tú... ¡hip!", {"Peppy Pedal te ha liado para que le des las malas noticias acerca de la peste de los Renegados al capitán Adams. Ve a verle a la Fortaleza de la Guardia Oeste."}},
[11332] = {"Misión: Echar pestes", {"El capitán Adams te ha ordenado que destruyas 5 tanques de peste en Nuevo Agamand. No vuelvas a verlo a la Fortaleza de la Guardia Oeste hasta que no hayas cumplido tu misión."}},
