[11346] = {"El libro de las Runas", {"El prospector Belvar, en el Fuerte Vildervar, quiere que le lleves el libro de las Runas."}},
[11348] = {"La runa de mando", {"El prospector Belvar en el Fuerte Vildervar quiere que pruebes su runa de mando y que derrotes al vinculador Murdis."}},
[11349] = {"Dominar las runas", {"Llévale un juego de herramientas de tallado Runaférrea al prospector Belvar en el Fuerte Vildervar."}},
[11350] = {"El libro de las Runas", {"El enviado Pembe en el Campamento Pezuña Invernal, quiere que le lleves el libro de las Runas."}},
