[11352] = {"La runa de mando", {"El enviado Pembe en el Campamento Pezuña Invernal quiere que pruebes la runa de mando y derrotes al vinculador Murdis."}},
[11354] = {"Se busca: Fusta de montar de Nazan", {"El comerciante de viento Zhareem te ha pedido que consigas la fusta de montar de Nazan. Llévasela al Bajo Arrabal de la Ciudad de Shattrath para conseguir la recompensa.","","Esta misión solo se puede realizar en dificultad heroica."}},
[11355] = {"La marcha de los gigantes", {"El investigador Aderan en el Fuerte Vildervar quiere que uses el pico para buscar runas sobre los cuerpos de 4 gigantes de piedra con runas."}},
[11356] = {"Supervisora de huérfanos disfrazada", {"Habla con una supervisora de huérfanos enmascarada en Villadorada, en Kharanos o en la Avanzada Azur."}},
[11357] = {"Supervisora de huérfanos enmascarada", {"Habla con la supervisora de huérfanos enmascarada en Cerrotajo, en Rémol o en Plaza Alalcón."}},
[11358] = {"La magnetita", {"El investigador Aderan del Fuerte Vildervar quiere que compares la muestra de runa con la tablilla rota."}},
