[11480] = {"Conoce a la número dos", {"Habla con Annie Bonn en el Cabo Pillastre."}},
[11481] = {"Crisis en La Fuente del Sol", {"Adyen el Celador de la Luz del Alto Aldor, en la Ciudad de Shattrath, te ha pedido que viajes hasta la Meseta de La Fuente del Sol para hablar con Larethor."}},
[11482] = {"El deber llama", {"Dathris Golpesol de la Grada del Arúspice, en la Ciudad de Shattrath, ha insistido en que viajes a Azeroth inmediatamente y te presentes ante Larethor en La Fuente del Sol."}},
[11483] = {"Podemos reconstruirlo", {"Walt de la Avanzada de la Liga de Expedicionarios en el Fiordo Aquilonal quiere que le lleves una barrica grande, cuerda de aguante industrial y lingotes de hierro negro."}},
[11484] = {"Tenemos la tecnología", {"Walt de la Avanzada de la Liga de Expedicionarios en el Fiordo Aquilonal quiere que le lleves un pellejo de colmipala prístino y tejido elástico de acero."}},
[11485] = {"Ensamblajes Runaférrea y tú: salto con cohete", {"Walt de la Avanzada de la Liga de Expedicionarios en el Fiordo Aquilonal quiere que uses la facultad de salto con cohete de ensamblaje Runaférrea sobre el tallado Runaférrea de Walt.","","Retira tu ensamblaje desde la ventana de mascotas cuando hayas completado la misión."}},
[11486] = {"La mejor de las cervezas", nil},
[11487] = {"La mejor de las cervezas", nil},
[11488] = {"El Bancal del Magister", {"El exarca Larethor de la Zona de Escala de Sol Devastado quiere que registres el Bancal del Magister y encuentres a Tyrith, un espía elfo de sangre."}},
[11489] = {"Ensamblajes Runaférrea y tú: recopilación de datos", {"Walt de la Avanzada de la Liga de Expedicionarios en el Fiordo Aquilonal quiere que uses la facultad de recopilación de datos del ensamblaje Runaférrea mientras permaneces junto a la reliquia de enano férreo.","","Retira tu ensamblaje desde la ventana de mascotas cuando hayas completado la misión."}},
[11490] = {"El cristal de adivinación del arúspice", {"Tyrith quiere que uses el orbe en el balcón del Bancal del Magister."}},
[11491] = {"Ensamblajes Runaférrea y tú: el engaño", {"Walt de la Avanzada de la Liga de Expedicionarios, en el Fiordo Aquilonal, quiere que utilices la facultad de engaño del ensamblaje Runaférrea con Lebronski tras haber caminado sobre su alfombra.","","Retira tu ensamblaje desde la ventana de mascotas cuando hayas completado la misión.|n"}},
[11492] = {"Duro de matar", {"Kalecgos te ha pedido que derrotes a Kael'thas en el Bancal del Magister. Lleva la cabeza de Kael y preséntate ante Larethor en la Zona de escala de Sol Devastado."}},
[11494] = {"Reliquias imbuidas de relámpagos", {"Walt de la Avanzada de la Liga de Expedicionarios en el Fiordo Aquilonal quiere que uses la facultad de recopilación de datos de ensamblaje Runaférrea para recoger 15 muestras de datos Runaférrea.","","Retira tu ensamblaje desde la ventana de mascotas cuando hayas completado la misión."}},
[11495] = {"El delicado sonido del trueno", {"Walt de la Avanzada de la Liga de Expedicionarios, en el Fiordo Aquilonal, quiere que uses el ensamblaje Runaférrea para explorar la atronadora cueva en la Excavación de Baelgun.","","Retira a tu ensamblaje desde la ventana de mascotas una vez que hayas completado la misión."}},
[11496] = {"Los resguardos del sagrario", {"El capitán Theris Albahogar en la Zona de Escala de Sol Devastado quiere que consigas 4 despojos de maná de malignos desdichados y devoradores desdichados y que los uses como fuente de energía para alguno de los resguardos de cristal que rodean el Sagrario de Tramo del Sol al este."}},
[11497] = {"Aprendiendo a volar", {"Habla con Ilsa Bravuconada en Bastión Martillo Salvaje en el Valle Sombraluna."}},
[11498] = {"Aprendiendo a volar", {"Habla con Olrokk en la Aldea Sombraluna en el Valle Sombraluna."}},
[11499] = {"Se busca: El sello del príncipe Kael'thas", {"El comerciante de viento Zhareem te ha pedido que consigas el sello del príncipe Kael'thas. Llévaselo al Bajo Arrabal de la Ciudad de Shattrath para conseguir la recompensa.","","Esta misión solo se puede realizar en el Bancal del Magister en dificultad heroica."}},
[11500] = {"Se busca: Hermanas del Tormento", {"El acechador abisal Mah'duun te ha pedido que mates 4 Hermanas del Tormento. Vuelve a verle al Bajo Arrabal de Shattrath cuando estén todos muertos para cobrar la recompensa."}},
[11501] = {"Noticias del este", {"Habla con el capitán Adams en la Fortaleza de la Guardia Oeste."}},
[11502] = {"En defensa de Halaa", {"Derrota a 10 jugadores enemigos en Halaa y vuelve a ver a Lakoor en Telaar."}},
[11503] = {"Enemigos, viejos y nuevos", {"Derrota a 10 jugadores enemigos en Halaa y vuelve a ver a Karrtog en Garadar."}},
[11504] = {"¡Los muertos se levantan!", {"Orfus de Komawa en El Antiguo Elevador en el Fiordo Aquilonal quiere que encuentres la pista de Fengir, la pista de Rodin, la pista de Isuldof y la pista de Windan."}},
[11505] = {"Espíritus de Auchindoun", {"Ayuda a la Alianza a proteger una torre en El Vertedero de Huesos."}},
[11506] = {"Espíritus de Auchindoun", {"Ayuda a la Horda a proteger una torre del Espíritu en El Vertedero de Huesos."}},
[11507] = {"El ancestro Atuik y Komawa", {"Orfus de Komawa en el Fiordo Aquilonal quiere que entregues el fardo de Orfus al ancestro Atuik en Komawa."}},
[11508] = {"Grezzix Morthadellix", {"Habla con Grezzix Morthadellix."}},
[11509] = {"\"Credibilidad\" callejera", {"Habla con Harry \"Lunargenta\" en el Cabo Pillastre sobre los artefactos vrykuls desaparecidos."}},
[11510] = {"\"Movidic\"", {"Harry \"Lunargenta\" de Cabo Pillastre quiere que recuperes su cristal de visión sin'dorei de \"Movidic\" la orca."}},
[11511] = {"El bastón de la Furia de la Tormenta", {"Recupera el bastón de la Furia de la Tormenta y llévaselo a Orfus de Komawa en el Fiordo Aquilonal.|n"}},
[11512] = {"El corazón congelado de Isuldof", {"Recupera el corazón congelado de Isuldof y llévaselo a Orfus de Komawa en el Fiordo Aquilonal."}},
[11513] = {"Interceptar las células de maná", {"Consigue 10 células de maná de contrabando y vuelve a ver al exarca Nasuun en el Bancal de la Luz, en la Ciudad de Shattrath."}},
[11514] = {"Hay que mantener el Portal de La Fuente del Sol", {"Consigue 10 células de maná de contrabando y vuelve a ver al exarca Nasuun en el Bancal de la Luz, en la Ciudad de Shattrath."}},
[11515] = {"Sangre por sangre", {"La magistrix Seyla en el Trono de Kil'jaeden quiere que mates 4 Sangrevil demacrados usando el sifón vil sobre ellos. Necesitarás sangre demoníaca de los Heraldos de cólera cercanos para propulsar el sifón vil."}},
[11516] = {"Destroza el portal", {"La magistrix Seyla del Trono de Kil'jaeden quiere que uses las brasas muy calientes para invocar a una centella viva y asesinar chispas viles incandescentes cerca de ella hasta que se convierta en una centella viva inestable. Vuelve al portal de la Legión con la centella viva inestable para destruirlo."}},
[11517] = {"Informa a Nasuun", {"El Proveedor Portanuus te ha pedido que hables con el exarca Nasuun en el Bancal de la Luz de la Ciudad de Shattrath."}},
[11518] = {"Bandera diaria del portal de La Fuente del Sol", nil},
[11519] = {"El escudo perdido de los Aesirites", {"Habla con el capitán Ellis a bordo del Hermana Misericordia."}},
[11520] = {"Descubriendo tus raíces", {"Mar'nah, en el Puerto de Tramo del Sol, quiere que viajes al Alto Rajaespina en Terrallende, recojas 5 raíces de Rajaespina y vuelvas junto a ella."}},
[11521] = {"Redescubriendo tus raíces", {"Mar'nah, en el Puerto de Tramo del Sol, quiere que viajes al Alto Rajaespina en Terrallende, recojas 5 raíces de Rajaespina y vuelvas junto a ella."}},
[11522] = {"Requisitos:", {" - 5 x Raíz de Rajaespina"}},
[11523] = {"¡Armen los resguardos!", {"El capitán Theris Albahogar de la Zona de Escala de Sol Devastado quiere que obtengas 4 restos de maná de devoradores desdichados y malignos desdichados y que los uses para energizar uno de los resguardos de cristal que rodean las estructuras del Tramo del Sol."}},
[11524] = {"Comportamiento errático", {"La vindicadora Xayann de la Zona de Escala de Sol Devastado quiere que coloques núcleos de cristal armonizado dentro de 5 avizores erráticos derrotados para convertirlos en unidades amistosas."}},
[11525] = {"Más transformaciones", {"La vindicadora Xayann de la Zona de Escala de Sol Devastado quiere que coloques núcleos de cristal armonizado dentro de 5 avizores erráticos derrotados para convertirlos en unidades amistosas."}},
[11526] = {"La magistrix desaparecida", {"Usa el pergamino de la Legión capturado cerca del portal de La Plaza Crepuscular. Cuando hayas atravesado el portal, busca a la magistrix Seyla."}},
[11527] = {"Motín en el Misericordia", {"El capitán Ellis a bordo del Hermana Misericordia te ha pedido que recuperes 5 barricas de pólvora de la bodega del barco.|n"}},
[11528] = {"Un obsequio del Festival de Invierno", nil},
[11529] = {"El botín de Sorlof", {"Mata a Sorlof usando la gran arma y recupera el botín de Sorlof. Devuélvele el botín de Sorlof al capitán Ellis a bordo del Hermana Misericordia."}},
[11530] = {"El escudo de los Aesirites", {"Devuelve el escudo de los Aesirites a Orfus de Komawa en El Antiguo Elevador en el Fiordo Aquilonal."}},
[11531] = {"La pieza de motor extraña", {"Lleva la pieza de motor extraña a K. Lee Fritito en Telredor."}},
[11532] = {"Distracción en La Cicatriz Muerta", {"La maga de batalla Arynna quiere que hables con Ayren Rompenubes cuando estés preparado para volar a La Cicatriz Muerta. Una vez allí usa las cargas Arcanas para matar a 2 Señores Supremos del foso, 3 hechiceros eredar y 12 déspotas de cólera."}},
[11533] = {"Los ataques aéreos deben continuar", {"La maga de batalla Arynna quiere que hables con Ayren Rompenubes cuando estés preparado para volar a La Cicatriz Muerta. Una vez allí usa las cargas Arcanas para matar a 2 Señores Supremos del foso, 3 hechiceros eredar y 12 déspotas de cólera."}},
[11534] = {"Informa a Nasuun", {"El Proveedor Portanuus te ha pedido que hables con el exarca Nasuun en el Bancal de la Luz de la Ciudad de Shattrath."}},
[11535] = {"Preparándose", {"La herrera Hauthaa, en el Arsenal de Tramo del Sol, quiere que mates mirmidones Espina Siniestra al este y que uses sus llaves para robar 3 menas de sus cofres."}},
[11536] = {"No te pares ahora", {"La herrera Hauthaa, en el Arsenal de Tramo del Sol, quiere que mates mirmidones Espina Siniestra al este y que uses sus llaves para robar 3 menas de sus cofres."}},
[11537] = {"La batalla debe continuar", {"El presagista Inuuro quiere que mates a 6 demonios de la Legión Ardiente y al emisario del Odio en La Plaza Crepuscular. Usa el estandarte de Sol Devastado para empalar el cadáver del emisario del Odio."}},
[11538] = {"La batalla por el Arsenal de Tramo del Sol", {"El presagista Inuuro quiere que mates a 6 demonios de la Legión Ardiente y al emisario del Odio en La Plaza Crepuscular o en el Arsenal de Tramo del Sol. Usa el estandarte de Sol Devastado para empalar el cadáver del emisario del Odio."}},
[11539] = {"Tomar el puerto", {"El Magister Ilastar en el Arsenal de Tramo del Sol quiere que mates a 6 invocadores Hojalba, a 6 Caballeros de sangre Hojalba y a 3 tiradores Hojalba."}},
[11540] = {"Aplasta a los Hojalba", {"El Magister Ilastar en el Arsenal de Tramo del Sol quiere que mates a 6 invocadores Hojalba, a 6 Caballeros de sangre Hojalba y a 3 tiradores Hojalba."}},
[11541] = {"Perturbar la Costa Branquia Verde", {"La capitana Valindria quiere que liberes a 10 esclavos Branquia Verde. Vuelve junto a ella a bordo del Orgullo de Lunargenta en el Puerto de Tramo del Sol cuando hayas terminado."}},
[11542] = {"Interceptar a los refuerzos", {"El Vindicador Kaalan del Arsenal de Tramo del Sol quiere que hables con Ayren Rompenubes y que vueles sobre la flota de refuerzo de Hojalba. Usa el aceite en llamas para incendiar las velas de los barcos mientras los sobrevuelas y cuando aterrices, mata a 6 reservistas Hojalba."}},
[11543] = {"Mantén al enemigo a raya", {"El Vindicador Kaalan del Arsenal de Tramo del Sol quiere que hables con Ayren Rompenubes y que vueles sobre la flota de refuerzo de Hojalba. Usa el aceite en llamas para incendiar las velas de los barcos mientras los sobrevuelas y cuando aterrices, mata a 6 reservistas Hojalba."}},
[11544] = {"Armamentos de Ata'mal", {"La herrera Hauthaa necesita que crees 5 metales de Ata'mal purificados. Puedes crearlos destruyendo armamentos de Ata'mal en su yunque en el Arsenal de Tramo del Sol en la Isla de Quel'Danas."}},
[11545] = {"Una donación caritativa", {"La anacoreta Ayuri de Tramo del Sol, en la Isla de La Fuente del Sol, quiere que dones 10 oros."}},
[11546] = {"Abierto al negocio", {"Mar'nah del Puerto de Tramo del Sol quiere que recojas 5 bayas de sangre de los arbustos de Quel'Danas."}},
[11547] = {"Conoce tus líneas Ley", {"El astromante Darnarian, en el Sagrario de Tramo del Sol, quiere que uses el cristal de astromante en el cristal de sangre, el portal de La Plaza Crepuscular y el sagrario naga en la Costa Branquia Verde."}},
[11548] = {"Tu incesante apoyo", {"La anacoreta Ayuri de Tramo del Sol, en la Isla de La Fuente del Sol, quiere que dones 10 oros."}},
[11549] = {"Un benefactor magnánimo", {"El anacoreta Kairthos quiere que dones 1000 oros para ayudar a la causa de la anacoreta Ayuri. Si completas esta misión, serás conocido como Sharmon del Sol Devastado."}},
[11550] = {"Adelante, Falsario...", {"Preséntate ante el archimago Ne'thul en la Isla de Quel'Danas, al norte de Quel'Thalas.","","Los maestros de vuelo de Forjaz y de Ciudad de Lunargenta te llevarán hasta tu destino."}},
