[11883] = {"¿Danza con fuego?", {"Habla con un maestro de danza del fuego en cualquier capital de la Horda."}},
[11885] = {"Sangre adversaria", {"Encuentra los montones de cráneos en el centro de los círculos de invocación de Skettis. Invoca y derrota a cada uno de los descendientes usando 10 Pergaminos perdidos en el Tiempo en el montón de cráneos. Vuelve a ver a Hazzik al Alto de los Vientonegro."}},
[11886] = {"Actividad sospechosa", {"Ve hasta el nuevo Campamento Crepuscular, al sur de la entrada a las Cavernas de Brazanegra en La Ensenada de Zoram de Vallefresno, y recupera la correspondencia Crepuscular de los cultores. Después, invoca al guía del Anillo de la Tierra mediante la baliza totémica."}},
[11891] = {"Un disfraz inofensivo", {"Utiliza el orbe del reptador para espiar en el nuevo Campamento Crepúsculo al oeste de la entrada de las Cavernas de Brazanegra en La Ensenada de Zoram en Vallefresno."}},
